/* AUTO-GENERATED — Arizona Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["AZ"] = {"code":"AZ","name":"Arizona","agency":"Arizona MVD","agencyShort":"MVD","handbook":"https://azdot.gov/mvd/services/driver-license-ID/getting-your-commercial-driver-license","links":{},"en":[{"q":"On most Arizona highways, including the Interstate system, what is the maximum legal width of a commercial vehicle or its load, excluding safety equipment?","options":["8 feet 0 inches (96 inches)","8 feet 6 inches (102 inches)","9 feet 0 inches (108 inches)","10 feet 0 inches (120 inches)"],"answer":1,"explanation":"Arizona limits total outside width to 102 inches (8 feet 6 inches) on the Interstate system, federal-aid and designated state highways, and reasonable-access routes; loads wider than this require an oversize permit. Source: A.R.S. 28-1093 (Vehicle width).","handbook":"","hbref":""},{"q":"Without a special permit, what is the maximum legal height of a vehicle, including its load, above the road surface in Arizona?","options":["12 feet 6 inches","13 feet 0 inches","13 feet 6 inches","14 feet 0 inches"],"answer":2,"explanation":"A vehicle, laden or unladen, may not exceed 13 feet 6 inches in height above the surface on which it stands without a permit. Source: A.R.S. 28-1094 (Vehicle height).","handbook":"","hbref":""},{"q":"What is the maximum gross weight allowed on a single axle on Arizona highways, including enforcement tolerances?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"answer":1,"explanation":"Arizona caps any single axle at 20,000 pounds, including enforcement tolerances, matching the federal standard. Source: A.R.S. 28-1100 and 28-1099 (single axle load limit).","handbook":"","hbref":""},{"q":"What is the maximum gross weight allowed on a tandem axle on Arizona highways, including enforcement tolerances?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":1,"explanation":"Arizona limits a tandem axle to 34,000 pounds, including enforcement tolerances, consistent with the federal standard. Source: A.R.S. 28-1100 (gross weight restrictions).","handbook":"","hbref":""},{"q":"Without an overweight permit, what is the maximum gross weight for a vehicle combination of five or more axles on Arizona highways?","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"answer":2,"explanation":"Arizona sets the maximum legal gross weight at 80,000 pounds for a vehicle combination of five or more axles, the same as the federal maximum. Source: A.R.S. 28-1100 (gross weight restrictions).","handbook":"","hbref":""},{"q":"How does Arizona statute define a 'tandem axle' for purposes of axle weight limits?","options":["Two consecutive axles not more than 40 inches apart","Two or more consecutive axles more than 40 inches but not more than 96 inches apart","Any two axles spaced more than 96 inches apart","Two consecutive axles exactly 8 feet apart"],"answer":1,"explanation":"Arizona defines tandem axles as two or more consecutive axles whose centers are more than 40 inches but not more than 96 inches apart. Source: A.R.S. 28-1100 (definitions).","handbook":"","hbref":""},{"q":"Arizona uses the federal bridge formula W = 500(LN/(N-1) + 12N + 36) to limit gross weight on a group of axles. In that formula, what does 'L' represent?","options":["The legal load rating of the lead axle","The distance in feet between the extreme axles of the group","The total length of the vehicle in feet","The lift capacity of the suspension in tons"],"answer":1,"explanation":"In the bridge formula adopted by Arizona, W is the maximum gross weight on the group, L is the distance in feet between the outer (extreme) axles of the group, and N is the number of axles in the group. Source: A.R.S. 28-1100 (gross weight restrictions).","handbook":"","hbref":""},{"q":"Under Arizona's bridge formula, what does increasing the spacing (L) between the extreme axles of a group generally allow?","options":["A lower allowable gross weight on the group","A higher allowable gross weight on the group","No change, since only the number of axles matters","A higher single-axle limit but lower group weight"],"answer":1,"explanation":"The bridge formula increases the permissible group gross weight as the distance L between extreme axles grows, spreading load over more of the bridge structure, up to the 80,000-pound combination cap. Source: A.R.S. 28-1100 (bridge formula).","handbook":"","hbref":""},{"q":"An over-the-road bus in Arizona is allowed an exception to the single-axle limit. What is the maximum single-axle weight permitted for such a bus?","options":["20,000 pounds","22,000 pounds","24,000 pounds","26,000 pounds"],"answer":2,"explanation":"While the general single-axle limit is 20,000 pounds, an over-the-road bus may exceed it but must not exceed 24,000 pounds on any single axle. Source: A.R.S. 28-1099 (single axle load limit; exceptions).","handbook":"","hbref":""},{"q":"What is the maximum length of a single (non-combination) vehicle, including its load, on Arizona highways without a permit?","options":["35 feet","40 feet","45 feet","53 feet"],"answer":1,"explanation":"A single vehicle, including any load, may not exceed 40 feet extreme overall dimension (with specific exceptions for buses). Source: A.R.S. 28-1095 (vehicle length).","handbook":"","hbref":""},{"q":"On Arizona highways, what is the maximum length of a semitrailer operated in a truck-tractor/semitrailer combination?","options":["48 feet","53 feet","57 feet 6 inches","65 feet"],"answer":2,"explanation":"Arizona allows a semitrailer of up to 57 feet 6 inches in a truck-tractor/semitrailer combination, with no overall combination length limit on the Interstate and designated network beyond trailer length. Source: A.R.S. 28-1095 (vehicle length).","handbook":"","hbref":""},{"q":"In a twin-trailer (semitrailer-trailer) combination on Arizona highways, what is the maximum length of each trailing unit?","options":["27 feet","28 feet 6 inches","33 feet","40 feet"],"answer":1,"explanation":"Arizona limits each unit in a semitrailer-trailer (twin/double) combination to 28 feet 6 inches. Source: A.R.S. 28-1095 (vehicle length; definitions).","handbook":"","hbref":""},{"q":"On Arizona highways that are NOT part of the designated Interstate/national network, what is the typical maximum overall length of a truck-trailer or combination such as a 53-foot rig?","options":["56 feet","60 feet","65 feet","70 feet"],"answer":2,"explanation":"On non-designated (general) Arizona highways the combination overall length limit is 65 feet, whereas the designated Interstate/national network instead governs by trailer length rather than overall length. Source: A.R.S. 28-1095 (vehicle length).","handbook":"","hbref":""},{"q":"When is an Arizona Department of Transportation oversize/overweight special permit required for a commercial vehicle?","options":["Only when the vehicle crosses a state line","Whenever the vehicle or load exceeds a legal size or weight limit and the load is non-reducible","Only when the cargo is hazardous material","Any time the vehicle weighs more than 26,001 pounds GVWR"],"answer":1,"explanation":"An ADOT oversize/overweight special permit is required when a vehicle or load exceeds the legal dimension or weight limits, and overweight/oversize permits are issued only for non-reducible loads. Source: ADOT Commercial Vehicle Permits (Oversize/Overweight); A.R.S. 28-1100 to 28-1145.","handbook":"","hbref":""},{"q":"Through which ADOT system can an Arizona oversize/overweight single-trip permit be obtained?","options":["The state's online commercial vehicle permit portal","Only by mailing a paper form to the Governor's office","Only in person at a city courthouse","Through the county sheriff's office"],"answer":0,"explanation":"ADOT issues oversize/overweight permits through its online commercial vehicle permit portal, as well as authorized permit services, by mail, and in person at Ports of Entry or the Central Permit Office. Source: ADOT Commercial Vehicle Permits (Oversize/Overweight).","handbook":"","hbref":""},{"q":"For a routine ADOT oversize/overweight permit (Class A), what is the maximum total weight of the vehicle and load that the permit may authorize?","options":["129,000 pounds","164,000 pounds","250,000 pounds","500,000 pounds"],"answer":2,"explanation":"ADOT's Class A oversize/overweight permit covers loads up to 14 feet wide, 16 feet high, 120 feet long, and a combined vehicle/load weight of 250,000 pounds; heavier or larger moves require additional review. Source: ADOT Commercial Vehicle Permits (Oversize/Overweight).","handbook":"","hbref":""},{"q":"Which of the following permit durations is offered by ADOT for oversize/overweight moves?","options":["Single-trip, 30-day, and annual permits","Hourly and weekly permits only","A single lifetime permit only","Per-county monthly permits only"],"answer":0,"explanation":"ADOT offers oversize/overweight permits in single-trip, 30-day, and annual durations, with fees scaled to the permit type. Source: ADOT Commercial Vehicle Permits (Oversize/Overweight).","handbook":"","hbref":""},{"q":"Arizona allows a gross weight allowance above the normal limits for a heavy-duty vehicle equipped with idle reduction technology (e.g., an auxiliary power unit). What is that maximum additional weight allowance?","options":["400 pounds","550 pounds","1,000 pounds","2,000 pounds"],"answer":1,"explanation":"Arizona permits up to 550 pounds (or the actual weight of the idle reduction technology, whichever is less) above the weight limits to account for an auxiliary power unit. Source: A.R.S. 28-1100 (gross weight restrictions; exceptions).","handbook":"","hbref":""},{"q":"Arizona grants a gross weight allowance for vehicles powered primarily by natural gas, electric battery, or hydrogen. Up to what total gross weight may such a vehicle operate under that allowance?","options":["80,000 pounds","82,000 pounds","85,000 pounds","88,000 pounds"],"answer":1,"explanation":"Arizona allows a vehicle fueled primarily by natural gas, battery-electric, or hydrogen to exceed the standard limits by the weight of the alternative-fuel system, but the gross weight may not exceed 82,000 pounds. Source: A.R.S. 28-1100 (gross weight restrictions; exceptions).","handbook":"","hbref":""},{"q":"Two consecutive sets of tandem axles in Arizona may each carry up to 34,000 pounds when spaced 36 feet or more apart, subject to what overall limit on the combination?","options":["The combination gross weight may not exceed 80,000 pounds","The combination gross weight may not exceed 68,000 pounds","There is no overall limit once tandems are 36 feet apart","The combination gross weight may not exceed 100,000 pounds"],"answer":0,"explanation":"Arizona allows two consecutive tandem-axle sets to each carry 34,000 pounds when spaced 36 feet or more apart, provided the overall combination gross weight still does not exceed 80,000 pounds. Source: A.R.S. 28-1100 (gross weight restrictions).","handbook":"","hbref":""},{"q":"In Arizona, which CDL class is required to drive a single vehicle with a gross vehicle weight rating (GVWR) of 26,001 pounds or more that is NOT towing anything over 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":1,"explanation":"Arizona requires a Class B CDL for any single vehicle with a GVWR of 26,001 pounds or more. Class A covers combination vehicles with a GCWR of 26,001+ pounds where the towed unit GVWR exceeds 10,000 pounds. Source: Arizona Commercial Driver License Manual (ADOT MVD), Section 1.","handbook":"","hbref":""},{"q":"Under Arizona rules, a Class A CDL is required for a combination vehicle with a gross combination weight rating (GCWR) of 26,001 pounds or more, provided the GVWR of the unit(s) being towed exceeds what weight?","options":["6,000 pounds","10,000 pounds","15,000 pounds","26,001 pounds"],"answer":1,"explanation":"Arizona requires a Class A CDL for a combination vehicle with a GCWR of 26,001+ pounds when the GVWR of the towed unit(s) is in excess of 10,000 pounds. Source: Arizona CDL Manual (ADOT MVD), Section 1 (CDL classes).","handbook":"","hbref":""},{"q":"Which Arizona CDL class applies to a vehicle with a GVWR of 26,000 pounds or less that is designed to transport 16 or more passengers (including the driver) or that carries placarded hazardous materials?","options":["Class A","Class B","Class C","Class M"],"answer":2,"explanation":"Arizona's Class C CDL covers vehicles not meeting the Class A or B weight thresholds that are designed to carry 16 or more passengers (including the driver) or that transport placarded hazardous materials. Source: Arizona CDL Manual (ADOT MVD), Section 1.","handbook":"","hbref":""},{"q":"A vehicle is designed to transport at least how many people (including the driver) before it falls under the passenger threshold that triggers a CDL requirement in Arizona?","options":["9 passengers","12 passengers","15 passengers","16 passengers"],"answer":3,"explanation":"Arizona requires a CDL to operate a vehicle designed to transport 16 or more passengers, including the driver. Source: Arizona CDL Manual (ADOT MVD), 'You must have a CDL to operate' list.","handbook":"","hbref":""},{"q":"What is the general minimum age to obtain a full (interstate) Arizona Commercial Driver License?","options":["16","18","21","25"],"answer":2,"explanation":"The minimum age for an Arizona CDL is 21. Applicants who are at least 18 may apply for an intrastate-only CDL valid solely within Arizona. Source: Arizona CDL Manual / Customer Service Guide for Commercial Drivers (ADOT MVD), Introduction.","handbook":"","hbref":""},{"q":"An 18-year-old Arizona resident wants a CDL but is not yet 21. What may that person apply for?","options":["A full interstate CDL with all endorsements","An intrastate CDL valid only within Arizona","A federal waiver to drive across state lines","Nothing; the minimum CDL age is 21 with no exceptions"],"answer":1,"explanation":"In Arizona, an applicant who is at least 18 but under 21 may apply for an intrastate commercial driver license that is valid only within Arizona. Source: Arizona CDL Manual / Customer Service Guide (ADOT MVD), Introduction.","handbook":"","hbref":""},{"q":"In Arizona, drivers under the age of 21 are specifically prohibited from doing what with a commercial vehicle?","options":["Transporting placarded amounts of hazardous materials","Driving any vehicle over 10,000 pounds","Operating a vehicle with air brakes","Towing any trailer"],"answer":0,"explanation":"Arizona drivers under age 21 are prohibited from transporting placarded amounts of hazardous materials. They may hold an intrastate CDL/CLP but cannot haul placarded hazmat. Source: Arizona CDL Manual / Customer Service Guide (ADOT MVD).","handbook":"","hbref":""},{"q":"How long is an Arizona Commercial Learner Permit (CLP) valid?","options":["For a maximum of 12 months","For 30 days","For 6 months","For 4 years"],"answer":0,"explanation":"The Arizona Commercial Learner Permit is valid for a 12-month period. Source: Arizona CDL Manual / Customer Service Guide (ADOT MVD), 'Commercial Learner Permit (CLP)'.","handbook":"","hbref":""},{"q":"After a CLP is initially issued in Arizona, how long must the holder wait before being eligible to take the CDL skills (driving) test?","options":["At least 14 days","At least 24 hours","At least 30 days","At least 60 days"],"answer":0,"explanation":"A CLP holder is not eligible to take the CDL skills test within 14 days of the initial issuance of the permit, consistent with the federal 14-day hold. Source: Arizona CDL Manual / Customer Service Guide (ADOT MVD), 'Skills (Driving) Test'; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Which endorsement can NOT be placed on an Arizona Commercial Learner Permit (CLP)?","options":["Passenger (P)","School Bus (S)","Hazardous Materials (H)","Tank (N)"],"answer":2,"explanation":"A Hazardous Materials (H) endorsement cannot be placed on a CLP. The applicant receives the CLP without the HME, completes the TSA Security Threat Assessment, and obtains the HME only after the assessment is approved. Source: Arizona CDL Manual / Customer Service Guide (ADOT MVD).","handbook":"","hbref":""},{"q":"To legally drive a school bus in Arizona, a CDL holder must carry which combination of endorsements?","options":["The P endorsement only","The S endorsement only","Both the P (Passenger) and S (School Bus) endorsements","The H and S endorsements"],"answer":2,"explanation":"Arizona school bus drivers must have BOTH the 'P' (Passenger) and 'S' (School Bus) endorsements to operate a school bus. Source: Arizona CDL Manual / Customer Service Guide (ADOT MVD), endorsements section.","handbook":"","hbref":""},{"q":"Before Arizona MVD will issue the Hazardous Materials endorsement, the applicant must pass which federal background screening?","options":["A TSA Security Threat Assessment","An FBI criminal records appeal","A DEA controlled-substance clearance","An ICE residency audit"],"answer":0,"explanation":"The Hazardous Materials endorsement requires the applicant to pass a Transportation Security Administration (TSA) Security Threat Assessment, which includes a background check and fingerprinting. Source: Arizona CDL Manual (ADOT MVD); 49 CFR 1572.","handbook":"","hbref":""},{"q":"Once completed, an Arizona HazMat endorsement's TSA Security Threat Assessment (STA) is valid for how long before it must be renewed?","options":["1 year","3 years","5 years","8 years"],"answer":2,"explanation":"A Security Threat Assessment (STA) is good for 5 years from the date of completion; MVD notifies the holder 60 days before the STA expires. Source: Arizona CDL Manual / Customer Service Guide (ADOT MVD).","handbook":"","hbref":""},{"q":"The Arizona Tank Vehicle (N) endorsement is required to haul liquids or gases in a tank with an individual rated capacity of more than 119 gallons and an aggregate rated capacity of at least how many gallons?","options":["500 gallons","750 gallons","1,000 gallons","2,000 gallons"],"answer":2,"explanation":"A Tank endorsement is required for tanks with an individual rated capacity of more than 119 gallons and an aggregate rated capacity of 1,000 gallons or more. Source: Arizona CDL Manual (ADOT MVD), Section 1; 49 CFR 383.5.","handbook":"","hbref":""},{"q":"Which endorsement does an Arizona driver need to pull double or triple trailers?","options":["N (Tank)","T (Doubles/Triples)","H (Hazardous Materials)","P (Passenger)"],"answer":1,"explanation":"The Doubles/Triples (T) endorsement is required to pull double or triple trailers and requires passing the doubles/triples knowledge test. Source: Arizona CDL Manual (ADOT MVD), Section 1 endorsement list.","handbook":"","hbref":""},{"q":"What minimum score must an applicant achieve on each Arizona CDL knowledge test to pass?","options":["70 percent","75 percent","80 percent","90 percent"],"answer":2,"explanation":"Applicants must answer at least 80 percent of the questions correctly on each knowledge test to achieve a passing score, and must wait until the next business day to retake any failed test. Source: Arizona CDL Manual / Customer Service Guide (ADOT MVD), 'Additional Testing Information'.","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) required before certain Arizona CDL skills or knowledge tests must be completed through a provider listed where?","options":["The FMCSA Training Provider Registry (TPR)","The Arizona MVD school directory only","Any state-licensed truck dealership","The National Registry of Certified Medical Examiners"],"answer":0,"explanation":"Federal ELDT regulations require entry-level drivers to train with a provider listed on the FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) before taking certain CDL skills or knowledge tests. Source: Arizona CDL Manual / Customer Service Guide (ADOT MVD), 'Entry-Level Driver Training (ELDT)'; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"On the Arizona CDL application, a driver who operates only within Arizona and must meet the state's medical requirements self-certifies under which category?","options":["Non-excepted Interstate (NI)","Non-excepted Intrastate (NA)","Excepted Interstate (EI)","Excepted Intrastate (EA)"],"answer":1,"explanation":"A driver operating entirely within Arizona who must meet medical requirements self-certifies as Non-excepted Intrastate (NA); this places an intrastate restriction on the CDL/CLP. Non-excepted Interstate (NI) allows nationwide operation under the federal DOT medical card. Source: Arizona CDL Manual / Customer Service Guide (ADOT MVD), 'Self-Certification'.","handbook":"","hbref":""},{"q":"While operating a commercial motor vehicle (CMV) in Arizona, a CDL driver is considered to be driving under the influence at what blood alcohol concentration (BAC)?","options":["0.02 or higher","0.04 or higher","0.08 or higher","0.10 or higher"],"answer":1,"explanation":"Arizona, following the federal standard in 49 CFR 383.51 and A.R.S. 28-1381/28-3312, prohibits operating a CMV with a BAC of 0.04 or higher (half the 0.08 limit for non-commercial vehicles). Source: Arizona CDL Manual; A.R.S. 28-3312.","handbook":"","hbref":""},{"q":"In Arizona, what is the minimum disqualification period for a CDL holder's FIRST major offense (such as a DUI in a CMV) when NOT transporting hazardous materials?","options":["60 days","120 days","1 year","3 years"],"answer":2,"explanation":"A first major offense results in a disqualification of at least one year. Source: A.R.S. 28-3312; Arizona CDL Manual (mirrors 49 CFR 383.51).","handbook":"","hbref":""},{"q":"If a CDL holder commits a first major offense in Arizona while transporting placarded hazardous materials, the minimum disqualification increases to:","options":["1 year","2 years","3 years","5 years"],"answer":2,"explanation":"A first major offense committed while transporting placarded hazardous materials results in a three-year disqualification rather than one year. Source: A.R.S. 28-3312; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"Under Arizona law, what is the disqualification for a SECOND major offense committed by a CDL holder?","options":["1 year","5 years","10 years","Lifetime"],"answer":3,"explanation":"Two separate major offenses result in a lifetime disqualification, though reinstatement may be possible after 10 years following an approved rehabilitation program. Source: A.R.S. 28-3312; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"In Arizona, how many SERIOUS traffic violations within a 3-year period trigger a 60-day disqualification of a CDL?","options":["1","2","3","4"],"answer":1,"explanation":"Two serious traffic violations within three years result in a 60-day disqualification. Source: A.R.S. 28-3312; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"A CDL driver in Arizona is convicted of THREE serious traffic violations within a 3-year period. What is the disqualification period?","options":["60 days","90 days","120 days","1 year"],"answer":2,"explanation":"Three serious traffic violations within three years result in a 120-day disqualification. Source: A.R.S. 28-3312; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"In Arizona, speeding by how much over the posted limit in a single offense counts as a 'serious traffic violation' for a CDL holder?","options":["10 mph or more over","15 mph or more over","20 mph or more over","25 mph or more over"],"answer":1,"explanation":"Under A.R.S. 28-3312(J), excessive speeding of 15 mph or more above the posted limit is a serious traffic violation. Source: A.R.S. 28-3312; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"Which of the following is classified as a MAJOR offense (not merely a serious traffic violation) for an Arizona CDL holder?","options":["Following too closely (tailgating)","Speeding 15 mph over the limit","Improper or erratic lane change","Leaving the scene of an accident involving a CMV"],"answer":3,"explanation":"Leaving the scene of an accident (hit-and-run) involving a CMV is a major offense carrying a 1-year (3-year if hazmat) disqualification. The other three are serious traffic violations. Source: A.R.S. 28-3312; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"Under Arizona's implied consent law, what happens to a CDL holder who refuses a lawful chemical (breath/blood) test during a DUI stop, regarding their commercial driving privilege?","options":["A warning only on a first refusal","A 30-day CDL disqualification","At least a 1-year CDL disqualification","No CDL effect if not driving commercially"],"answer":2,"explanation":"Refusing a lawful chemical test is treated like a major offense: at least a one-year CDL disqualification (three years if transporting placarded hazardous materials), in addition to the implied-consent license suspension. Source: A.R.S. 28-1321 (implied consent); A.R.S. 28-3312; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"In Arizona, a DUI offense that disqualifies a CDL holder can be committed in:","options":["Only a commercial motor vehicle","Only a vehicle carrying hazardous materials","Either a commercial OR a personal (non-commercial) vehicle","Only a vehicle weighing over 26,001 pounds"],"answer":2,"explanation":"A DUI conviction in ANY vehicle, commercial or personal, disqualifies the CDL. A driver can lose the CDL for a DUI committed in a private car. Source: A.R.S. 28-3312; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"What is the disqualification period for a CDL holder's FIRST violation of an out-of-service (OOS) order in Arizona?","options":["60 days","90 days","180 days","1 year"],"answer":2,"explanation":"A first out-of-service order violation results in a disqualification of at least 180 days. Source: A.R.S. 28-3312; Arizona CDL Manual (mirrors 49 CFR 383.51).","handbook":"","hbref":""},{"q":"In Arizona, what is the disqualification for a SECOND out-of-service order violation within a 10-year period (non-hazmat, non-passenger)?","options":["180 days","1 year","2 years","5 years"],"answer":2,"explanation":"A second out-of-service order violation within 10 years results in a disqualification of at least 2 years. Source: A.R.S. 28-3312; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"A CDL driver in Arizona commits a THIRD out-of-service order violation within 10 years. The minimum disqualification is:","options":["1 year","2 years","3 years","Lifetime"],"answer":2,"explanation":"A third or subsequent out-of-service order violation within 10 years results in a disqualification of at least 3 years. Source: A.R.S. 28-3312; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"What is the disqualification for a CDL holder's FIRST railroad grade-crossing violation in Arizona?","options":["No less than 60 days","No less than 90 days","No less than 120 days","1 year"],"answer":0,"explanation":"A first railroad grade-crossing violation results in a disqualification of no less than 60 days. Source: A.R.S. 28-3312; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"In Arizona, a CDL driver's SECOND railroad grade-crossing violation within 3 years results in a disqualification of no less than:","options":["60 days","120 days","180 days","1 year"],"answer":1,"explanation":"A second railroad grade-crossing violation within three years results in a disqualification of no less than 120 days. Source: A.R.S. 28-3312; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"A CDL holder in Arizona commits a THIRD railroad grade-crossing violation within a 3-year period. The disqualification is no less than:","options":["120 days","180 days","1 year","3 years"],"answer":2,"explanation":"A third or subsequent railroad grade-crossing violation within three years results in a disqualification of no less than one year. Source: A.R.S. 28-3312; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"Using a vehicle in the commission of a felony involving the manufacturing, distributing, or dispensing of a controlled substance results in what CDL disqualification in Arizona?","options":["1 year","3 years","10 years","A permanent (lifetime) disqualification with no reinstatement"],"answer":3,"explanation":"Using a motor vehicle in a felony involving manufacturing, distributing, or dispensing a controlled substance results in a permanent (lifetime) disqualification that is NOT eligible for the 10-year reinstatement. Source: A.R.S. 28-3312; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"Under the rule that applies to Arizona CDL drivers, sending or reading a text message while driving a CMV can subject the DRIVER to a civil penalty of up to:","options":["$500","$1,000","$2,750","$11,000"],"answer":2,"explanation":"Texting while driving a CMV can result in a federal civil penalty of up to $2,750 for the driver (employers face up to $11,000 for allowing or requiring it). A texting/handheld-phone conviction is also a serious traffic violation. Source: 49 CFR 392.80/392.82 (FMCSA No-Texting Rule); Arizona CDL Manual.","handbook":"","hbref":""},{"q":"For an Arizona CDL driver, using a HAND-HELD mobile phone while driving a CMV is permitted only if the driver:","options":["Keeps the call under one minute","Is stopped at a red light","Uses a hands-free setup and presses no more than a single button while seated and belted","Is on a private road"],"answer":2,"explanation":"The rule prohibits holding the phone, reaching for it, or pressing more than one button; hands-free use is allowed only if the driver can initiate/answer with a single button touch while remaining in the seated, belted driving position. Violations count as serious traffic violations. Source: 49 CFR 392.82; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"A CDL holder is convicted of a major offense and reaches a lifetime disqualification. Under Arizona/federal rules, reinstatement may be possible only after a minimum of:","options":["3 years","5 years","10 years and completion of an approved rehabilitation program","It can never be reinstated"],"answer":2,"explanation":"A lifetime disqualification from two major offenses may be reduced to allow reinstatement after at least 10 years if the driver completes an approved rehabilitation program; controlled-substance felony disqualifications remain permanent. Source: A.R.S. 28-3312; Arizona CDL Manual.","handbook":"","hbref":""},{"q":"At a railroad-highway crossing with no white stop line painted on the pavement, where must an Arizona CDL driver who is required to stop bring the vehicle to a halt?","options":["No closer than 5 feet and no farther than 25 feet from the nearest rail","No closer than 15 feet and no farther than 50 feet from the nearest rail","No closer than 20 feet and no farther than 75 feet from the nearest rail","No closer than 10 feet and no farther than 100 feet from the nearest rail"],"answer":1,"explanation":"Arizona's CDL Manual and ARS 28-853 require buses, vehicles carrying passengers for hire, and placarded/flammable-cargo vehicles to stop within 50 feet but not less than 15 feet from the nearest rail when no stop line is present. Source: Arizona CDL Manual sec. 2.15; ARS 28-853.","handbook":"","hbref":""},{"q":"Under Arizona's Move Over law, when a driver on a four-lane highway (two or more lanes the same direction) approaches a stationary vehicle displaying flashing or warning lights, what is the driver first required to do?","options":["Come to a complete stop until the stopped vehicle leaves","Sound the horn continuously while passing the stopped vehicle","Pull onto the shoulder and wait for an officer to wave them past","Make a lane change away from the stopped vehicle if it is safe and possible"],"answer":3,"explanation":"ARS 28-775 requires drivers to yield by moving into a non-adjacent lane when safe; only if a lane change is unsafe must the driver slow to a safe speed. Source: ARS 28-775; AZDPS Move Over Law page.","handbook":"","hbref":""},{"q":"What is the maximum speed limit in Arizona for a motor vehicle or combination over 26,000 pounds declared gross weight (other than a passenger bus), unless ADOT has posted a higher limit?","options":["55 miles per hour","60 miles per hour","75 miles per hour","65 miles per hour"],"answer":3,"explanation":"ARS 28-709 caps heavy commercial vehicles over 26,000 lbs (and vehicles towing a pole trailer of 6,000+ lbs) at 65 mph unless ADOT posts a higher limit after an engineering study. Source: ARS 28-709.","handbook":"","hbref":""},{"q":"According to the Arizona CDL Manual, when stopping on or beside a one-way or divided highway, where should the three reflective warning triangles be placed toward approaching traffic?","options":["At 10 feet, 50 feet, and 150 feet toward approaching traffic","At 25 feet, 75 feet, and 125 feet toward approaching traffic","At 10 feet, 100 feet, and 200 feet toward approaching traffic","At 15 feet, 100 feet, and 300 feet toward approaching traffic"],"answer":2,"explanation":"The Arizona CDL Manual directs drivers stopped on a one-way or divided highway to place warning devices at 10, 100, and 200 feet toward approaching traffic, within 10 minutes. Source: Arizona CDL Manual sec. 2.5.","handbook":"","hbref":""},{"q":"On a two-lane road carrying traffic in both directions (undivided highway), where does the Arizona CDL Manual say to place the warning triangles after stopping?","options":["Within 25 feet of the vehicle and 200 feet ahead and behind it","Within 50 feet of the vehicle and 150 feet ahead and behind it","Within 10 feet of the vehicle and 250 feet ahead and behind it","Within 10 feet of the vehicle and 100 feet ahead and behind it"],"answer":3,"explanation":"On an undivided two-way road, the Arizona CDL Manual requires a triangle within 10 feet of the vehicle plus one 100 feet ahead and one 100 feet behind. Source: Arizona CDL Manual sec. 2.5.","handbook":"","hbref":""},{"q":"While crossing railroad tracks in a commercial vehicle in Arizona, what does the law and CDL Manual prohibit the driver from doing?","options":["Using the four-way emergency flashers","Looking left and right for trains","Shifting gears while crossing the track or tracks","Crossing when the gates are up"],"answer":2,"explanation":"ARS 28-853 and the Arizona CDL Manual state a driver shall not shift gears while crossing the tracks, to avoid stalling on the crossing. Source: ARS 28-853; Arizona CDL Manual sec. 2.15.5.","handbook":"","hbref":""},{"q":"Under Arizona's school-bus stopping rules (ARS 28-857), which oncoming driver is NOT required to stop for a school bus that has its alternately flashing red lights activated?","options":["A driver in the lane directly across a center turn lane from the bus","A driver approaching the bus on a two-lane undivided road","A driver behind the bus in the same direction of travel","A driver traveling on a different roadway of a highway with separate roadways"],"answer":3,"explanation":"ARS 28-857 exempts a driver on a different roadway of a highway with separate roadways (a physically divided highway); painted lines or a two-way left-turn lane do NOT create separate roadways. Source: ARS 28-857.","handbook":"","hbref":""},{"q":"On an Arizona highway with a two-way left-turn (center) lane but no physical median, what must a driver coming from the opposite direction do when a school bus stops with red lights flashing?","options":["Proceed without stopping, because the turn lane divides the road","Slow to 15 mph but need not stop","Stop only if children are visibly crossing","Stop, because a center turn lane is not a separate roadway"],"answer":3,"explanation":"ARS 28-857 specifies that a lane or group of lanes on either side of a two-way left-turn lane is not a separate roadway, so opposing traffic must stop. Source: ARS 28-857.","handbook":"","hbref":""},{"q":"Which vehicles does Arizona law (ARS 28-853) specifically require to stop at every railroad grade crossing before proceeding?","options":["Only vehicles displaying hazardous-materials placards","All commercial vehicles weighing more than 10,000 pounds","Buses/passenger-for-hire vehicles, school buses, and vehicles hauling explosives or flammable liquids","Only school buses when students are aboard"],"answer":2,"explanation":"ARS 28-853 names motor vehicles carrying passengers for hire, school buses carrying children, and vehicles carrying explosive substances or flammable liquids as cargo. Source: ARS 28-853.","handbook":"","hbref":""},{"q":"Per the Arizona CDL School Bus section, when should a school bus driver activate the hazard lights when approaching a railroad crossing?","options":["At least approximately 100 feet before the crossing","At least approximately 300 feet before the crossing","Only after the bus has come to a full stop","Approximately 50 feet before the crossing"],"answer":0,"explanation":"The Arizona CDL Manual school bus section directs drivers to activate hazard lights approximately 100 feet minimum before the crossing to signal intentions. Source: Arizona CDL Manual sec. 10.4.","handbook":"","hbref":""},{"q":"What is the civil penalty for a FIRST violation of Arizona's Move Over law (ARS 28-775)?","options":["$150","$275","$500","$1,000"],"answer":1,"explanation":"ARS 28-775 sets a $275 civil penalty for a first violation, rising to $500 for a second and $1,000 for a third within five years. Source: ARS 28-775.","handbook":"","hbref":""},{"q":"On Arizona multi-lane roadways, what does ARS 28-721 require of a driver traveling slower than the normal speed of traffic?","options":["Stay in the center lane at all times","Drive in the right-hand lane except when passing or preparing to turn left","Use only the left lane so faster traffic can pass on the right","Maintain at least 45 mph in any lane"],"answer":1,"explanation":"ARS 28-721 requires a vehicle moving slower than normal traffic to keep to the right-hand lane, except when overtaking/passing or preparing for a left turn. Source: ARS 28-721.","handbook":"","hbref":""},{"q":"What is the maximum legal vehicle WIDTH on Arizona highways before an oversize permit from ADOT is required?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"answer":0,"explanation":"Arizona's legal maximum width is 8 feet 6 inches (102 inches); anything wider requires an ADOT oversize permit. Source: ADOT Oversize/Overweight permit regulations.","handbook":"","hbref":""},{"q":"Without an Arizona oversize/overweight permit, what is the maximum gross vehicle weight generally allowed?","options":["80,000 pounds","100,000 pounds","26,000 pounds","120,000 pounds"],"answer":0,"explanation":"Arizona follows the federal legal limit of 80,000 lbs gross; exceeding it requires an ADOT overweight permit. Source: ADOT Oversize/Overweight permits; ARS Title 28.","handbook":"","hbref":""},{"q":"A southbound truck descending the steep grade on I-17 near the Verde Valley sees a sign for a 'Runaway Truck Ramp.' What is the purpose of this Arizona safety feature?","options":["To provide a mandatory weigh-station pull-off for all trucks","To let a vehicle with failed or overheated brakes leave the highway and stop safely","To serve as a designated chain-up area in winter","To act as a rest area for fatigued drivers"],"answer":1,"explanation":"ADOT runaway truck (escape) ramps on grades like I-17 let out-of-control trucks with brake failure exit and stop safely; their need is based on grade steepness, length, and crash frequency. Source: ADOT (Runaway Truck Ramps).","handbook":"","hbref":""},{"q":"Within how many minutes must an Arizona CDL driver place emergency warning devices after stopping on a road or shoulder?","options":["Within 5 minutes","Within 15 minutes","Within 10 minutes","Within 30 minutes"],"answer":2,"explanation":"The Arizona CDL Manual requires emergency warning devices to be put out within 10 minutes of stopping on a road or shoulder. Source: Arizona CDL Manual sec. 2.5.","handbook":"","hbref":""},{"q":"If a lane change cannot be made safely when passing a stationary vehicle with flashing lights in Arizona, what does ARS 28-775 require the driver to do instead?","options":["Maintain the posted speed limit but sound the horn","Proceed with due caution and reduce speed to a safe speed for conditions","Stop completely on the roadway until it is clear to move over","Continue at normal speed since moving over is impossible"],"answer":1,"explanation":"ARS 28-775 provides that when a safe lane change is not possible, the driver must slow down and proceed with caution at a safe speed for conditions. Source: ARS 28-775.","handbook":"","hbref":""},{"q":"The Arizona CDL Manual notes a tractor-trailer needs roughly how long to clear a SINGLE railroad track, underscoring why you must be sure you can fully clear before starting across?","options":["At least about 14 seconds","About 5 seconds","About 30 seconds","About 8 seconds"],"answer":0,"explanation":"The Arizona CDL Manual states a typical tractor-trailer needs at least 14 seconds to clear a single track and more than 15 seconds for a double track, so never start across unless you can fully clear. Source: Arizona CDL Manual sec. 2.15.5.","handbook":"","hbref":""},{"q":"On a divided highway with a physical median, how must an Arizona driver respond to a stopped school bus flashing red lights on the OPPOSITE roadway, and to one stopped on the SAME roadway?","options":["No stop required for the opposite roadway, but a stop is required on the same roadway","A stop is required in both directions regardless of the median","No stop is required in either direction because the highway is divided","A stop is required only on the opposite roadway"],"answer":0,"explanation":"Under ARS 28-857, traffic on a physically separate (opposite) roadway need not stop, but vehicles meeting or following the bus on the same roadway must stop until the lights are off. Source: ARS 28-857.","handbook":"","hbref":""},{"q":"For violators, what is the MINIMUM civil penalty in Arizona for a first offense of unlawfully passing a stopped school bus displaying its flashing red lights (ARS 28-857)?","options":["$100","$500","$250","$1,000"],"answer":2,"explanation":"ARS 28-857 sets a minimum $250 civil penalty for a first violation; a second within 36 months is at least $750 and a third at least $1,000, both with possible license suspension. Source: ARS 28-857.","handbook":"","hbref":""},{"q":"Which Arizona agency issues Commercial Driver Licenses (CDLs)?","options":["The Arizona Department of Transportation (ADOT) Motor Vehicle Division","The Arizona Department of Public Safety","The Arizona Department of Weights and Measures","The Federal Motor Carrier Safety Administration (FMCSA)"],"answer":0,"explanation":"In Arizona, CDLs are issued by the Arizona Department of Transportation (ADOT) Motor Vehicle Division (MVD). The FMCSA sets federal standards but does not issue the actual license. Source: ADOT MVD, Getting Your Commercial Driver License page.","handbook":"","hbref":""},{"q":"What minimum score must you achieve on each CDL knowledge (written) test in Arizona to pass?","options":["80 percent","70 percent","75 percent","85 percent"],"answer":0,"explanation":"Arizona MVD knowledge tests require a minimum score of 80 percent to pass each exam. Source: ADOT MVD, Getting Your Commercial Driver License / Tests and Manuals pages.","handbook":"","hbref":""},{"q":"Before you may take the CDL skills test in Arizona, how long must you have held your Commercial Learner's Permit (CLP)?","options":["At least 14 days","At least 30 days","At least 10 days","At least 60 days"],"answer":0,"explanation":"Arizona follows the federal rule: a CLP holder must wait at least 14 days after the CLP is issued before taking the CDL skills test. Source: ADOT MVD, Getting Your Commercial Driver License page (49 CFR 383.25).","handbook":"","hbref":""},{"q":"What is the maximum period for which an Arizona Commercial Learner's Permit (CLP) is valid?","options":["12 months","6 months","180 days","24 months"],"answer":0,"explanation":"An Arizona CLP is valid for a maximum of 12 months. Source: ADOT MVD, Getting Your Commercial Driver License page.","handbook":"","hbref":""},{"q":"How often must a CDL holder's DOT Medical Examiner's Certificate generally be renewed?","options":["Every 24 months or sooner","Every 12 months or sooner","Every 36 months or sooner","Every 48 months or sooner"],"answer":0,"explanation":"The Medical Examiner's Certificate must be renewed every 24 months or sooner, as determined by the medical examiner or by regulation. Source: ADOT MVD, Medical Certification (CDL) page.","handbook":"","hbref":""},{"q":"The Arizona CDL skills test is divided into which three parts?","options":["Pre-trip inspection, basic vehicle control, and on-road driving","Written knowledge, vision screening, and on-road driving","Pre-trip inspection, hazmat handling, and night driving","Backing, parallel parking, and freeway merging only"],"answer":0,"explanation":"The Arizona CDL skills test has three components: the pre-trip inspection, basic vehicle controls, and the on-road (road) driving test. Source: ADOT MVD, Tests and Manuals page; Arizona CDL Manual Sections 11-13.","handbook":"","hbref":""},{"q":"Where must a medical examiner be listed for a CDL physical to be accepted in Arizona?","options":["On the FMCSA National Registry of Certified Medical Examiners","On the ADOT roster of approved physicians","On the Arizona Medical Board's specialist list","On any state's DMV-approved doctor list"],"answer":0,"explanation":"The CDL physical must be performed by a medical examiner listed on the FMCSA National Registry of Certified Medical Examiners (per 49 CFR 391.41/391.43). Source: ADOT MVD, Medical Certification (CDL) page.","handbook":"","hbref":""},{"q":"For a standard (non-intrastate-restricted) CDL holder, how is the Medical Examiner's Certificate normally transmitted to Arizona MVD?","options":["The certified medical examiner submits it to MVD electronically","The driver mails the paper certificate to MVD headquarters","The employer faxes it to MVD on the driver's behalf","FMCSA automatically forwards it without examiner action"],"answer":0,"explanation":"The certified medical examiner submits the Medical Examiner's Certificate (MEC) to MVD electronically; drivers should allow 24 hours before visiting an MVD office. Source: ADOT MVD, Medical Certification (CDL) page.","handbook":"","hbref":""},{"q":"What are the four self-certification categories a CDL applicant in Arizona must choose from?","options":["Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, and Excepted Intrastate","Interstate, Intrastate, Federal, and State","Commercial, Non-Commercial, Hazmat, and Tanker","Class A, Class B, Class C, and Class D"],"answer":0,"explanation":"CDL self-certification requires choosing one of four categories: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, or Excepted Intrastate. Source: ADOT MVD CDL self-certification / Form 96-0526 (49 CFR 383.71).","handbook":"","hbref":""},{"q":"Which self-certification category requires the driver to meet the federal DOT medical card requirements?","options":["Non-Excepted Interstate","Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"answer":0,"explanation":"A driver who self-certifies as Non-Excepted Interstate operates in interstate commerce and must meet the federal DOT medical certificate requirements. Excepted categories do not require the federal medical card. Source: ADOT MVD / FMCSA self-certification (49 CFR 383.71).","handbook":"","hbref":""},{"q":"On an Arizona CDL, what does the 'K' restriction indicate about the driver?","options":["The driver is limited to intrastate (Arizona-only) operation","The driver may not operate vehicles with air brakes","The driver may not carry hazardous materials","The driver must wear corrective lenses"],"answer":0,"explanation":"A 'K' restriction means the driver is restricted to intrastate commerce only (driving within Arizona). Such drivers continue submitting the paper MEC and long form to MVD. Source: ADOT MVD, Medical Certification (CDL) / CDL Restrictions pages.","handbook":"","hbref":""},{"q":"For a CDL holder with the intrastate-only 'K' restriction in Arizona, how is the medical certificate submitted?","options":["By continuing to submit the paper MEC and long form to MVD for review","Electronically through the National Registry only","It is not required for intrastate drivers","By uploading it through the FMCSA driver portal"],"answer":0,"explanation":"Intrastate (K-restricted) drivers continue to submit the paper Medical Examiner's Certificate and long form to MVD for review, rather than relying on the electronic National Registry submission. Source: ADOT MVD, Medical Certification (CDL) page.","handbook":"","hbref":""},{"q":"What happens to a CDL if the holder fails to keep a current Medical Examiner's Certificate on file with MVD?","options":["The CDL is subject to suspension and revocation","Nothing, as long as the driver stays intrastate","The driver receives a one-year automatic extension","Only the hazmat endorsement is removed"],"answer":0,"explanation":"Failure to maintain a current Medical Examiner's Certificate on file with MVD results in suspension and revocation of the CDL privileges. Source: ADOT MVD, Medical Certification (CDL) page.","handbook":"","hbref":""},{"q":"Under Entry-Level Driver Training (ELDT) rules, when must a first-time Arizona applicant complete ELDT?","options":["Before taking the CDL skills test for an initial Class A or B CDL","After passing the skills test but before the license prints","Only after one year of holding a CDL","Only if the applicant is under 21 years old"],"answer":0,"explanation":"ELDT must be completed (through an FMCSA Training Provider Registry-listed school) before taking the skills test for a first-time Class A or B CDL, an upgrade from B to A, or a first-time S, P, or H endorsement. Source: ADOT MVD; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"Which of these is a documentation requirement when applying for a CDL at an Arizona MVD office?","options":["Proof of authorized presence in the U.S., two proofs of Arizona residency, and a Social Security number","A notarized letter from a current employer only","A passport from the country of birth and nothing else","Proof of completed defensive-driving course"],"answer":0,"explanation":"Applicants must provide proof their presence in the U.S. is authorized under federal law, two proofs of residence address, and their Social Security number, plus a valid Medical Examiner's Certificate. Source: ADOT MVD, Getting Your Commercial Driver License page.","handbook":"","hbref":""},{"q":"Besides MVD CDL offices, who else is authorized to administer the CDL road/skills test in Arizona?","options":["MVD-certified third-party testers at public and private organizations","Any licensed commercial driver with five years' experience","Out-of-state DMV examiners visiting Arizona","FMCSA federal inspectors only"],"answer":0,"explanation":"In addition to MVD CDL offices, many public and private organizations in Arizona have MVD-certified testers authorized to administer the road/skills test. Source: ADOT MVD, CDL Examination Program / testing locations pages.","handbook":"","hbref":""},{"q":"An Arizona CDL is valid for a maximum period of how many years?","options":["Up to 8 years","Up to 4 years","Up to 5 years","Up to 10 years"],"answer":0,"explanation":"Arizona CDLs are valid for a period of up to 8 years, and the driver is responsible for renewing before expiration. Note that a shorter medical certificate cycle can still trigger a downgrade. Source: ADOT MVD, Managing Your Commercial Driver License page.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a CDL valid for interstate (out-of-state) commerce in Arizona?","options":["21 years old","18 years old","19 years old","25 years old"],"answer":0,"explanation":"A driver must be at least 21 to obtain a CDL for interstate commerce. Applicants who are 18 to 20 may obtain a CDL restricted to intrastate (Arizona-only) operation. Source: ADOT MVD, Getting Your Commercial Driver License page (49 CFR 383.3).","handbook":"","hbref":""},{"q":"If a driver self-certifies as Non-Excepted Intrastate or Excepted Intrastate in Arizona, what is the consequence?","options":["The driver may not operate a commercial motor vehicle in interstate commerce","The driver is exempt from all skills testing","The driver may drive only school buses","The driver's CDL never needs renewal"],"answer":0,"explanation":"Certifying as Non-Excepted Intrastate or Excepted Intrastate limits the driver to intrastate commerce; they may not operate a CMV in interstate commerce. Source: ADOT MVD, Managing Your Commercial Driver License page (49 CFR 383.71).","handbook":"","hbref":""},{"q":"Which statement best describes Arizona's process and fee structure for CDL testing?","options":["Knowledge and skills tests are administered through MVD or certified testers, and exact fees are set by ADOT and can change over time","All CDL testing is free of charge in Arizona at all times","Fees are set permanently by federal statute and never change","Only the federal government collects all CDL-related fees"],"answer":0,"explanation":"Arizona CDL knowledge and skills tests are administered through MVD offices and MVD-certified third-party testers; applicable fees are established by ADOT and are subject to change, so applicants should verify current amounts with MVD. Source: ADOT MVD, CDL Examination Program / fee schedule pages.","handbook":"","hbref":""}],"ru":{"0":{"q":"На большинстве автомагистралей Аризоны, включая систему Interstate, какова максимальная разрешённая законом ширина коммерческого транспортного средства или его груза, не считая средств обеспечения безопасности?","options":["8 футов 0 дюймов (96 дюймов)","8 футов 6 дюймов (102 дюйма)","9 футов 0 дюймов (108 дюймов)","10 футов 0 дюймов (120 дюймов)"],"explanation":"Аризона ограничивает общую внешнюю ширину до 102 дюймов (8 футов 6 дюймов) на системе Interstate, автомагистралях с федеральным финансированием и обозначенных автомагистралях штата, а также на маршрутах разумного доступа; для грузов шире этого требуется разрешение на негабаритный груз. Источник: A.R.S. 28-1093 (ширина транспортного средства)."},"1":{"q":"Без специального разрешения какова максимальная разрешённая законом высота транспортного средства, включая его груз, над поверхностью дороги в Аризоне?","options":["12 футов 6 дюймов","13 футов 0 дюймов","13 футов 6 дюймов","14 футов 0 дюймов"],"explanation":"Транспортное средство, гружёное или порожнее, не может превышать 13 футов 6 дюймов в высоту над поверхностью, на которой оно стоит, без разрешения. Источник: A.R.S. 28-1094 (высота транспортного средства)."},"2":{"q":"Какова максимальная полная нагрузка, разрешённая на одиночную ось на автомагистралях Аризоны, включая допуски при контроле?","options":["18 000 фунтов","20 000 фунтов","22 400 фунтов","24 000 фунтов"],"explanation":"Аризона ограничивает любую одиночную ось до 20 000 фунтов, включая допуски при контроле, что соответствует федеральному стандарту. Источник: A.R.S. 28-1100 и 28-1099 (предел нагрузки на одиночную ось)."},"3":{"q":"Какова максимальная полная нагрузка, разрешённая на сдвоенную ось на автомагистралях Аризоны, включая допуски при контроле?","options":["32 000 фунтов","34 000 фунтов","36 000 фунтов","40 000 фунтов"],"explanation":"Аризона ограничивает сдвоенную ось до 34 000 фунтов, включая допуски при контроле, в соответствии с федеральным стандартом. Источник: A.R.S. 28-1100 (ограничения полной массы)."},"4":{"q":"Без разрешения на перевес какова максимальная полная масса для автопоезда с пятью или более осями на автомагистралях Аризоны?","options":["73 280 фунтов","76 000 фунтов","80 000 фунтов","84 000 фунтов"],"explanation":"Аризона устанавливает максимальную разрешённую законом полную массу в 80 000 фунтов для автопоезда с пятью или более осями, что совпадает с федеральным максимумом. Источник: A.R.S. 28-1100 (ограничения полной массы)."},"5":{"q":"Как закон Аризоны определяет «сдвоенную ось» (tandem axle) применительно к ограничениям нагрузки на ось?","options":["Две последовательные оси на расстоянии не более 40 дюймов друг от друга","Две или более последовательные оси на расстоянии более 40 дюймов, но не более 96 дюймов друг от друга","Любые две оси, расположенные на расстоянии более 96 дюймов друг от друга","Две последовательные оси на расстоянии ровно 8 футов друг от друга"],"explanation":"Аризона определяет сдвоенные оси как две или более последовательные оси, центры которых находятся на расстоянии более 40 дюймов, но не более 96 дюймов друг от друга. Источник: A.R.S. 28-1100 (определения)."},"6":{"q":"Аризона использует федеральную мостовую формулу W = 500(LN/(N-1) + 12N + 36) для ограничения полной массы на группу осей. Что в этой формуле обозначает «L»?","options":["Разрешённую грузоподъёмность ведущей оси","Расстояние в футах между крайними осями группы","Общую длину транспортного средства в футах","Подъёмную способность подвески в тоннах"],"explanation":"В мостовой формуле, принятой Аризоной, W — это максимальная полная масса на группу, L — расстояние в футах между крайними (внешними) осями группы, а N — количество осей в группе. Источник: A.R.S. 28-1100 (ограничения полной массы)."},"7":{"q":"Согласно мостовой формуле Аризоны, что обычно позволяет увеличение расстояния (L) между крайними осями группы?","options":["Более низкую допустимую полную массу на группу","Более высокую допустимую полную массу на группу","Никаких изменений, поскольку важно только количество осей","Более высокий предел для одиночной оси, но меньшую массу на группу"],"explanation":"Мостовая формула увеличивает допустимую полную массу на группу по мере роста расстояния L между крайними осями, распределяя нагрузку по большей части конструкции моста, вплоть до предела в 80 000 фунтов для автопоезда. Источник: A.R.S. 28-1100 (мостовая формула)."},"8":{"q":"Междугороднему автобусу (over-the-road bus) в Аризоне разрешено исключение из предела нагрузки на одиночную ось. Какова максимальная нагрузка на одиночную ось, разрешённая для такого автобуса?","options":["20 000 фунтов","22 000 фунтов","24 000 фунтов","26 000 фунтов"],"explanation":"Хотя общий предел для одиночной оси составляет 20 000 фунтов, междугородний автобус может его превышать, но не должен превышать 24 000 фунтов на любую одиночную ось. Источник: A.R.S. 28-1099 (предел нагрузки на одиночную ось; исключения)."},"9":{"q":"Какова максимальная длина одиночного (несоставного) транспортного средства, включая его груз, на автомагистралях Аризоны без разрешения?","options":["35 футов","40 футов","45 футов","53 фута"],"explanation":"Одиночное транспортное средство, включая любой груз, не может превышать 40 футов в крайнем габаритном измерении (с особыми исключениями для автобусов). Источник: A.R.S. 28-1095 (длина транспортного средства)."},"10":{"q":"На автомагистралях Аризоны какова максимальная длина полуприцепа, эксплуатируемого в составе «тягач/полуприцеп»?","options":["48 футов","53 фута","57 футов 6 дюймов","65 футов"],"explanation":"Аризона допускает полуприцеп длиной до 57 футов 6 дюймов в составе «тягач/полуприцеп», без ограничения общей длины автопоезда на системе Interstate и обозначенной сети сверх длины прицепа. Источник: A.R.S. 28-1095 (длина транспортного средства)."},"11":{"q":"В составе со сдвоенными прицепами (полуприцеп-прицеп) на автомагистралях Аризоны какова максимальная длина каждого буксируемого звена?","options":["27 футов","28 футов 6 дюймов","33 фута","40 футов"],"explanation":"Аризона ограничивает каждое звено в составе «полуприцеп-прицеп» (сдвоенный/двойной) до 28 футов 6 дюймов. Источник: A.R.S. 28-1095 (длина транспортного средства; определения)."},"12":{"q":"На автомагистралях Аризоны, которые НЕ являются частью обозначенной сети Interstate/национальной сети, какова типичная максимальная общая длина автопоезда или состава, такого как 53-футовая сцепка?","options":["56 футов","60 футов","65 футов","70 футов"],"explanation":"На необозначенных (обычных) автомагистралях Аризоны предел общей длины автопоезда составляет 65 футов, тогда как на обозначенной сети Interstate/национальной сети действует регулирование по длине прицепа, а не по общей длине. Источник: A.R.S. 28-1095 (длина транспортного средства)."},"13":{"q":"Когда требуется специальное разрешение на негабарит/перевес от Департамента транспорта Аризоны для коммерческого транспортного средства?","options":["Только когда транспортное средство пересекает границу штата","Всякий раз, когда транспортное средство или груз превышает разрешённый законом предел по габаритам или массе, и груз является неделимым","Только когда груз является опасным материалом","Каждый раз, когда транспортное средство имеет полную массу (GVWR) более 26 001 фунта"],"explanation":"Специальное разрешение ADOT на негабарит/перевес требуется, когда транспортное средство или груз превышает разрешённые законом пределы по габаритам или массе, причём разрешения на перевес/негабарит выдаются только для неделимых грузов. Источник: ADOT Commercial Vehicle Permits (негабарит/перевес); A.R.S. 28-1100 - 28-1145."},"14":{"q":"Через какую систему ADOT можно получить разрешение на негабарит/перевес для одной поездки в Аризоне?","options":["Онлайн-портал разрешений для коммерческого транспорта штата","Только путём отправки бумажной формы почтой в офис губернатора","Только лично в городском здании суда","Через офис шерифа округа"],"explanation":"ADOT выдаёт разрешения на негабарит/перевес через свой онлайн-портал разрешений для коммерческого транспорта, а также через уполномоченные службы выдачи разрешений, почтой и лично в пунктах въезда (Ports of Entry) или в Центральном офисе выдачи разрешений. Источник: ADOT Commercial Vehicle Permits (негабарит/перевес)."},"15":{"q":"Для стандартного разрешения ADOT на негабарит/перевес (класс A) какова максимальная общая масса транспортного средства и груза, которую может разрешить такое разрешение?","options":["129 000 фунтов","164 000 фунтов","250 000 фунтов","500 000 фунтов"],"explanation":"Разрешение ADOT класса A на негабарит/перевес охватывает грузы шириной до 14 футов, высотой до 16 футов, длиной до 120 футов и совокупной массой транспортного средства/груза до 250 000 фунтов; более тяжёлые или крупные перевозки требуют дополнительного рассмотрения. Источник: ADOT Commercial Vehicle Permits (негабарит/перевес)."},"16":{"q":"Какой из следующих сроков действия разрешений предлагает ADOT для перевозок негабарита/перевеса?","options":["Разрешения на одну поездку, на 30 дней и годовые","Только почасовые и недельные разрешения","Только единственное пожизненное разрешение","Только помесячные разрешения по округам"],"explanation":"ADOT предлагает разрешения на негабарит/перевес со сроком действия на одну поездку, на 30 дней и годовые, причём сборы соответствуют типу разрешения. Источник: ADOT Commercial Vehicle Permits (негабарит/перевес)."},"17":{"q":"Аризона допускает превышение полной массы сверх обычных пределов для тяжёлого транспортного средства, оснащённого технологией снижения холостого хода (например, вспомогательной силовой установкой). Каков этот максимальный дополнительный весовой допуск?","options":["400 фунтов","550 фунтов","1 000 фунтов","2 000 фунтов"],"explanation":"Аризона разрешает превышение пределов массы до 550 фунтов (или на фактический вес технологии снижения холостого хода, в зависимости от того, что меньше) для учёта вспомогательной силовой установки. Источник: A.R.S. 28-1100 (ограничения полной массы; исключения)."},"18":{"q":"Аризона предоставляет весовой допуск для транспортных средств, работающих преимущественно на природном газе, электрической батарее или водороде. До какой общей полной массы может эксплуатироваться такое транспортное средство в рамках этого допуска?","options":["80 000 фунтов","82 000 фунтов","85 000 фунтов","88 000 фунтов"],"explanation":"Аризона позволяет транспортному средству, работающему преимущественно на природном газе, электрической батарее или водороде, превышать стандартные пределы на вес системы альтернативного топлива, но полная масса не может превышать 82 000 фунтов. Источник: A.R.S. 28-1100 (ограничения полной массы; исключения)."},"19":{"q":"Два последовательных набора сдвоенных осей в Аризоне могут нести каждый до 34 000 фунтов при расстоянии 36 футов или более между ними, при условии какого общего ограничения на автопоезд?","options":["Полная масса автопоезда не может превышать 80 000 фунтов","Полная масса автопоезда не может превышать 68 000 фунтов","Никакого общего ограничения нет, как только сдвоенные оси разнесены на 36 футов","Полная масса автопоезда не может превышать 100 000 фунтов"],"explanation":"Аризона позволяет двум последовательным наборам сдвоенных осей нести каждый по 34 000 фунтов при расстоянии 36 футов или более между ними, при условии что общая полная масса автопоезда по-прежнему не превышает 80 000 фунтов. Источник: A.R.S. 28-1100 (ограничения полной массы)."},"20":{"q":"В Аризоне какой класс CDL требуется для управления одиночным транспортным средством с полной разрешённой массой (GVWR) 26 001 фунт или более, которое НЕ буксирует ничего тяжелее 10 000 фунтов?","options":["Класс A","Класс B","Класс C","Класс D"],"explanation":"Аризона требует CDL класса B для любого одиночного транспортного средства с GVWR 26 001 фунт или более. Класс A охватывает составные транспортные средства с GCWR 26 001+ фунтов, где GVWR буксируемого звена превышает 10 000 фунтов. Источник: Arizona Commercial Driver License Manual (ADOT MVD), раздел 1."},"21":{"q":"По правилам Аризоны CDL класса A требуется для составного транспортного средства с полной разрешённой массой автопоезда (GCWR) 26 001 фунт или более при условии, что GVWR буксируемого(ых) звена(ьев) превышает какую массу?","options":["6 000 фунтов","10 000 фунтов","15 000 фунтов","26 001 фунт"],"explanation":"Аризона требует CDL класса A для составного транспортного средства с GCWR 26 001+ фунтов, когда GVWR буксируемого(ых) звена(ьев) превышает 10 000 фунтов. Источник: Arizona CDL Manual (ADOT MVD), раздел 1 (классы CDL)."},"22":{"q":"Какой класс CDL Аризоны применяется к транспортному средству с GVWR 26 000 фунтов или менее, которое спроектировано для перевозки 16 или более пассажиров (включая водителя) или которое перевозит опасные материалы с табличками (placard)?","options":["Класс A","Класс B","Класс C","Класс M"],"explanation":"CDL класса C в Аризоне охватывает транспортные средства, не соответствующие весовым порогам класса A или B, которые спроектированы для перевозки 16 или более пассажиров (включая водителя) или которые перевозят опасные материалы с табличками. Источник: Arizona CDL Manual (ADOT MVD), раздел 1."},"23":{"q":"Для перевозки скольких как минимум человек (включая водителя) должно быть спроектировано транспортное средство, чтобы оно подпадало под пассажирский порог, требующий наличия CDL в Аризоне?","options":["9 пассажиров","12 пассажиров","15 пассажиров","16 пассажиров"],"explanation":"Аризона требует CDL для управления транспортным средством, спроектированным для перевозки 16 или более пассажиров, включая водителя. Источник: Arizona CDL Manual (ADOT MVD), перечень «Вы должны иметь CDL для управления»."},"24":{"q":"Каков общий минимальный возраст для получения полной (междуштатной) коммерческой водительской лицензии Аризоны?","options":["16","18","21","25"],"explanation":"Минимальный возраст для CDL Аризоны — 21 год. Заявители в возрасте не менее 18 лет могут подать заявление на внутриштатный CDL, действительный только в пределах Аризоны. Источник: Arizona CDL Manual / Customer Service Guide for Commercial Drivers (ADOT MVD), введение."},"25":{"q":"18-летний житель Аризоны хочет получить CDL, но ему ещё нет 21 года. На что может подать заявление этот человек?","options":["Полный междуштатный CDL со всеми дополнительными отметками (endorsements)","Внутриштатный CDL, действительный только в пределах Аризоны","Федеральное освобождение для управления при пересечении границ штатов","Ни на что; минимальный возраст для CDL — 21 год без исключений"],"explanation":"В Аризоне заявитель в возрасте не менее 18 лет, но младше 21 года может подать заявление на внутриштатную коммерческую водительскую лицензию, действительную только в пределах Аризоны. Источник: Arizona CDL Manual / Customer Service Guide (ADOT MVD), введение."},"26":{"q":"В Аризоне водителям младше 21 года прямо запрещено делать что с коммерческим транспортным средством?","options":["Перевозить опасные материалы в количествах, требующих табличек (placard)","Управлять любым транспортным средством тяжелее 10 000 фунтов","Управлять транспортным средством с пневматическими тормозами","Буксировать любой прицеп"],"explanation":"Водителям в Аризоне младше 21 года запрещено перевозить опасные материалы в количествах, требующих табличек. Они могут иметь внутриштатный CDL/CLP, но не могут перевозить опасные материалы с табличками. Источник: Arizona CDL Manual / Customer Service Guide (ADOT MVD)."},"27":{"q":"Каков срок действия коммерческого ученического разрешения (CLP) Аризоны?","options":["Не более 12 месяцев","30 дней","6 месяцев","4 года"],"explanation":"Коммерческое ученическое разрешение Аризоны действительно в течение периода в 12 месяцев. Источник: Arizona CDL Manual / Customer Service Guide (ADOT MVD), «Commercial Learner Permit (CLP)»."},"28":{"q":"После первоначальной выдачи CLP в Аризоне сколько времени должен ждать его обладатель, прежде чем получить право сдавать практический экзамен по навыкам вождения CDL?","options":["Не менее 14 дней","Не менее 24 часов","Не менее 30 дней","Не менее 60 дней"],"explanation":"Обладатель CLP не имеет права сдавать экзамен по навыкам CDL в течение 14 дней с момента первоначальной выдачи разрешения, в соответствии с федеральным 14-дневным периодом ожидания. Источник: Arizona CDL Manual / Customer Service Guide (ADOT MVD), «Skills (Driving) Test»; 49 CFR 383.25."},"29":{"q":"Какая дополнительная отметка (endorsement) НЕ может быть проставлена в коммерческом ученическом разрешении (CLP) Аризоны?","options":["Пассажирская (P)","Школьный автобус (S)","Опасные материалы (H)","Цистерна (N)"],"explanation":"Отметка «Опасные материалы» (H) не может быть проставлена в CLP. Заявитель получает CLP без отметки HME, проходит оценку угрозы безопасности TSA (Security Threat Assessment) и получает HME только после одобрения этой оценки. Источник: Arizona CDL Manual / Customer Service Guide (ADOT MVD)."},"30":{"q":"Чтобы законно управлять школьным автобусом в Аризоне, обладатель CDL должен иметь какое сочетание дополнительных отметок (endorsements)?","options":["Только отметку P","Только отметку S","Обе отметки: P (пассажирская) и S (школьный автобус)","Отметки H и S"],"explanation":"Водители школьных автобусов в Аризоне должны иметь ОБЕ отметки: «P» (пассажирская) и «S» (школьный автобус), чтобы управлять школьным автобусом. Источник: Arizona CDL Manual / Customer Service Guide (ADOT MVD), раздел дополнительных отметок."},"31":{"q":"Прежде чем Arizona MVD выдаст отметку «Опасные материалы», заявитель должен пройти какую федеральную проверку?","options":["Оценку угрозы безопасности TSA (Security Threat Assessment)","Апелляцию по уголовным записям ФБР","Допуск DEA по контролируемым веществам","Аудит резидентства ICE"],"explanation":"Отметка «Опасные материалы» требует, чтобы заявитель прошёл оценку угрозы безопасности Управления транспортной безопасности (TSA Security Threat Assessment), которая включает проверку биографических данных и снятие отпечатков пальцев. Источник: Arizona CDL Manual (ADOT MVD); 49 CFR 1572."},"32":{"q":"После завершения какой срок действительна оценка угрозы безопасности TSA (STA) для отметки HazMat в Аризоне, прежде чем её необходимо обновить?","options":["1 год","3 года","5 лет","8 лет"],"explanation":"Оценка угрозы безопасности (STA) действительна в течение 5 лет с даты завершения; MVD уведомляет обладателя за 60 дней до истечения срока действия STA. Источник: Arizona CDL Manual / Customer Service Guide (ADOT MVD)."},"33":{"q":"Отметка «Цистерна» (N) Аризоны требуется для перевозки жидкостей или газов в цистерне с индивидуальной номинальной ёмкостью более 119 галлонов и совокупной номинальной ёмкостью не менее скольких галлонов?","options":["500 галлонов","750 галлонов","1 000 галлонов","2 000 галлонов"],"explanation":"Отметка «Цистерна» требуется для цистерн с индивидуальной номинальной ёмкостью более 119 галлонов и совокупной номинальной ёмкостью 1 000 галлонов или более. Источник: Arizona CDL Manual (ADOT MVD), раздел 1; 49 CFR 383.5."},"34":{"q":"Какая дополнительная отметка (endorsement) нужна водителю в Аризоне, чтобы буксировать двойные или тройные прицепы?","options":["N (Цистерна)","T (Двойные/тройные)","H (Опасные материалы)","P (Пассажирская)"],"explanation":"Отметка «Двойные/тройные» (T) требуется для буксировки двойных или тройных прицепов и требует сдачи теоретического экзамена по двойным/тройным прицепам. Источник: Arizona CDL Manual (ADOT MVD), перечень дополнительных отметок раздела 1."},"35":{"q":"Какой минимальный результат должен набрать заявитель на каждом теоретическом экзамене CDL Аризоны, чтобы сдать его?","options":["70 процентов","75 процентов","80 процентов","90 процентов"],"explanation":"Заявители должны правильно ответить не менее чем на 80 процентов вопросов на каждом теоретическом экзамене, чтобы получить проходной балл, и должны ждать до следующего рабочего дня, чтобы пересдать любой проваленный экзамен. Источник: Arizona CDL Manual / Customer Service Guide (ADOT MVD), «Additional Testing Information»."},"36":{"q":"Начальная подготовка водителей (ELDT), требуемая перед определёнными экзаменами по навыкам или теоретическими экзаменами CDL в Аризоне, должна быть пройдена у провайдера, указанного где?","options":["В реестре провайдеров обучения FMCSA (Training Provider Registry, TPR)","Только в справочнике школ Arizona MVD","У любого лицензированного штатом дилера грузовиков","В Национальном реестре сертифицированных медицинских экспертов"],"explanation":"Федеральные нормы ELDT требуют, чтобы начинающие водители проходили подготовку у провайдера, указанного в реестре провайдеров обучения FMCSA (tpr.fmcsa.dot.gov), перед сдачей определённых экзаменов по навыкам или теоретических экзаменов CDL. Источник: Arizona CDL Manual / Customer Service Guide (ADOT MVD), «Entry-Level Driver Training (ELDT)»; 49 CFR Part 380."},"37":{"q":"В заявлении на CDL Аризоны водитель, который работает только в пределах Аризоны и должен соответствовать медицинским требованиям штата, проводит самосертификацию по какой категории?","options":["Non-excepted Interstate (NI)","Non-excepted Intrastate (NA)","Excepted Interstate (EI)","Excepted Intrastate (EA)"],"explanation":"Водитель, работающий полностью в пределах Аризоны и обязанный соответствовать медицинским требованиям, проводит самосертификацию как Non-excepted Intrastate (NA); это накладывает внутриштатное ограничение на CDL/CLP. Категория Non-excepted Interstate (NI) допускает работу по всей стране при наличии федеральной медицинской карты DOT. Источник: Arizona CDL Manual / Customer Service Guide (ADOT MVD), «Self-Certification»."},"38":{"q":"При управлении коммерческим автотранспортным средством (CMV) в Аризоне водитель CDL считается находящимся под воздействием алкоголя при какой концентрации алкоголя в крови (BAC)?","options":["0,02 или выше","0,04 или выше","0,08 или выше","0,10 или выше"],"explanation":"Аризона, следуя федеральному стандарту в 49 CFR 383.51 и A.R.S. 28-1381/28-3312, запрещает управление CMV с BAC 0,04 или выше (половина от предела 0,08 для некоммерческих транспортных средств). Источник: Arizona CDL Manual; A.R.S. 28-3312."},"39":{"q":"В Аризоне каков минимальный срок дисквалификации за ПЕРВОЕ тяжкое нарушение обладателя CDL (например, DUI в CMV), когда он НЕ перевозит опасные материалы?","options":["60 дней","120 дней","1 год","3 года"],"explanation":"Первое тяжкое нарушение приводит к дисквалификации не менее чем на один год. Источник: A.R.S. 28-3312; Arizona CDL Manual (отражает 49 CFR 383.51)."},"40":{"q":"Если обладатель CDL совершает первое тяжкое нарушение в Аризоне во время перевозки опасных материалов с табличками (placard), минимальная дисквалификация увеличивается до:","options":["1 года","2 лет","3 лет","5 лет"],"explanation":"Первое тяжкое нарушение, совершённое во время перевозки опасных материалов с табличками, приводит к трёхлетней дисквалификации вместо одного года. Источник: A.R.S. 28-3312; Arizona CDL Manual."},"41":{"q":"Согласно закону Аризоны, какова дисквалификация за ВТОРОЕ тяжкое нарушение, совершённое обладателем CDL?","options":["1 год","5 лет","10 лет","Пожизненно"],"explanation":"Два отдельных тяжких нарушения приводят к пожизненной дисквалификации, хотя восстановление может быть возможно по истечении 10 лет после прохождения утверждённой программы реабилитации. Источник: A.R.S. 28-3312; Arizona CDL Manual."},"42":{"q":"В Аризоне сколько СЕРЬЁЗНЫХ нарушений правил дорожного движения в течение 3-летнего периода влекут за собой 60-дневную дисквалификацию CDL?","options":["1","2","3","4"],"explanation":"Два серьёзных нарушения правил дорожного движения в течение трёх лет приводят к 60-дневной дисквалификации. Источник: A.R.S. 28-3312; Arizona CDL Manual."},"43":{"q":"Водитель CDL в Аризоне осуждён за ТРИ серьёзных нарушения правил дорожного движения в течение 3-летнего периода. Каков срок дисквалификации?","options":["60 дней","90 дней","120 дней","1 год"],"explanation":"Три серьёзных нарушения правил дорожного движения в течение трёх лет приводят к 120-дневной дисквалификации. Источник: A.R.S. 28-3312; Arizona CDL Manual."},"44":{"q":"В Аризоне на сколько превышение установленного ограничения скорости в одном нарушении считается «серьёзным нарушением правил дорожного движения» для обладателя CDL?","options":["На 10 миль/ч или более","На 15 миль/ч или более","На 20 миль/ч или более","На 25 миль/ч или более"],"explanation":"Согласно A.R.S. 28-3312(J), чрезмерное превышение скорости на 15 миль/ч или более сверх установленного ограничения является серьёзным нарушением правил дорожного движения. Источник: A.R.S. 28-3312; Arizona CDL Manual."},"45":{"q":"Что из перечисленного классифицируется как ТЯЖКОЕ нарушение (а не просто серьёзное нарушение правил дорожного движения) для обладателя CDL в Аризоне?","options":["Слишком близкое следование (несоблюдение дистанции)","Превышение скорости на 15 миль/ч сверх ограничения","Неправильная или беспорядочная смена полосы движения","Оставление места происшествия с участием CMV"],"explanation":"Оставление места происшествия (hit-and-run) с участием CMV является тяжким нарушением, влекущим за собой дисквалификацию на 1 год (3 года при перевозке опасных материалов). Остальные три — серьёзные нарушения правил дорожного движения. Источник: A.R.S. 28-3312; Arizona CDL Manual."},"46":{"q":"Согласно закону Аризоны о подразумеваемом согласии, что происходит с обладателем CDL, который отказывается от законного химического анализа (дыхания/крови) во время остановки за DUI, применительно к его праву на коммерческое вождение?","options":["Только предупреждение при первом отказе","30-дневная дисквалификация CDL","Дисквалификация CDL не менее чем на 1 год","Никаких последствий для CDL, если он не управлял коммерческим транспортом"],"explanation":"Отказ от законного химического анализа рассматривается как тяжкое нарушение: дисквалификация CDL не менее чем на один год (три года при перевозке опасных материалов с табличками), в дополнение к приостановке лицензии по подразумеваемому согласию. Источник: A.R.S. 28-1321 (подразумеваемое согласие); A.R.S. 28-3312; Arizona CDL Manual."},"47":{"q":"В Аризоне нарушение DUI, дисквалифицирующее обладателя CDL, может быть совершено в:","options":["Только в коммерческом автотранспортном средстве","Только в транспортном средстве, перевозящем опасные материалы","Как в коммерческом, ТАК И в личном (некоммерческом) транспортном средстве","Только в транспортном средстве массой более 26 001 фунта"],"explanation":"Осуждение за DUI в ЛЮБОМ транспортном средстве, коммерческом или личном, дисквалифицирует CDL. Водитель может лишиться CDL за DUI, совершённое в личном автомобиле. Источник: A.R.S. 28-3312; Arizona CDL Manual."},"48":{"q":"Каков срок дисквалификации за ПЕРВОЕ нарушение предписания о выводе из эксплуатации (out-of-service, OOS) обладателем CDL в Аризоне?","options":["60 дней","90 дней","180 дней","1 год"],"explanation":"Первое нарушение предписания о выводе из эксплуатации приводит к дисквалификации не менее чем на 180 дней. Источник: A.R.S. 28-3312; Arizona CDL Manual (отражает 49 CFR 383.51)."},"49":{"q":"В Аризоне какова дисквалификация за ВТОРОЕ нарушение предписания о выводе из эксплуатации в течение 10-летнего периода (без опасных материалов, без пассажиров)?","options":["180 дней","1 год","2 года","5 лет"],"explanation":"Второе нарушение предписания о выводе из эксплуатации в течение 10 лет приводит к дисквалификации не менее чем на 2 года. Источник: A.R.S. 28-3312; Arizona CDL Manual."},"50":{"q":"Водитель CDL в Аризоне совершает ТРЕТЬЕ нарушение предписания о выводе из эксплуатации в течение 10 лет. Минимальная дисквалификация составляет:","options":["1 год","2 года","3 года","Пожизненно"],"explanation":"Третье или последующее нарушение предписания о выводе из эксплуатации в течение 10 лет приводит к дисквалификации не менее чем на 3 года. Источник: A.R.S. 28-3312; Arizona CDL Manual."},"51":{"q":"Какова дисквалификация за ПЕРВОЕ нарушение правил на железнодорожном переезде обладателем CDL в Аризоне?","options":["Не менее 60 дней","Не менее 90 дней","Не менее 120 дней","1 год"],"explanation":"Первое нарушение правил на железнодорожном переезде приводит к дисквалификации не менее чем на 60 дней. Источник: A.R.S. 28-3312; Arizona CDL Manual."},"52":{"q":"В Аризоне ВТОРОЕ нарушение правил на железнодорожном переезде водителем CDL в течение 3 лет приводит к дисквалификации не менее чем на:","options":["60 дней","120 дней","180 дней","1 год"],"explanation":"Второе нарушение правил на железнодорожном переезде в течение трёх лет приводит к дисквалификации не менее чем на 120 дней. Источник: A.R.S. 28-3312; Arizona CDL Manual."},"53":{"q":"Обладатель CDL в Аризоне совершает ТРЕТЬЕ нарушение правил на железнодорожном переезде в течение 3-летнего периода. Дисквалификация составляет не менее:","options":["120 дней","180 дней","1 год","3 года"],"explanation":"Третье или последующее нарушение правил на железнодорожном переезде в течение трёх лет приводит к дисквалификации не менее чем на один год. Источник: A.R.S. 28-3312; Arizona CDL Manual."},"54":{"q":"Использование транспортного средства при совершении тяжкого преступления (felony), связанного с производством, распространением или сбытом контролируемого вещества, приводит к какой дисквалификации CDL в Аризоне?","options":["1 год","3 года","10 лет","Постоянная (пожизненная) дисквалификация без права восстановления"],"explanation":"Использование автотранспортного средства при совершении тяжкого преступления, связанного с производством, распространением или сбытом контролируемого вещества, приводит к постоянной (пожизненной) дисквалификации, которая НЕ подлежит восстановлению через 10 лет. Источник: A.R.S. 28-3312; Arizona CDL Manual."},"55":{"q":"Согласно правилу, применимому к водителям CDL в Аризоне, отправка или чтение текстового сообщения во время управления CMV может повлечь для ВОДИТЕЛЯ гражданско-правовой штраф в размере до:","options":["$500","$1,000","$2,750","$11,000"],"explanation":"Отправка текстовых сообщений во время управления CMV может повлечь федеральный гражданско-правовой штраф в размере до $2,750 для водителя (работодателям грозит до $11,000 за разрешение или требование этого). Осуждение за текстовые сообщения/использование ручного телефона также является серьёзным нарушением правил дорожного движения. Источник: 49 CFR 392.80/392.82 (правило FMCSA о запрете текстовых сообщений); Arizona CDL Manual."},"56":{"q":"Для водителя CDL в Аризоне использование РУЧНОГО мобильного телефона во время управления CMV разрешается только если водитель:","options":["Удерживает звонок менее одной минуты","Остановлен на красный сигнал светофора","Использует устройство громкой связи и нажимает не более одной кнопки, находясь в сидячем положении и пристёгнутым","Находится на частной дороге"],"explanation":"Правило запрещает держать телефон в руке, тянуться за ним или нажимать более одной кнопки; использование громкой связи разрешено только если водитель может инициировать/принять звонок одним нажатием кнопки, оставаясь в сидячем, пристёгнутом положении для вождения. Нарушения считаются серьёзными нарушениями правил дорожного движения. Источник: 49 CFR 392.82; Arizona CDL Manual."},"57":{"q":"Обладатель CDL осуждён за тяжкое нарушение и достигает пожизненной дисквалификации. Согласно правилам Аризоны/федеральным правилам, восстановление может быть возможно только по истечении минимум:","options":["3 лет","5 лет","10 лет и прохождения утверждённой программы реабилитации","Восстановление никогда невозможно"],"explanation":"Пожизненная дисквалификация за два тяжких нарушения может быть смягчена с возможностью восстановления по истечении не менее 10 лет, если водитель проходит утверждённую программу реабилитации; дисквалификации за тяжкие преступления, связанные с контролируемыми веществами, остаются постоянными. Источник: A.R.S. 28-3312; Arizona CDL Manual."},"58":{"q":"На железнодорожном переезде, где на дорожном покрытии не нанесена белая стоп-линия, где водитель с CDL в Аризоне, обязанный остановиться, должен остановить транспортное средство?","options":["Не ближе 5 футов и не дальше 25 футов от ближайшего рельса","Не ближе 15 футов и не дальше 50 футов от ближайшего рельса","Не ближе 20 футов и не дальше 75 футов от ближайшего рельса","Не ближе 10 футов и не дальше 100 футов от ближайшего рельса"],"explanation":"Руководство по CDL штата Аризона и ARS 28-853 требуют, чтобы автобусы, транспортные средства, перевозящие пассажиров за плату, и транспортные средства с табличками опасного груза / легковоспламеняющимся грузом останавливались в пределах 50 футов, но не ближе 15 футов от ближайшего рельса, когда стоп-линия отсутствует. Источник: Руководство по CDL штата Аризона, разд. 2.15; ARS 28-853."},"59":{"q":"Согласно закону Аризоны Move Over, когда водитель на четырехполосной автомагистрали (две или более полос в одном направлении) приближается к стоящему транспортному средству с включенными мигающими или предупредительными огнями, что водитель обязан сделать в первую очередь?","options":["Полностью остановиться, пока стоящее транспортное средство не уедет","Непрерывно сигналить клаксоном при проезде мимо стоящего транспортного средства","Съехать на обочину и ждать, пока сотрудник не даст знак проезжать","Перестроиться в полосу, удаленную от стоящего транспортного средства, если это безопасно и возможно"],"explanation":"ARS 28-775 требует, чтобы водители уступали дорогу, перестраиваясь в несмежную полосу, когда это безопасно; только если перестроение небезопасно, водитель должен снизить скорость до безопасной. Источник: ARS 28-775; страница закона Move Over на сайте AZDPS."},"60":{"q":"Каково максимальное ограничение скорости в Аризоне для механического транспортного средства или состава с заявленной полной массой свыше 26 000 фунтов (кроме пассажирского автобуса), если ADOT не установил более высокий лимит?","options":["55 миль в час","60 миль в час","75 миль в час","65 миль в час"],"explanation":"ARS 28-709 ограничивает скорость тяжелых коммерческих транспортных средств массой свыше 26 000 фунтов (а также транспортных средств, буксирующих прицеп-роспуск массой 6 000+ фунтов) до 65 миль в час, если ADOT не установит более высокий лимит после инженерного исследования. Источник: ARS 28-709."},"61":{"q":"Согласно Руководству по CDL штата Аризона, при остановке на дороге с односторонним движением или на разделенной автомагистрали или рядом с ней, где следует разместить три светоотражающих предупредительных треугольника в сторону приближающегося транспорта?","options":["На расстоянии 10 футов, 50 футов и 150 футов в сторону приближающегося транспорта","На расстоянии 25 футов, 75 футов и 125 футов в сторону приближающегося транспорта","На расстоянии 10 футов, 100 футов и 200 футов в сторону приближающегося транспорта","На расстоянии 15 футов, 100 футов и 300 футов в сторону приближающегося транспорта"],"explanation":"Руководство по CDL штата Аризона предписывает водителям, остановившимся на дороге с односторонним движением или на разделенной автомагистрали, размещать предупредительные устройства на расстоянии 10, 100 и 200 футов в сторону приближающегося транспорта в течение 10 минут. Источник: Руководство по CDL штата Аризона, разд. 2.5."},"62":{"q":"На двухполосной дороге с движением в обоих направлениях (неразделенная автомагистраль), где, согласно Руководству по CDL штата Аризона, следует размещать предупредительные треугольники после остановки?","options":["В пределах 25 футов от транспортного средства и на 200 футов впереди и позади него","В пределах 50 футов от транспортного средства и на 150 футов впереди и позади него","В пределах 10 футов от транспортного средства и на 250 футов впереди и позади него","В пределах 10 футов от транспортного средства и на 100 футов впереди и позади него"],"explanation":"На неразделенной двусторонней дороге Руководство по CDL штата Аризона требует размещать один треугольник в пределах 10 футов от транспортного средства, плюс один на расстоянии 100 футов впереди и один на расстоянии 100 футов позади. Источник: Руководство по CDL штата Аризона, разд. 2.5."},"63":{"q":"При пересечении железнодорожных путей на коммерческом транспортном средстве в Аризоне, что закон и Руководство по CDL запрещают водителю делать?","options":["Использовать четырехстороннюю аварийную сигнализацию","Смотреть налево и направо в поисках поездов","Переключать передачи во время пересечения пути или путей","Пересекать переезд, когда шлагбаумы подняты"],"explanation":"ARS 28-853 и Руководство по CDL штата Аризона устанавливают, что водитель не должен переключать передачи во время пересечения путей, чтобы избежать остановки двигателя на переезде. Источник: ARS 28-853; Руководство по CDL штата Аризона, разд. 2.15.5."},"64":{"q":"Согласно правилам Аризоны об остановке школьного автобуса (ARS 28-857), какой встречный водитель НЕ обязан останавливаться перед школьным автобусом с включенными попеременно мигающими красными огнями?","options":["Водитель в полосе прямо напротив автобуса через центральную полосу для поворота","Водитель, приближающийся к автобусу по двухполосной неразделенной дороге","Водитель позади автобуса в том же направлении движения","Водитель, движущийся по другой проезжей части автомагистрали с раздельными проезжими частями"],"explanation":"ARS 28-857 освобождает от обязанности останавливаться водителя на другой проезжей части автомагистрали с раздельными проезжими частями (физически разделенная автомагистраль); нанесенная разметка или двусторонняя полоса для левого поворота НЕ создают раздельных проезжих частей. Источник: ARS 28-857."},"65":{"q":"На автомагистрали в Аризоне с двусторонней (центральной) полосой для левого поворота, но без физического разделительного барьера, что должен сделать водитель, движущийся со встречного направления, когда школьный автобус останавливается с мигающими красными огнями?","options":["Продолжать движение без остановки, поскольку полоса для поворота разделяет дорогу","Снизить скорость до 15 миль в час, но останавливаться не обязательно","Останавливаться только если видно, что дети переходят дорогу","Остановиться, поскольку центральная полоса для поворота не является раздельной проезжей частью"],"explanation":"ARS 28-857 уточняет, что полоса или группа полос по любую сторону от двусторонней полосы для левого поворота не является раздельной проезжей частью, поэтому встречный транспорт обязан останавливаться. Источник: ARS 28-857."},"66":{"q":"Какие транспортные средства закон Аризоны (ARS 28-853) конкретно обязывает останавливаться на каждом одноуровневом железнодорожном переезде перед продолжением движения?","options":["Только транспортные средства с табличками опасных материалов","Все коммерческие транспортные средства массой более 10 000 фунтов","Автобусы / транспортные средства, перевозящие пассажиров за плату, школьные автобусы и транспортные средства, перевозящие взрывчатые вещества или легковоспламеняющиеся жидкости","Только школьные автобусы, когда в них находятся учащиеся"],"explanation":"ARS 28-853 называет механические транспортные средства, перевозящие пассажиров за плату, школьные автобусы с детьми и транспортные средства, перевозящие взрывчатые вещества или легковоспламеняющиеся жидкости в качестве груза. Источник: ARS 28-853."},"67":{"q":"Согласно разделу о школьных автобусах в Руководстве по CDL штата Аризона, когда водитель школьного автобуса должен включить аварийную сигнализацию при приближении к железнодорожному переезду?","options":["Не менее чем примерно за 100 футов до переезда","Не менее чем примерно за 300 футов до переезда","Только после того, как автобус полностью остановится","Примерно за 50 футов до переезда"],"explanation":"Раздел о школьных автобусах в Руководстве по CDL штата Аризона предписывает водителям включать аварийную сигнализацию минимум примерно за 100 футов до переезда, чтобы обозначить свои намерения. Источник: Руководство по CDL штата Аризона, разд. 10.4."},"68":{"q":"Каков гражданский штраф за ПЕРВОЕ нарушение закона Аризоны Move Over (ARS 28-775)?","options":["$150","$275","$500","$1,000"],"explanation":"ARS 28-775 устанавливает гражданский штраф в размере $275 за первое нарушение, повышающийся до $500 за второе и $1,000 за третье в течение пяти лет. Источник: ARS 28-775."},"69":{"q":"На многополосных дорогах Аризоны, что ARS 28-721 требует от водителя, движущегося медленнее обычной скорости потока?","options":["Всегда оставаться в центральной полосе","Двигаться в правой полосе, кроме случаев обгона или подготовки к левому повороту","Использовать только левую полосу, чтобы более быстрый транспорт мог обгонять справа","Поддерживать не менее 45 миль в час в любой полосе"],"explanation":"ARS 28-721 требует, чтобы транспортное средство, движущееся медленнее обычного потока, держалось правой полосы, кроме случаев обгона / опережения или подготовки к левому повороту. Источник: ARS 28-721."},"70":{"q":"Какова максимальная разрешенная ШИРИНА транспортного средства на автомагистралях Аризоны, прежде чем потребуется разрешение на негабаритный груз от ADOT?","options":["8 футов 6 дюймов","8 футов 0 дюймов","9 футов 0 дюймов","10 футов 0 дюймов"],"explanation":"Максимальная разрешенная законом ширина в Аризоне составляет 8 футов 6 дюймов (102 inches); для всего, что шире, требуется разрешение ADOT на негабаритный груз. Источник: Правила ADOT о разрешениях на негабаритный/сверхтяжелый груз."},"71":{"q":"Без разрешения Аризоны на негабаритный/сверхтяжелый груз, какова максимально допустимая полная масса транспортного средства в общем случае?","options":["80,000 фунтов","100,000 фунтов","26,000 фунтов","120,000 фунтов"],"explanation":"Аризона следует федеральному установленному законом лимиту в 80,000 фунтов полной массы; превышение требует разрешения ADOT на сверхтяжелый груз. Источник: Разрешения ADOT на негабаритный/сверхтяжелый груз; ARS Title 28."},"72":{"q":"Грузовик, движущийся на юг и спускающийся по крутому уклону на I-17 возле Верде-Валли, видит знак «Runaway Truck Ramp» (улавливающий тупик). В чем назначение этого средства безопасности в Аризоне?","options":["Обеспечить обязательный съезд к весовой станции для всех грузовиков","Позволить транспортному средству с отказавшими или перегретыми тормозами съехать с автомагистрали и безопасно остановиться","Служить выделенной зоной для установки цепей зимой","Служить зоной отдыха для уставших водителей"],"explanation":"Улавливающие тупики (аварийные съезды) ADOT на уклонах, таких как I-17, позволяют потерявшим управление грузовикам с отказом тормозов съехать и безопасно остановиться; необходимость в них определяется крутизной уклона, его протяженностью и частотой аварий. Источник: ADOT (Runaway Truck Ramps)."},"73":{"q":"В течение скольких минут водитель с CDL в Аризоне должен выставить аварийные предупредительные устройства после остановки на дороге или обочине?","options":["В течение 5 минут","В течение 15 минут","В течение 10 минут","В течение 30 минут"],"explanation":"Руководство по CDL штата Аризона требует выставить аварийные предупредительные устройства в течение 10 минут после остановки на дороге или обочине. Источник: Руководство по CDL штата Аризона, разд. 2.5."},"74":{"q":"Если перестроение нельзя выполнить безопасно при проезде мимо стоящего транспортного средства с мигающими огнями в Аризоне, что ARS 28-775 требует от водителя вместо этого?","options":["Поддерживать установленное ограничение скорости, но подавать звуковой сигнал","Продолжать движение с должной осторожностью и снизить скорость до безопасной для данных условий","Полностью остановиться на проезжей части, пока не освободится возможность перестроиться","Продолжать движение с нормальной скоростью, поскольку перестроение невозможно"],"explanation":"ARS 28-775 предусматривает, что когда безопасное перестроение невозможно, водитель должен снизить скорость и продолжать движение с осторожностью на безопасной для данных условий скорости. Источник: ARS 28-775."},"75":{"q":"Руководство по CDL штата Аризона отмечает, что автопоезду требуется примерно сколько времени, чтобы полностью пересечь ОДИН железнодорожный путь, подчеркивая, почему нужно быть уверенным, что вы сможете полностью проехать, прежде чем начинать пересечение?","options":["Не менее примерно 14 секунд","Около 5 секунд","Около 30 секунд","Около 8 секунд"],"explanation":"Руководство по CDL штата Аризона указывает, что типичному автопоезду требуется не менее 14 секунд, чтобы пересечь один путь, и более 15 секунд для двойного пути, поэтому никогда не начинайте пересечение, если не сможете полностью проехать. Источник: Руководство по CDL штата Аризона, разд. 2.15.5."},"76":{"q":"На разделенной автомагистрали с физическим разделительным барьером, как водитель в Аризоне должен реагировать на остановившийся школьный автобус с мигающими красными огнями на ПРОТИВОПОЛОЖНОЙ проезжей части, и на автобус, остановившийся на ТОЙ ЖЕ проезжей части?","options":["Остановка не требуется для противоположной проезжей части, но требуется на той же проезжей части","Остановка требуется в обоих направлениях независимо от разделительного барьера","Остановка не требуется ни в одном направлении, поскольку автомагистраль разделена","Остановка требуется только на противоположной проезжей части"],"explanation":"Согласно ARS 28-857, транспорту на физически отдельной (противоположной) проезжей части останавливаться не нужно, но транспортные средства, движущиеся навстречу автобусу или за ним по той же проезжей части, должны остановиться, пока огни не будут выключены. Источник: ARS 28-857."},"77":{"q":"Для нарушителей, каков МИНИМАЛЬНЫЙ гражданский штраф в Аризоне за первое нарушение в виде незаконного объезда остановившегося школьного автобуса с включенными мигающими красными огнями (ARS 28-857)?","options":["$100","$500","$250","$1,000"],"explanation":"ARS 28-857 устанавливает минимальный гражданский штраф в размере $250 за первое нарушение; второе в течение 36 месяцев влечет не менее $750, а третье не менее $1,000, оба с возможным приостановлением действия прав. Источник: ARS 28-857."},"78":{"q":"Какое ведомство Аризоны выдает коммерческие водительские права (CDL)?","options":["Отдел транспортных средств (Motor Vehicle Division) Департамента транспорта Аризоны (ADOT)","Департамент общественной безопасности Аризоны","Департамент мер и весов Аризоны","Федеральное управление безопасности грузоперевозок (FMCSA)"],"explanation":"В Аризоне CDL выдаются Отделом транспортных средств (MVD) Департамента транспорта Аризоны (ADOT). FMCSA устанавливает федеральные стандарты, но не выдает сами права. Источник: ADOT MVD, страница Getting Your Commercial Driver License."},"79":{"q":"Какой минимальный балл нужно набрать на каждом теоретическом (письменном) экзамене на CDL в Аризоне, чтобы сдать его?","options":["80 процентов","70 процентов","75 процентов","85 процентов"],"explanation":"Теоретические экзамены Arizona MVD требуют минимального балла в 80 процентов для сдачи каждого экзамена. Источник: ADOT MVD, страницы Getting Your Commercial Driver License / Tests and Manuals."},"80":{"q":"Прежде чем вы сможете сдавать практический экзамен на CDL в Аризоне, как долго вы должны были владеть коммерческим ученическим разрешением (CLP)?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 10 дней","Не менее 60 дней"],"explanation":"Аризона следует федеральному правилу: владелец CLP должен подождать не менее 14 дней после выдачи CLP, прежде чем сдавать практический экзамен на CDL. Источник: ADOT MVD, страница Getting Your Commercial Driver License (49 CFR 383.25)."},"81":{"q":"Каков максимальный срок действия коммерческого ученического разрешения (CLP) в Аризоне?","options":["12 месяцев","6 месяцев","180 дней","24 месяца"],"explanation":"CLP в Аризоне действителен в течение максимум 12 месяцев. Источник: ADOT MVD, страница Getting Your Commercial Driver License."},"82":{"q":"Как часто, как правило, должен обновляться медицинский сертификат DOT (DOT Medical Examiner's Certificate) у владельца CDL?","options":["Каждые 24 месяца или раньше","Каждые 12 месяцев или раньше","Каждые 36 месяцев или раньше","Каждые 48 месяцев или раньше"],"explanation":"Медицинский сертификат (Medical Examiner's Certificate) должен обновляться каждые 24 месяца или раньше, как определит медицинский эксперт или согласно нормативным требованиям. Источник: ADOT MVD, страница Medical Certification (CDL)."},"83":{"q":"Практический экзамен на CDL в Аризоне делится на какие три части?","options":["Предрейсовый осмотр, базовое управление транспортным средством и вождение по дороге","Теоретический экзамен, проверка зрения и вождение по дороге","Предрейсовый осмотр, обращение с опасными грузами и ночное вождение","Только движение задним ходом, параллельная парковка и выезд на автомагистраль"],"explanation":"Практический экзамен на CDL в Аризоне состоит из трех компонентов: предрейсовый осмотр, базовое управление транспортным средством и экзамен по вождению на дороге. Источник: ADOT MVD, страница Tests and Manuals; Руководство по CDL штата Аризона, разделы 11-13."},"84":{"q":"Где должен быть указан медицинский эксперт, чтобы медицинский осмотр для CDL был принят в Аризоне?","options":["В Национальном реестре сертифицированных медицинских экспертов FMCSA (FMCSA National Registry of Certified Medical Examiners)","В списке одобренных врачей ADOT","В списке специалистов Медицинского совета Аризоны","В списке врачей, одобренных DMV любого штата"],"explanation":"Медицинский осмотр для CDL должен проводиться медицинским экспертом, указанным в Национальном реестре сертифицированных медицинских экспертов FMCSA (согласно 49 CFR 391.41/391.43). Источник: ADOT MVD, страница Medical Certification (CDL)."},"85":{"q":"Для владельца стандартного CDL (без ограничения на работу только внутри штата), как медицинский сертификат обычно передается в Arizona MVD?","options":["Сертифицированный медицинский эксперт подает его в MVD в электронном виде","Водитель отправляет бумажный сертификат по почте в головной офис MVD","Работодатель отправляет его в MVD по факсу от имени водителя","FMCSA автоматически пересылает его без действий со стороны эксперта"],"explanation":"Сертифицированный медицинский эксперт подает медицинский сертификат (MEC) в MVD в электронном виде; водителям следует подождать 24 часа перед посещением офиса MVD. Источник: ADOT MVD, страница Medical Certification (CDL)."},"86":{"q":"Каковы четыре категории самосертификации, из которых должен выбрать заявитель на CDL в Аризоне?","options":["Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate и Excepted Intrastate","Interstate, Intrastate, Federal и State","Commercial, Non-Commercial, Hazmat и Tanker","Class A, Class B, Class C и Class D"],"explanation":"Самосертификация для CDL требует выбора одной из четырех категорий: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate или Excepted Intrastate. Источник: Самосертификация CDL ADOT MVD / форма 96-0526 (49 CFR 383.71)."},"87":{"q":"Какая категория самосертификации требует от водителя соответствия федеральным требованиям к медицинской карте DOT?","options":["Non-Excepted Interstate","Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"explanation":"Водитель, самосертифицирующийся как Non-Excepted Interstate, работает в межштатных перевозках и должен соответствовать федеральным требованиям к медицинскому сертификату DOT. Категории Excepted не требуют федеральной медицинской карты. Источник: Самосертификация ADOT MVD / FMCSA (49 CFR 383.71)."},"88":{"q":"Что на CDL Аризоны означает ограничение «K» в отношении водителя?","options":["Водитель ограничен работой только внутри штата (только в Аризоне)","Водителю нельзя управлять транспортными средствами с пневматическими тормозами","Водителю нельзя перевозить опасные материалы","Водитель должен носить корректирующие линзы"],"explanation":"Ограничение «K» означает, что водитель ограничен только внутриштатными перевозками (вождение в пределах Аризоны). Такие водители продолжают подавать бумажный MEC и длинную форму в MVD. Источник: ADOT MVD, страницы Medical Certification (CDL) / CDL Restrictions."},"89":{"q":"Для владельца CDL с ограничением «K» (только внутри штата) в Аризоне, как подается медицинский сертификат?","options":["Путем продолжения подачи бумажного MEC и длинной формы в MVD на рассмотрение","Только в электронном виде через Национальный реестр","Он не требуется для внутриштатных водителей","Путем загрузки через портал водителей FMCSA"],"explanation":"Внутриштатные водители (с ограничением K) продолжают подавать бумажный медицинский сертификат (Medical Examiner's Certificate) и длинную форму в MVD на рассмотрение, а не полагаются на электронную подачу через Национальный реестр. Источник: ADOT MVD, страница Medical Certification (CDL)."},"90":{"q":"Что происходит с CDL, если владелец не поддерживает действующий медицинский сертификат (Medical Examiner's Certificate) в досье MVD?","options":["CDL подлежит приостановлению и аннулированию","Ничего, пока водитель работает только внутри штата","Водитель получает автоматическое продление на один год","Удаляется только разрешение на перевозку опасных грузов (hazmat)"],"explanation":"Несоблюдение требования поддерживать действующий медицинский сертификат (Medical Examiner's Certificate) в досье MVD приводит к приостановлению и аннулированию прав CDL. Источник: ADOT MVD, страница Medical Certification (CDL)."},"91":{"q":"Согласно правилам обучения водителей начального уровня (ELDT), когда заявитель в Аризоне, впервые получающий права, должен пройти ELDT?","options":["До сдачи практического экзамена на первоначальный CDL класса A или B","После сдачи практического экзамена, но до печати прав","Только после одного года владения CDL","Только если заявителю меньше 21 года"],"explanation":"ELDT должно быть пройдено (в школе, включенной в Реестр поставщиков обучения FMCSA) до сдачи практического экзамена на первоначальный CDL класса A или B, на повышение с B до A, либо на первоначальное получение разрешения S, P или H. Источник: ADOT MVD; 49 CFR Part 380."},"92":{"q":"Что из перечисленного является требованием к документам при подаче заявления на CDL в офисе Arizona MVD?","options":["Подтверждение разрешенного пребывания в США, два подтверждения проживания в Аризоне и номер социального страхования","Только нотариально заверенное письмо от текущего работодателя","Паспорт страны рождения и больше ничего","Подтверждение пройденного курса безопасного вождения"],"explanation":"Заявители должны предоставить подтверждение того, что их пребывание в США разрешено федеральным законом, два подтверждения адреса проживания и номер социального страхования, а также действующий медицинский сертификат (Medical Examiner's Certificate). Источник: ADOT MVD, страница Getting Your Commercial Driver License."},"93":{"q":"Помимо офисов CDL MVD, кто еще уполномочен проводить дорожный/практический экзамен на CDL в Аризоне?","options":["Сертифицированные MVD сторонние экзаменаторы в государственных и частных организациях","Любой лицензированный коммерческий водитель с пятилетним стажем","Экзаменаторы DMV из других штатов, посещающие Аризону","Только федеральные инспекторы FMCSA"],"explanation":"Помимо офисов CDL MVD, многие государственные и частные организации в Аризоне имеют сертифицированных MVD экзаменаторов, уполномоченных проводить дорожный/практический экзамен. Источник: ADOT MVD, страницы CDL Examination Program / расположения мест тестирования."},"94":{"q":"CDL Аризоны действителен максимум на какой срок в годах?","options":["До 8 лет","До 4 лет","До 5 лет","До 10 лет"],"explanation":"CDL Аризоны действительны на срок до 8 лет, и водитель несет ответственность за обновление до истечения срока. Обратите внимание, что более короткий цикл медицинского сертификата все равно может повлечь понижение категории. Источник: ADOT MVD, страница Managing Your Commercial Driver License."},"95":{"q":"Каков минимальный возраст для получения CDL, действительного для межштатных (за пределами штата) перевозок в Аризоне?","options":["21 год","18 лет","19 лет","25 лет"],"explanation":"Водитель должен быть не моложе 21 года, чтобы получить CDL для межштатных перевозок. Заявители в возрасте от 18 до 20 лет могут получить CDL с ограничением на внутриштатные перевозки (только в Аризоне). Источник: ADOT MVD, страница Getting Your Commercial Driver License (49 CFR 383.3)."},"96":{"q":"Если водитель самосертифицируется как Non-Excepted Intrastate или Excepted Intrastate в Аризоне, каковы последствия?","options":["Водитель не может управлять коммерческим механическим транспортным средством в межштатных перевозках","Водитель освобождается от всех практических экзаменов","Водитель может управлять только школьными автобусами","CDL водителя никогда не нужно обновлять"],"explanation":"Сертификация как Non-Excepted Intrastate или Excepted Intrastate ограничивает водителя внутриштатными перевозками; он не может управлять CMV в межштатных перевозках. Источник: ADOT MVD, страница Managing Your Commercial Driver License (49 CFR 383.71)."},"97":{"q":"Какое утверждение лучше всего описывает процесс и структуру сборов за тестирование на CDL в Аризоне?","options":["Теоретические и практические экзамены проводятся через MVD или сертифицированных экзаменаторов, а точные сборы устанавливаются ADOT и могут со временем меняться","Все тестирование на CDL в Аризоне всегда бесплатно","Сборы устанавливаются навсегда федеральным законом и никогда не меняются","Все сборы, связанные с CDL, собирает только федеральное правительство"],"explanation":"Теоретические и практические экзамены на CDL в Аризоне проводятся через офисы MVD и сертифицированных MVD сторонних экзаменаторов; применимые сборы устанавливаются ADOT и могут меняться, поэтому заявителям следует уточнять актуальные суммы в MVD. Источник: ADOT MVD, страницы CDL Examination Program / расписание сборов."}},"tr":{"0":{"q":"Çoğu Arizona karayolunda, Eyaletler Arası (Interstate) sistem dahil, güvenlik ekipmanları hariç bir ticari aracın veya yükünün izin verilen azami yasal genişliği nedir?","options":["8 fit 0 inç (96 inç)","8 fit 6 inç (102 inç)","9 fit 0 inç (108 inç)","10 fit 0 inç (120 inç)"],"explanation":"Arizona, Eyaletler Arası sistemde, federal destekli ve belirlenmiş eyalet karayollarında ve makul erişim güzergahlarında toplam dış genişliği 102 inç (8 fit 6 inç) ile sınırlar; bundan daha geniş yükler bir aşırı boyut (oversize) izni gerektirir. Kaynak: A.R.S. 28-1093 (Araç genişliği)."},"1":{"q":"Özel bir izin olmadan, Arizona'da bir aracın, yükü dahil, yol yüzeyinden itibaren izin verilen azami yasal yüksekliği nedir?","options":["12 fit 6 inç","13 fit 0 inç","13 fit 6 inç","14 fit 0 inç"],"explanation":"Bir araç, yüklü veya yüksüz, izin olmadan üzerinde durduğu yüzeyden itibaren 13 fit 6 inç yüksekliği aşamaz. Kaynak: A.R.S. 28-1094 (Araç yüksekliği)."},"2":{"q":"Denetim toleransları dahil, Arizona karayollarında tek bir aksta izin verilen azami brüt ağırlık nedir?","options":["18.000 pound","20.000 pound","22.400 pound","24.000 pound"],"explanation":"Arizona, denetim toleransları dahil olmak üzere herhangi bir tek aksı, federal standartla uyumlu olarak 20.000 pound ile sınırlar. Kaynak: A.R.S. 28-1100 ve 28-1099 (tek aks yük sınırı)."},"3":{"q":"Denetim toleransları dahil, Arizona karayollarında tandem aksta izin verilen azami brüt ağırlık nedir?","options":["32.000 pound","34.000 pound","36.000 pound","40.000 pound"],"explanation":"Arizona, federal standartla tutarlı olarak bir tandem aksı, denetim toleransları dahil 34.000 pound ile sınırlar. Kaynak: A.R.S. 28-1100 (brüt ağırlık kısıtlamaları)."},"4":{"q":"Bir aşırı yük (overweight) izni olmadan, Arizona karayollarında beş veya daha fazla akslı bir araç kombinasyonu için azami brüt ağırlık nedir?","options":["73.280 pound","76.000 pound","80.000 pound","84.000 pound"],"explanation":"Arizona, beş veya daha fazla akslı bir araç kombinasyonu için azami yasal brüt ağırlığı, federal azami değerle aynı olan 80.000 pound olarak belirler. Kaynak: A.R.S. 28-1100 (brüt ağırlık kısıtlamaları)."},"5":{"q":"Arizona yasası, aks ağırlık sınırları açısından 'tandem aks'ı nasıl tanımlar?","options":["Aralarında en fazla 40 inç bulunan ardışık iki aks","Aralarında 40 inçten fazla ancak 96 inçten fazla olmayan iki veya daha fazla ardışık aks","Aralarında 96 inçten fazla mesafe bulunan herhangi iki aks","Aralarında tam olarak 8 fit bulunan ardışık iki aks"],"explanation":"Arizona, tandem aksları, merkezleri arasında 40 inçten fazla ancak 96 inçten fazla olmayan mesafe bulunan iki veya daha fazla ardışık aks olarak tanımlar. Kaynak: A.R.S. 28-1100 (tanımlar)."},"6":{"q":"Arizona, bir aks grubundaki brüt ağırlığı sınırlamak için W = 500(LN/(N-1) + 12N + 36) federal köprü formülünü kullanır. Bu formülde 'L' neyi temsil eder?","options":["Öndeki aksın yasal yük derecelendirmesini","Grubun en uçtaki aksları arasındaki fit cinsinden mesafeyi","Aracın fit cinsinden toplam uzunluğunu","Süspansiyonun ton cinsinden kaldırma kapasitesini"],"explanation":"Arizona tarafından benimsenen köprü formülünde W, grup üzerindeki azami brüt ağırlık, L, grubun dış (en uçtaki) aksları arasındaki fit cinsinden mesafe ve N, gruptaki aks sayısıdır. Kaynak: A.R.S. 28-1100 (brüt ağırlık kısıtlamaları)."},"7":{"q":"Arizona'nın köprü formülüne göre, bir grubun en uçtaki aksları arasındaki mesafenin (L) artırılması genellikle neye olanak tanır?","options":["Grup üzerinde daha düşük bir izin verilen brüt ağırlığa","Grup üzerinde daha yüksek bir izin verilen brüt ağırlığa","Yalnızca aks sayısı önemli olduğu için herhangi bir değişiklik olmaz","Daha yüksek bir tek aks sınırına ancak daha düşük grup ağırlığına"],"explanation":"Köprü formülü, en uçtaki akslar arasındaki L mesafesi büyüdükçe, yükü köprü yapısının daha geniş bir bölümüne yayarak, 80.000 poundluk kombinasyon üst sınırına kadar izin verilen grup brüt ağırlığını artırır. Kaynak: A.R.S. 28-1100 (köprü formülü)."},"8":{"q":"Arizona'da bir şehirlerarası otobüse (over-the-road bus) tek aks sınırına bir istisna tanınır. Böyle bir otobüs için izin verilen azami tek aks ağırlığı nedir?","options":["20.000 pound","22.000 pound","24.000 pound","26.000 pound"],"explanation":"Genel tek aks sınırı 20.000 pound olsa da, bir şehirlerarası otobüs bunu aşabilir ancak herhangi bir tek aksta 24.000 poundu geçemez. Kaynak: A.R.S. 28-1099 (tek aks yük sınırı; istisnalar)."},"9":{"q":"Arizona karayollarında izin olmadan, tek bir (kombinasyon olmayan) aracın, yükü dahil, azami uzunluğu nedir?","options":["35 fit","40 fit","45 fit","53 fit"],"explanation":"Tek bir araç, herhangi bir yük dahil, en uç toplam boyut olarak 40 fiti aşamaz (otobüsler için belirli istisnalarla). Kaynak: A.R.S. 28-1095 (araç uzunluğu)."},"10":{"q":"Arizona karayollarında, bir çekici/yarı römork (truck-tractor/semitrailer) kombinasyonunda çalıştırılan bir yarı römorkun azami uzunluğu nedir?","options":["48 fit","53 fit","57 fit 6 inç","65 fit"],"explanation":"Arizona, bir çekici/yarı römork kombinasyonunda 57 fit 6 inçe kadar bir yarı römorka izin verir; Eyaletler Arası ve belirlenmiş ağda römork uzunluğu dışında genel bir kombinasyon uzunluğu sınırı yoktur. Kaynak: A.R.S. 28-1095 (araç uzunluğu)."},"11":{"q":"Arizona karayollarında ikiz römorklu (yarı römork-römork) bir kombinasyonda, her bir çekilen birimin azami uzunluğu nedir?","options":["27 fit","28 fit 6 inç","33 fit","40 fit"],"explanation":"Arizona, bir yarı römork-römork (ikiz/çiftli) kombinasyonundaki her bir birimi 28 fit 6 inç ile sınırlar. Kaynak: A.R.S. 28-1095 (araç uzunluğu; tanımlar)."},"12":{"q":"Belirlenmiş Eyaletler Arası/ulusal ağın parçası OLMAYAN Arizona karayollarında, 53 fitlik bir araç gibi bir kamyon-römork veya kombinasyonun tipik azami toplam uzunluğu nedir?","options":["56 fit","60 fit","65 fit","70 fit"],"explanation":"Belirlenmemiş (genel) Arizona karayollarında kombinasyon toplam uzunluk sınırı 65 fittir; belirlenmiş Eyaletler Arası/ulusal ağ ise toplam uzunluk yerine römork uzunluğuna göre düzenlenir. Kaynak: A.R.S. 28-1095 (araç uzunluğu)."},"13":{"q":"Bir ticari araç için ne zaman bir Arizona Ulaştırma Bakanlığı aşırı boyut/aşırı yük özel izni gereklidir?","options":["Yalnızca araç bir eyalet sınırını geçtiğinde","Araç veya yük yasal bir boyut veya ağırlık sınırını aştığında ve yük indirilemez (non-reducible) olduğunda","Yalnızca kargo tehlikeli madde olduğunda","Aracın GVWR değeri 26.001 pounddan fazla olduğu her zaman"],"explanation":"Bir araç veya yük yasal boyut veya ağırlık sınırlarını aştığında bir ADOT aşırı boyut/aşırı yük özel izni gereklidir ve aşırı yük/aşırı boyut izinleri yalnızca indirilemez yükler için verilir. Kaynak: ADOT Ticari Araç İzinleri (Aşırı Boyut/Aşırı Yük); A.R.S. 28-1100 ila 28-1145."},"14":{"q":"Bir Arizona aşırı boyut/aşırı yük tek seferlik izni hangi ADOT sistemi aracılığıyla alınabilir?","options":["Eyaletin çevrimiçi ticari araç izin portalı","Yalnızca Valilik ofisine kağıt bir form posta ile göndererek","Yalnızca bir şehir adliyesinde şahsen","İlçe şerif ofisi aracılığıyla"],"explanation":"ADOT, aşırı boyut/aşırı yük izinlerini çevrimiçi ticari araç izin portalı aracılığıyla, ayrıca yetkili izin hizmetleri, posta yoluyla ve Giriş Noktalarında (Ports of Entry) veya Merkezi İzin Ofisinde şahsen olmak üzere verir. Kaynak: ADOT Ticari Araç İzinleri (Aşırı Boyut/Aşırı Yük)."},"15":{"q":"Rutin bir ADOT aşırı boyut/aşırı yük izni (Sınıf A) için, iznin onaylayabileceği aracın ve yükün azami toplam ağırlığı nedir?","options":["129.000 pound","164.000 pound","250.000 pound","500.000 pound"],"explanation":"ADOT'un Sınıf A aşırı boyut/aşırı yük izni, 14 fit genişliğe, 16 fit yüksekliğe, 120 fit uzunluğa ve 250.000 poundluk birleşik araç/yük ağırlığına kadar yükleri kapsar; daha ağır veya daha büyük taşımalar ek inceleme gerektirir. Kaynak: ADOT Ticari Araç İzinleri (Aşırı Boyut/Aşırı Yük)."},"16":{"q":"Aşağıdaki izin sürelerinden hangisi ADOT tarafından aşırı boyut/aşırı yük taşımaları için sunulur?","options":["Tek seferlik, 30 günlük ve yıllık izinler","Yalnızca saatlik ve haftalık izinler","Yalnızca tek bir ömür boyu izin","Yalnızca ilçe başına aylık izinler"],"explanation":"ADOT, aşırı boyut/aşırı yük izinlerini tek seferlik, 30 günlük ve yıllık sürelerde, izin türüne göre ölçeklenen ücretlerle sunar. Kaynak: ADOT Ticari Araç İzinleri (Aşırı Boyut/Aşırı Yük)."},"17":{"q":"Arizona, rölanti azaltma teknolojisiyle (örneğin bir yardımcı güç ünitesi) donatılmış ağır hizmet bir araç için normal sınırların üzerinde bir brüt ağırlık payı tanır. Bu azami ek ağırlık payı nedir?","options":["400 pound","550 pound","1.000 pound","2.000 pound"],"explanation":"Arizona, bir yardımcı güç ünitesini hesaba katmak için ağırlık sınırlarının üzerinde 550 pounda (veya rölanti azaltma teknolojisinin gerçek ağırlığına, hangisi daha azsa) kadar izin verir. Kaynak: A.R.S. 28-1100 (brüt ağırlık kısıtlamaları; istisnalar)."},"18":{"q":"Arizona, öncelikle doğal gaz, elektrikli batarya veya hidrojenle çalışan araçlar için bir brüt ağırlık payı tanır. Böyle bir araç bu pay kapsamında hangi toplam brüt ağırlığa kadar çalışabilir?","options":["80.000 pound","82.000 pound","85.000 pound","88.000 pound"],"explanation":"Arizona, öncelikle doğal gaz, batarya-elektrik veya hidrojenle çalışan bir aracın, alternatif yakıt sisteminin ağırlığı kadar standart sınırları aşmasına izin verir, ancak brüt ağırlık 82.000 poundu geçemez. Kaynak: A.R.S. 28-1100 (brüt ağırlık kısıtlamaları; istisnalar)."},"19":{"q":"Arizona'da iki ardışık tandem aks seti, 36 fit veya daha fazla aralıkla yerleştirildiğinde her biri 34.000 pounda kadar taşıyabilir; kombinasyon üzerinde hangi genel sınıra tabidir?","options":["Kombinasyon brüt ağırlığı 80.000 poundu geçemez","Kombinasyon brüt ağırlığı 68.000 poundu geçemez","Tandemler 36 fit aralıkta olduğunda genel bir sınır yoktur","Kombinasyon brüt ağırlığı 100.000 poundu geçemez"],"explanation":"Arizona, 36 fit veya daha fazla aralıkla yerleştirildiğinde iki ardışık tandem aks setinin her birinin 34.000 pound taşımasına izin verir, ancak genel kombinasyon brüt ağırlığının yine de 80.000 poundu geçmemesi koşuluyla. Kaynak: A.R.S. 28-1100 (brüt ağırlık kısıtlamaları)."},"20":{"q":"Arizona'da, 10.000 pounddan fazla bir şeyi çekmeyen, brüt araç ağırlık derecelendirmesi (GVWR) 26.001 pound veya daha fazla olan tek bir aracı kullanmak için hangi CDL sınıfı gereklidir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf D"],"explanation":"Arizona, GVWR değeri 26.001 pound veya daha fazla olan herhangi bir tek araç için Sınıf B CDL gerektirir. Sınıf A, çekilen birimin GVWR değerinin 10.000 poundu aştığı, GCWR değeri 26.001+ pound olan kombinasyon araçlarını kapsar. Kaynak: Arizona Ticari Sürücü Belgesi El Kitabı (ADOT MVD), Bölüm 1."},"21":{"q":"Arizona kurallarına göre, brüt kombinasyon ağırlık derecelendirmesi (GCWR) 26.001 pound veya daha fazla olan bir kombinasyon araç için Sınıf A CDL gereklidir; çekilen birim(ler)in GVWR değerinin hangi ağırlığı aşması koşuluyla?","options":["6.000 pound","10.000 pound","15.000 pound","26.001 pound"],"explanation":"Arizona, çekilen birim(ler)in GVWR değeri 10.000 poundu aştığında GCWR değeri 26.001+ pound olan bir kombinasyon araç için Sınıf A CDL gerektirir. Kaynak: Arizona CDL El Kitabı (ADOT MVD), Bölüm 1 (CDL sınıfları)."},"22":{"q":"16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış veya plakalı (placarded) tehlikeli madde taşıyan, GVWR değeri 26.000 pound veya daha az olan bir araca hangi Arizona CDL sınıfı uygulanır?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf M"],"explanation":"Arizona'nın Sınıf C CDL'si, Sınıf A veya B ağırlık eşiklerini karşılamayan, 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış veya plakalı tehlikeli madde taşıyan araçları kapsar. Kaynak: Arizona CDL El Kitabı (ADOT MVD), Bölüm 1."},"23":{"q":"Bir araç, Arizona'da CDL gerekliliğini tetikleyen yolcu eşiğine girmeden önce en az kaç kişiyi (sürücü dahil) taşımak için tasarlanmış olmalıdır?","options":["9 yolcu","12 yolcu","15 yolcu","16 yolcu"],"explanation":"Arizona, sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış bir aracı kullanmak için CDL gerektirir. Kaynak: Arizona CDL El Kitabı (ADOT MVD), 'CDL'ye sahip olmanız gereken durumlar' listesi."},"24":{"q":"Tam (eyaletler arası) bir Arizona Ticari Sürücü Belgesi almak için genel asgari yaş nedir?","options":["16","18","21","25"],"explanation":"Arizona CDL için asgari yaş 21'dir. En az 18 yaşında olan başvuru sahipleri, yalnızca Arizona içinde geçerli olan eyalet içi (intrastate) bir CDL için başvurabilir. Kaynak: Arizona CDL El Kitabı / Ticari Sürücüler için Müşteri Hizmetleri Rehberi (ADOT MVD), Giriş."},"25":{"q":"18 yaşında bir Arizona sakini CDL istiyor ancak henüz 21 yaşında değil. Bu kişi ne için başvurabilir?","options":["Tüm onaylarla (endorsement) tam bir eyaletler arası CDL","Yalnızca Arizona içinde geçerli bir eyalet içi CDL","Eyalet sınırlarını geçerek araç kullanmak için federal bir muafiyet","Hiçbir şey; asgari CDL yaşı istisnasız 21'dir"],"explanation":"Arizona'da, en az 18 ancak 21 yaşından küçük bir başvuru sahibi, yalnızca Arizona içinde geçerli olan bir eyalet içi ticari sürücü belgesi için başvurabilir. Kaynak: Arizona CDL El Kitabı / Müşteri Hizmetleri Rehberi (ADOT MVD), Giriş."},"26":{"q":"Arizona'da 21 yaşın altındaki sürücülerin bir ticari araçla yapması özellikle yasaklanan şey nedir?","options":["Plakalı miktarlarda tehlikeli madde taşımak","10.000 pounddan ağır herhangi bir aracı kullanmak","Havalı frenli bir aracı kullanmak","Herhangi bir römork çekmek"],"explanation":"Arizona'da 21 yaşın altındaki sürücülerin plakalı miktarlarda tehlikeli madde taşıması yasaktır. Eyalet içi bir CDL/CLP'ye sahip olabilirler ancak plakalı tehlikeli madde taşıyamazlar. Kaynak: Arizona CDL El Kitabı / Müşteri Hizmetleri Rehberi (ADOT MVD)."},"27":{"q":"Bir Arizona Ticari Öğrenme İzni (CLP) ne kadar süre geçerlidir?","options":["En fazla 12 ay boyunca","30 gün boyunca","6 ay boyunca","4 yıl boyunca"],"explanation":"Arizona Ticari Öğrenme İzni 12 aylık bir süre boyunca geçerlidir. Kaynak: Arizona CDL El Kitabı / Müşteri Hizmetleri Rehberi (ADOT MVD), 'Ticari Öğrenme İzni (CLP)'."},"28":{"q":"Arizona'da bir CLP ilk verildikten sonra, sahibinin CDL beceri (sürüş) sınavına girmeye hak kazanmadan önce ne kadar beklemesi gerekir?","options":["En az 14 gün","En az 24 saat","En az 30 gün","En az 60 gün"],"explanation":"Bir CLP sahibi, federal 14 günlük bekleme süresiyle tutarlı olarak, iznin ilk verilmesinden itibaren 14 gün içinde CDL beceri sınavına girmeye hak kazanamaz. Kaynak: Arizona CDL El Kitabı / Müşteri Hizmetleri Rehberi (ADOT MVD), 'Beceri (Sürüş) Sınavı'; 49 CFR 383.25."},"29":{"q":"Bir Arizona Ticari Öğrenme İznine (CLP) hangi onay (endorsement) konulamaz?","options":["Yolcu (P)","Okul Otobüsü (S)","Tehlikeli Maddeler (H)","Tank (N)"],"explanation":"Bir CLP'ye Tehlikeli Maddeler (H) onayı konulamaz. Başvuru sahibi CLP'yi HME olmadan alır, TSA Güvenlik Tehdidi Değerlendirmesini tamamlar ve HME'yi yalnızca değerlendirme onaylandıktan sonra alır. Kaynak: Arizona CDL El Kitabı / Müşteri Hizmetleri Rehberi (ADOT MVD)."},"30":{"q":"Arizona'da yasal olarak bir okul otobüsü kullanmak için, bir CDL sahibi hangi onay kombinasyonunu taşımalıdır?","options":["Yalnızca P onayı","Yalnızca S onayı","Hem P (Yolcu) hem de S (Okul Otobüsü) onayları","H ve S onayları"],"explanation":"Arizona okul otobüsü sürücüleri, bir okul otobüsü kullanmak için HEM 'P' (Yolcu) HEM de 'S' (Okul Otobüsü) onaylarına sahip olmalıdır. Kaynak: Arizona CDL El Kitabı / Müşteri Hizmetleri Rehberi (ADOT MVD), onaylar bölümü."},"31":{"q":"Arizona MVD, Tehlikeli Maddeler onayını vermeden önce, başvuru sahibinin hangi federal arka plan taramasını geçmesi gerekir?","options":["Bir TSA Güvenlik Tehdidi Değerlendirmesi","Bir FBI sabıka kayıtları itirazı","Bir DEA kontrollü madde izni","Bir ICE ikamet denetimi"],"explanation":"Tehlikeli Maddeler onayı, başvuru sahibinin bir arka plan kontrolü ve parmak izi alımını içeren Ulaştırma Güvenliği İdaresi (TSA) Güvenlik Tehdidi Değerlendirmesini geçmesini gerektirir. Kaynak: Arizona CDL El Kitabı (ADOT MVD); 49 CFR 1572."},"32":{"q":"Tamamlandıktan sonra, bir Arizona HazMat onayının TSA Güvenlik Tehdidi Değerlendirmesi (STA), yenilenmesi gerekmeden önce ne kadar süre geçerlidir?","options":["1 yıl","3 yıl","5 yıl","8 yıl"],"explanation":"Bir Güvenlik Tehdidi Değerlendirmesi (STA), tamamlandığı tarihten itibaren 5 yıl geçerlidir; MVD, STA'nın süresi dolmadan 60 gün önce sahibini bilgilendirir. Kaynak: Arizona CDL El Kitabı / Müşteri Hizmetleri Rehberi (ADOT MVD)."},"33":{"q":"Arizona Tank Aracı (N) onayı, bireysel derecelendirilmiş kapasitesi 119 galondan fazla ve toplam derecelendirilmiş kapasitesi en az kaç galon olan bir tankta sıvı veya gaz taşımak için gereklidir?","options":["500 galon","750 galon","1.000 galon","2.000 galon"],"explanation":"Bireysel derecelendirilmiş kapasitesi 119 galondan fazla ve toplam derecelendirilmiş kapasitesi 1.000 galon veya daha fazla olan tanklar için bir Tank onayı gereklidir. Kaynak: Arizona CDL El Kitabı (ADOT MVD), Bölüm 1; 49 CFR 383.5."},"34":{"q":"Bir Arizona sürücüsünün çiftli veya üçlü römork çekmek için hangi onaya ihtiyacı vardır?","options":["N (Tank)","T (Çiftli/Üçlü)","H (Tehlikeli Maddeler)","P (Yolcu)"],"explanation":"Çiftli veya üçlü römork çekmek için Çiftli/Üçlü (T) onayı gereklidir ve çiftli/üçlü bilgi sınavını geçmeyi gerektirir. Kaynak: Arizona CDL El Kitabı (ADOT MVD), Bölüm 1 onay listesi."},"35":{"q":"Bir başvuru sahibinin geçmek için her bir Arizona CDL bilgi sınavında elde etmesi gereken asgari puan nedir?","options":["yüzde 70","yüzde 75","yüzde 80","yüzde 90"],"explanation":"Başvuru sahipleri, geçer puan elde etmek için her bilgi sınavında soruların en az yüzde 80'ini doğru yanıtlamalıdır ve başarısız olunan herhangi bir sınavı tekrar almak için bir sonraki iş gününe kadar beklemelidir. Kaynak: Arizona CDL El Kitabı / Müşteri Hizmetleri Rehberi (ADOT MVD), 'Ek Sınav Bilgileri'."},"36":{"q":"Belirli Arizona CDL beceri veya bilgi sınavlarından önce gerekli olan Giriş Seviyesi Sürücü Eğitimi (ELDT), nerede listelenen bir sağlayıcı aracılığıyla tamamlanmalıdır?","options":["FMCSA Eğitim Sağlayıcı Kaydı (TPR)","Yalnızca Arizona MVD okul dizini","Eyalet lisanslı herhangi bir kamyon bayisi","Sertifikalı Tıbbi Muayene Görevlileri Ulusal Kaydı"],"explanation":"Federal ELDT düzenlemeleri, giriş seviyesi sürücülerin belirli CDL beceri veya bilgi sınavlarına girmeden önce FMCSA Eğitim Sağlayıcı Kaydında (tpr.fmcsa.dot.gov) listelenen bir sağlayıcıyla eğitim almasını gerektirir. Kaynak: Arizona CDL El Kitabı / Müşteri Hizmetleri Rehberi (ADOT MVD), 'Giriş Seviyesi Sürücü Eğitimi (ELDT)'; 49 CFR Part 380."},"37":{"q":"Arizona CDL başvurusunda, yalnızca Arizona içinde çalışan ve eyaletin tıbbi gerekliliklerini karşılaması gereken bir sürücü hangi kategori altında kendini sertifikalandırır (self-certify)?","options":["Muafiyetsiz Eyaletler Arası (NI)","Muafiyetsiz Eyalet İçi (NA)","Muafiyetli Eyaletler Arası (EI)","Muafiyetli Eyalet İçi (EA)"],"explanation":"Tamamen Arizona içinde çalışan ve tıbbi gereklilikleri karşılaması gereken bir sürücü, Muafiyetsiz Eyalet İçi (NA) olarak kendini sertifikalandırır; bu, CDL/CLP'ye bir eyalet içi kısıtlaması koyar. Muafiyetsiz Eyaletler Arası (NI), federal DOT tıbbi kartı kapsamında ülke çapında çalışmaya izin verir. Kaynak: Arizona CDL El Kitabı / Müşteri Hizmetleri Rehberi (ADOT MVD), 'Kendini Sertifikalandırma'."},"38":{"q":"Arizona'da bir ticari motorlu araç (CMV) kullanırken, bir CDL sürücüsü hangi kan alkol konsantrasyonunda (BAC) alkollü araç kullanmış sayılır?","options":["0.02 veya daha yüksek","0.04 veya daha yüksek","0.08 veya daha yüksek","0.10 veya daha yüksek"],"explanation":"Arizona, 49 CFR 383.51 ve A.R.S. 28-1381/28-3312'deki federal standardı izleyerek, bir CMV'yi 0.04 veya daha yüksek bir BAC ile kullanmayı yasaklar (ticari olmayan araçlar için 0.08 sınırının yarısı). Kaynak: Arizona CDL El Kitabı; A.R.S. 28-3312."},"39":{"q":"Arizona'da, tehlikeli madde taşınMAZken bir CDL sahibinin İLK büyük suçu (örneğin bir CMV'de DUI) için asgari diskalifiye süresi nedir?","options":["60 gün","120 gün","1 yıl","3 yıl"],"explanation":"İlk büyük suç, en az bir yıllık bir diskalifiye ile sonuçlanır. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı (49 CFR 383.51'i yansıtır)."},"40":{"q":"Bir CDL sahibi, Arizona'da plakalı tehlikeli madde taşırken ilk büyük suçu işlerse, asgari diskalifiye şuna yükselir:","options":["1 yıl","2 yıl","3 yıl","5 yıl"],"explanation":"Plakalı tehlikeli madde taşınırken işlenen ilk büyük suç, bir yıl yerine üç yıllık bir diskalifiye ile sonuçlanır. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı."},"41":{"q":"Arizona yasasına göre, bir CDL sahibi tarafından işlenen İKİNCİ bir büyük suç için diskalifiye nedir?","options":["1 yıl","5 yıl","10 yıl","Ömür boyu"],"explanation":"İki ayrı büyük suç ömür boyu diskalifiye ile sonuçlanır, ancak onaylanmış bir rehabilitasyon programının ardından 10 yıl sonra yeniden ehliyet alma mümkün olabilir. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı."},"42":{"q":"Arizona'da, 3 yıllık bir süre içinde kaç CİDDİ trafik ihlali bir CDL'nin 60 günlük diskalifiyesini tetikler?","options":["1","2","3","4"],"explanation":"Üç yıl içinde iki ciddi trafik ihlali 60 günlük bir diskalifiye ile sonuçlanır. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı."},"43":{"q":"Arizona'da bir CDL sürücüsü, 3 yıllık bir süre içinde ÜÇ ciddi trafik ihlalinden mahkum oluyor. Diskalifiye süresi nedir?","options":["60 gün","90 gün","120 gün","1 yıl"],"explanation":"Üç yıl içinde üç ciddi trafik ihlali 120 günlük bir diskalifiye ile sonuçlanır. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı."},"44":{"q":"Arizona'da, tek bir suçta belirtilen sınırın ne kadar üzerinde hız yapmak bir CDL sahibi için 'ciddi trafik ihlali' sayılır?","options":["10 mph veya daha fazla üzerinde","15 mph veya daha fazla üzerinde","20 mph veya daha fazla üzerinde","25 mph veya daha fazla üzerinde"],"explanation":"A.R.S. 28-3312(J) uyarınca, belirtilen sınırın 15 mph veya daha fazla üzerinde aşırı hız yapmak ciddi bir trafik ihlalidir. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı."},"45":{"q":"Aşağıdakilerden hangisi bir Arizona CDL sahibi için BÜYÜK bir suç olarak sınıflandırılır (sadece bir ciddi trafik ihlali değil)?","options":["Çok yakından takip etme (tampona yapışma)","Sınırın 15 mph üzerinde hız yapma","Uygunsuz veya düzensiz şerit değiştirme","Bir CMV içeren bir kazanın olay yerinden ayrılma"],"explanation":"Bir CMV içeren bir kazanın olay yerinden ayrılma (vur-kaç), 1 yıllık (tehlikeli madde varsa 3 yıllık) bir diskalifiye taşıyan büyük bir suçtur. Diğer üçü ciddi trafik ihlalleridir. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı."},"46":{"q":"Arizona'nın zımni rıza (implied consent) yasası uyarınca, bir DUI durdurmasında yasal bir kimyasal (nefes/kan) testini reddeden bir CDL sahibinin ticari sürüş ayrıcalığına ne olur?","options":["İlk reddetmede yalnızca bir uyarı","30 günlük bir CDL diskalifiyesi","En az 1 yıllık bir CDL diskalifiyesi","Ticari olarak araç kullanılmıyorsa CDL üzerinde etki yok"],"explanation":"Yasal bir kimyasal testi reddetmek, büyük bir suç gibi muamele görür: zımni rıza ehliyet askıya alımına ek olarak en az bir yıllık bir CDL diskalifiyesi (plakalı tehlikeli madde taşınıyorsa üç yıl). Kaynak: A.R.S. 28-1321 (zımni rıza); A.R.S. 28-3312; Arizona CDL El Kitabı."},"47":{"q":"Arizona'da, bir CDL sahibini diskalifiye eden bir DUI suçu şurada işlenebilir:","options":["Yalnızca bir ticari motorlu araçta","Yalnızca tehlikeli madde taşıyan bir araçta","Ya bir ticari YA DA bir kişisel (ticari olmayan) araçta","Yalnızca 26.001 pounddan ağır bir araçta"],"explanation":"HERHANGİ bir araçta, ticari veya kişisel, bir DUI mahkumiyeti CDL'yi diskalifiye eder. Bir sürücü, özel bir arabada işlenen bir DUI nedeniyle CDL'sini kaybedebilir. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı."},"48":{"q":"Arizona'da bir CDL sahibinin İLK hizmet dışı (out-of-service, OOS) emri ihlali için diskalifiye süresi nedir?","options":["60 gün","90 gün","180 gün","1 yıl"],"explanation":"İlk hizmet dışı emri ihlali, en az 180 günlük bir diskalifiye ile sonuçlanır. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı (49 CFR 383.51'i yansıtır)."},"49":{"q":"Arizona'da, 10 yıllık bir süre içinde İKİNCİ bir hizmet dışı emri ihlali için diskalifiye nedir (tehlikeli madde olmayan, yolcu olmayan)?","options":["180 gün","1 yıl","2 yıl","5 yıl"],"explanation":"10 yıl içinde ikinci bir hizmet dışı emri ihlali, en az 2 yıllık bir diskalifiye ile sonuçlanır. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı."},"50":{"q":"Arizona'da bir CDL sürücüsü, 10 yıl içinde ÜÇÜNCÜ bir hizmet dışı emri ihlali işliyor. Asgari diskalifiye şudur:","options":["1 yıl","2 yıl","3 yıl","Ömür boyu"],"explanation":"10 yıl içinde üçüncü veya sonraki bir hizmet dışı emri ihlali, en az 3 yıllık bir diskalifiye ile sonuçlanır. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı."},"51":{"q":"Arizona'da bir CDL sahibinin İLK demiryolu hemzemin geçit ihlali için diskalifiye nedir?","options":["60 günden az olmamak üzere","90 günden az olmamak üzere","120 günden az olmamak üzere","1 yıl"],"explanation":"İlk demiryolu hemzemin geçit ihlali, 60 günden az olmamak üzere bir diskalifiye ile sonuçlanır. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı."},"52":{"q":"Arizona'da, bir CDL sürücüsünün 3 yıl içinde İKİNCİ demiryolu hemzemin geçit ihlali, şu kadardan az olmamak üzere bir diskalifiye ile sonuçlanır:","options":["60 gün","120 gün","180 gün","1 yıl"],"explanation":"Üç yıl içinde ikinci bir demiryolu hemzemin geçit ihlali, 120 günden az olmamak üzere bir diskalifiye ile sonuçlanır. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı."},"53":{"q":"Arizona'da bir CDL sahibi, 3 yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu hemzemin geçit ihlali işliyor. Diskalifiye şu kadardan az değildir:","options":["120 gün","180 gün","1 yıl","3 yıl"],"explanation":"Üç yıl içinde üçüncü veya sonraki bir demiryolu hemzemin geçit ihlali, bir yıldan az olmamak üzere bir diskalifiye ile sonuçlanır. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı."},"54":{"q":"Bir kontrollü maddenin imalatı, dağıtımı veya temini içeren bir suçun işlenmesinde bir araç kullanmak, Arizona'da ne tür bir CDL diskalifiyesiyle sonuçlanır?","options":["1 yıl","3 yıl","10 yıl","Yeniden ehliyet alma imkanı olmayan kalıcı (ömür boyu) bir diskalifiye"],"explanation":"Bir kontrollü maddenin imalatı, dağıtımı veya temini içeren bir suçta motorlu bir araç kullanmak, 10 yıllık yeniden ehliyet alma hakkına UYGUN OLMAYAN kalıcı (ömür boyu) bir diskalifiye ile sonuçlanır. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı."},"55":{"q":"Arizona CDL sürücülerine uygulanan kural uyarınca, bir CMV kullanırken kısa mesaj göndermek veya okumak, SÜRÜCÜYÜ şu kadara kadar bir hukuki para cezasına tabi tutabilir:","options":["$500","$1,000","$2,750","$11,000"],"explanation":"Bir CMV kullanırken mesajlaşmak, sürücü için $2,750'ye kadar bir federal hukuki para cezasıyla sonuçlanabilir (işverenler buna izin verdikleri veya bunu gerektirdikleri için $11,000'e kadar ceza ile karşı karşıya kalır). Bir mesajlaşma/elde tutulan telefon mahkumiyeti aynı zamanda ciddi bir trafik ihlalidir. Kaynak: 49 CFR 392.80/392.82 (FMCSA Mesajlaşma Yasağı Kuralı); Arizona CDL El Kitabı."},"56":{"q":"Bir Arizona CDL sürücüsü için, bir CMV kullanırken ELDE TUTULAN bir cep telefonu kullanmaya yalnızca sürücünün şu durumda izin verilir:","options":["Aramayı bir dakikanın altında tutarsa","Kırmızı ışıkta durmuşsa","Eller serbest bir düzenek kullanır ve oturmuş ve emniyet kemeri takılı haldeyken en fazla tek bir düğmeye basarsa","Özel bir yoldaysa"],"explanation":"Kural, telefonu tutmayı, ona uzanmayı veya birden fazla düğmeye basmayı yasaklar; eller serbest kullanıma yalnızca sürücü, oturmuş, emniyet kemeri takılı sürüş pozisyonunda kalarak tek bir düğme dokunuşuyla aramayı başlatabilir/yanıtlayabilirse izin verilir. İhlaller ciddi trafik ihlalleri sayılır. Kaynak: 49 CFR 392.82; Arizona CDL El Kitabı."},"57":{"q":"Bir CDL sahibi büyük bir suçtan mahkum oluyor ve ömür boyu diskalifiyeye ulaşıyor. Arizona/federal kurallar uyarınca, yeniden ehliyet alma yalnızca şu asgari süreden sonra mümkün olabilir:","options":["3 yıl","5 yıl","10 yıl ve onaylanmış bir rehabilitasyon programının tamamlanması","Asla yeniden ehliyet alınamaz"],"explanation":"İki büyük suçtan kaynaklanan ömür boyu bir diskalifiye, sürücü onaylanmış bir rehabilitasyon programını tamamlarsa en az 10 yıl sonra yeniden ehliyet almaya izin verecek şekilde azaltılabilir; kontrollü madde suçu diskalifiyeleri kalıcı kalır. Kaynak: A.R.S. 28-3312; Arizona CDL El Kitabı."},"58":{"q":"Yola çizilmiş beyaz bir durma çizgisinin bulunmadığı bir demiryolu-karayolu geçidinde, durmak zorunda olan bir Arizona CDL sürücüsü aracını nerede durdurmalıdır?","options":["En yakın raya 5 feet'ten daha yakın ve 25 feet'ten daha uzak olmayacak şekilde","En yakın raya 15 feet'ten daha yakın ve 50 feet'ten daha uzak olmayacak şekilde","En yakın raya 20 feet'ten daha yakın ve 75 feet'ten daha uzak olmayacak şekilde","En yakın raya 10 feet'ten daha yakın ve 100 feet'ten daha uzak olmayacak şekilde"],"explanation":"Arizona CDL Kılavuzu ve ARS 28-853, durma çizgisi bulunmadığında otobüslerin, ücret karşılığı yolcu taşıyan araçların ve plakart taşıyan/yanıcı yük taşıyan araçların en yakın raya 50 feet'ten uzak olmamak, ancak 15 feet'ten daha yakın olmamak kaydıyla durmasını gerektirir. Kaynak: Arizona CDL Kılavuzu böl. 2.15; ARS 28-853."},"59":{"q":"Arizona'nın Move Over (Şerit Değiştir) yasasına göre, dört şeritli bir karayolunda (aynı yönde iki veya daha fazla şerit) yanıp sönen veya uyarı ışıkları yanan duran bir araca yaklaşan bir sürücünün ilk olarak yapması gereken nedir?","options":["Duran araç ayrılana kadar tamamen durmak","Duran aracın yanından geçerken kornaya sürekli basmak","Banket üzerine çekmek ve bir memurun geçmesi için işaret etmesini beklemek","Güvenli ve mümkünse duran araçtan uzaklaşacak şekilde şerit değiştirmek"],"explanation":"ARS 28-775, sürücülerin güvenli olduğunda bitişik olmayan bir şeride geçerek yol vermesini gerektirir; yalnızca şerit değiştirmek güvenli değilse sürücü güvenli bir hıza yavaşlamalıdır. Kaynak: ARS 28-775; AZDPS Move Over Yasası sayfası."},"60":{"q":"Arizona'da, beyan edilen brüt ağırlığı 26.000 pound'un üzerinde olan bir motorlu araç veya kombinasyon için (yolcu otobüsü dışında), ADOT daha yüksek bir limit ilan etmediği sürece azami hız sınırı nedir?","options":["Saatte 55 mil","Saatte 60 mil","Saatte 75 mil","Saatte 65 mil"],"explanation":"ARS 28-709, 26.000 lbs üzerindeki ağır ticari araçları (ve 6.000+ lbs ağırlığında bir direk römorku çeken araçları), ADOT bir mühendislik incelemesi sonrasında daha yüksek bir limit ilan etmediği sürece 65 mph ile sınırlandırır. Kaynak: ARS 28-709."},"61":{"q":"Arizona CDL Kılavuzu'na göre, tek yönlü veya bölünmüş bir karayolunda veya kenarında dururken, üç yansıtıcı uyarı üçgeni yaklaşan trafiğe doğru nereye yerleştirilmelidir?","options":["Yaklaşan trafiğe doğru 10 feet, 50 feet ve 150 feet mesafede","Yaklaşan trafiğe doğru 25 feet, 75 feet ve 125 feet mesafede","Yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet mesafede","Yaklaşan trafiğe doğru 15 feet, 100 feet ve 300 feet mesafede"],"explanation":"Arizona CDL Kılavuzu, tek yönlü veya bölünmüş bir karayolunda duran sürücülerin uyarı cihazlarını 10 dakika içinde yaklaşan trafiğe doğru 10, 100 ve 200 feet mesafelere yerleştirmesini ister. Kaynak: Arizona CDL Kılavuzu böl. 2.5."},"62":{"q":"Her iki yönde trafik taşıyan iki şeritli bir yolda (bölünmemiş karayolu), Arizona CDL Kılavuzu durduktan sonra uyarı üçgenlerinin nereye yerleştirileceğini söyler?","options":["Aracın 25 feet yakınına ve önünde ve arkasında 200 feet mesafeye","Aracın 50 feet yakınına ve önünde ve arkasında 150 feet mesafeye","Aracın 10 feet yakınına ve önünde ve arkasında 250 feet mesafeye","Aracın 10 feet yakınına ve önünde ve arkasında 100 feet mesafeye"],"explanation":"Bölünmemiş iki yönlü bir yolda, Arizona CDL Kılavuzu aracın 10 feet yakınına bir üçgen, ayrıca 100 feet önüne bir tane ve 100 feet arkasına bir tane yerleştirilmesini gerektirir. Kaynak: Arizona CDL Kılavuzu böl. 2.5."},"63":{"q":"Arizona'da ticari bir araçla demiryolu raylarını geçerken, yasa ve CDL Kılavuzu sürücünün ne yapmasını yasaklar?","options":["Dörtlü acil durum flaşörlerini kullanmak","Trenler için sola ve sağa bakmak","Rayı veya rayları geçerken vites değiştirmek","Bariyerler yukarıdayken geçmek"],"explanation":"ARS 28-853 ve Arizona CDL Kılavuzu, geçitte stop etmeyi önlemek için sürücünün rayları geçerken vites değiştirmemesi gerektiğini belirtir. Kaynak: ARS 28-853; Arizona CDL Kılavuzu böl. 2.15.5."},"64":{"q":"Arizona'nın okul otobüsü durma kurallarına göre (ARS 28-857), yanıp sönen kırmızı ışıkları etkinleştirilmiş bir okul otobüsü için durmak zorunda OLMAYAN karşı yönden gelen sürücü hangisidir?","options":["Otobüsten bir orta dönüş şeridiyle ayrılan, tam karşı şeritteki bir sürücü","İki şeritli bölünmemiş bir yolda otobüse yaklaşan bir sürücü","Otobüsün arkasında aynı seyir yönünde bulunan bir sürücü","Ayrı yolları olan bir karayolunun farklı bir yolunda seyreden bir sürücü"],"explanation":"ARS 28-857, ayrı yolları olan bir karayolunun (fiziksel olarak bölünmüş bir karayolu) farklı bir yolundaki sürücüyü muaf tutar; boyalı çizgiler veya iki yönlü sola dönüş şeridi ayrı yollar OLUŞTURMAZ. Kaynak: ARS 28-857."},"65":{"q":"İki yönlü sola dönüş (orta) şeridi olan ancak fiziksel bir refüjü olmayan bir Arizona karayolunda, bir okul otobüsü kırmızı ışıkları yanıp sönerek durduğunda karşı yönden gelen bir sürücü ne yapmalıdır?","options":["Dönüş şeridi yolu böldüğü için durmadan devam etmek","15 mph'ye yavaşlamak ancak durmaya gerek yok","Yalnızca çocuklar gözle görülür şekilde karşıdan karşıya geçiyorsa durmak","Durmak, çünkü orta dönüş şeridi ayrı bir yol değildir"],"explanation":"ARS 28-857, iki yönlü sola dönüş şeridinin her iki yanındaki bir şeridin veya şerit grubunun ayrı bir yol olmadığını belirtir, bu nedenle karşı yönden gelen trafik durmalıdır. Kaynak: ARS 28-857."},"66":{"q":"Arizona yasası (ARS 28-853) hangi araçların devam etmeden önce her demiryolu hemzemin geçidinde durmasını özellikle gerektirir?","options":["Yalnızca tehlikeli madde plakartları taşıyan araçlar","10.000 pound'dan ağır tüm ticari araçlar","Otobüsler/ücret karşılığı yolcu taşıyan araçlar, okul otobüsleri ve patlayıcı veya yanıcı sıvı taşıyan araçlar","Yalnızca öğrenciler içindeyken okul otobüsleri"],"explanation":"ARS 28-853, ücret karşılığı yolcu taşıyan motorlu araçları, çocuk taşıyan okul otobüslerini ve yük olarak patlayıcı madde veya yanıcı sıvı taşıyan araçları belirtir. Kaynak: ARS 28-853."},"67":{"q":"Arizona CDL Okul Otobüsü bölümüne göre, bir okul otobüsü sürücüsü bir demiryolu geçidine yaklaşırken tehlike ışıklarını ne zaman etkinleştirmelidir?","options":["Geçitten en az yaklaşık 100 feet önce","Geçitten en az yaklaşık 300 feet önce","Yalnızca otobüs tamamen durduktan sonra","Geçitten yaklaşık 50 feet önce"],"explanation":"Arizona CDL Kılavuzu okul otobüsü bölümü, sürücülere niyetlerini belirtmek için geçitten en az yaklaşık 100 feet önce tehlike ışıklarını etkinleştirmelerini söyler. Kaynak: Arizona CDL Kılavuzu böl. 10.4."},"68":{"q":"Arizona'nın Move Over yasasının (ARS 28-775) İLK ihlali için uygulanan idari para cezası nedir?","options":["$150","$275","$500","$1,000"],"explanation":"ARS 28-775, ilk ihlal için $275 idari para cezası belirler; bu, beş yıl içindeki ikinci ihlal için $500'a ve üçüncü için $1,000'a yükselir. Kaynak: ARS 28-775."},"69":{"q":"Arizona'daki çok şeritli yollarda, ARS 28-721 normal trafik hızından daha yavaş seyreden bir sürücüden ne ister?","options":["Her zaman orta şeritte kalmak","Sollama veya sola dönüş hazırlığı dışında sağ şeritte sürmek","Yalnızca sol şeridi kullanmak, böylece daha hızlı trafik sağdan geçebilsin","Herhangi bir şeritte en az 45 mph hızı korumak"],"explanation":"ARS 28-721, normal trafikten daha yavaş hareket eden bir aracın, sollama/geçiş yaparken veya sola dönüş için hazırlanırken hariç, sağ şeritte kalmasını gerektirir. Kaynak: ARS 28-721."},"70":{"q":"ADOT'tan bir geniş yük izni gerekmeden önce Arizona karayollarında izin verilen azami yasal araç GENİŞLİĞİ nedir?","options":["8 feet 6 inç","8 feet 0 inç","9 feet 0 inç","10 feet 0 inç"],"explanation":"Arizona'nın yasal azami genişliği 8 feet 6 inç'tir (102 inç); bundan daha geniş olan herhangi bir şey bir ADOT geniş yük izni gerektirir. Kaynak: ADOT Geniş Yük/Ağır Yük izin düzenlemeleri."},"71":{"q":"Bir Arizona geniş yük/ağır yük izni olmadan, genel olarak izin verilen azami brüt araç ağırlığı nedir?","options":["80.000 pound","100.000 pound","26.000 pound","120.000 pound"],"explanation":"Arizona, 80.000 lbs brüt federal yasal limiti izler; bunu aşmak bir ADOT ağır yük izni gerektirir. Kaynak: ADOT Geniş Yük/Ağır Yük izinleri; ARS Title 28."},"72":{"q":"Verde Valley yakınındaki I-17'de dik yokuştan inen güneye giden bir kamyon, 'Runaway Truck Ramp' (Kontrolden Çıkan Kamyon Rampası) tabelasını görüyor. Bu Arizona güvenlik özelliğinin amacı nedir?","options":["Tüm kamyonlar için zorunlu bir tartı istasyonu durağı sağlamak","Frenleri arızalanan veya aşırı ısınan bir aracın karayolundan ayrılıp güvenli bir şekilde durmasına izin vermek","Kışın belirlenmiş bir zincir takma alanı olarak hizmet vermek","Yorgun sürücüler için bir dinlenme alanı olarak işlev görmek"],"explanation":"I-17 gibi yokuşlardaki ADOT kontrolden çıkan kamyon (kaçış) rampaları, fren arızası olan kontrolden çıkmış kamyonların güvenli bir şekilde çıkıp durmasına izin verir; bunlara duyulan ihtiyaç yokuşun dikliği, uzunluğu ve kaza sıklığına dayanır. Kaynak: ADOT (Runaway Truck Ramps)."},"73":{"q":"Bir Arizona CDL sürücüsü, bir yolda veya bankette durduktan sonra acil durum uyarı cihazlarını kaç dakika içinde yerleştirmelidir?","options":["5 dakika içinde","15 dakika içinde","10 dakika içinde","30 dakika içinde"],"explanation":"Arizona CDL Kılavuzu, bir yolda veya bankette durduktan sonra acil durum uyarı cihazlarının 10 dakika içinde yerleştirilmesini gerektirir. Kaynak: Arizona CDL Kılavuzu böl. 2.5."},"74":{"q":"Arizona'da ışıkları yanıp sönen duran bir aracın yanından geçerken güvenli bir şekilde şerit değiştirilemiyorsa, ARS 28-775 bunun yerine sürücünün ne yapmasını gerektirir?","options":["İlan edilen hız sınırını korumak ama kornaya basmak","Gerekli dikkati göstererek devam etmek ve hızı koşullara uygun güvenli bir hıza düşürmek","Şerit değiştirmek için yol açılana kadar yol üzerinde tamamen durmak","Şerit değiştirmek imkansız olduğu için normal hızda devam etmek"],"explanation":"ARS 28-775, güvenli bir şerit değişikliği mümkün olmadığında sürücünün yavaşlaması ve koşullara uygun güvenli bir hızda dikkatle devam etmesi gerektiğini öngörür. Kaynak: ARS 28-775."},"75":{"q":"Arizona CDL Kılavuzu, bir çekici-römork kombinasyonunun TEK bir demiryolu rayını yaklaşık ne kadar sürede geçtiğini belirtir ve karşıya geçmeye başlamadan önce tamamen geçebileceğinizden emin olmanız gerektiğini vurgular?","options":["En az yaklaşık 14 saniye","Yaklaşık 5 saniye","Yaklaşık 30 saniye","Yaklaşık 8 saniye"],"explanation":"Arizona CDL Kılavuzu, tipik bir çekici-römorkun tek bir rayı geçmek için en az 14 saniyeye ve çift ray için 15 saniyeden fazlasına ihtiyaç duyduğunu belirtir, bu yüzden tamamen geçemeyecekseniz asla karşıya geçmeye başlamayın. Kaynak: Arizona CDL Kılavuzu böl. 2.15.5."},"76":{"q":"Fiziksel bir refüjü olan bölünmüş bir karayolunda, bir Arizona sürücüsü KARŞI yolda kırmızı ışıkları yanıp sönen duran bir okul otobüsüne ve AYNI yolda duran bir otobüse nasıl tepki vermelidir?","options":["Karşı yol için durma gerekli değil, ancak aynı yolda durma gereklidir","Refüjden bağımsız olarak her iki yönde de durma gereklidir","Karayolu bölünmüş olduğu için her iki yönde de durma gerekli değildir","Yalnızca karşı yolda durma gereklidir"],"explanation":"ARS 28-857 uyarınca, fiziksel olarak ayrı (karşı) bir yoldaki trafiğin durması gerekmez, ancak aynı yolda otobüsle karşılaşan veya onu takip eden araçlar ışıklar sönene kadar durmalıdır. Kaynak: ARS 28-857."},"77":{"q":"İhlal edenler için, Arizona'da kırmızı ışıkları yanıp sönen duran bir okul otobüsünü yasadışı şekilde geçmenin ilk suçu için ASGARİ idari para cezası nedir (ARS 28-857)?","options":["$100","$500","$250","$1,000"],"explanation":"ARS 28-857, ilk ihlal için asgari $250 idari para cezası belirler; 36 ay içindeki ikinci ihlal en az $750 ve üçüncüsü en az $1,000'dır, her ikisi de olası ehliyet askıya alınmasıyla birlikte. Kaynak: ARS 28-857."},"78":{"q":"Hangi Arizona kurumu Ticari Sürücü Belgelerini (CDL) düzenler?","options":["Arizona Ulaştırma Bakanlığı (ADOT) Motorlu Araçlar Birimi (MVD)","Arizona Kamu Güvenliği Bakanlığı","Arizona Ağırlıklar ve Ölçüler Bakanlığı","Federal Motorlu Taşıyıcı Güvenlik İdaresi (FMCSA)"],"explanation":"Arizona'da CDL'ler, Arizona Ulaştırma Bakanlığı (ADOT) Motorlu Araçlar Birimi (MVD) tarafından düzenlenir. FMCSA federal standartları belirler ancak gerçek belgeyi düzenlemez. Kaynak: ADOT MVD, Getting Your Commercial Driver License sayfası."},"79":{"q":"Arizona'da her CDL bilgi (yazılı) sınavını geçmek için almanız gereken asgari puan nedir?","options":["Yüzde 80","Yüzde 70","Yüzde 75","Yüzde 85"],"explanation":"Arizona MVD bilgi sınavları, her sınavı geçmek için asgari yüzde 80 puan gerektirir. Kaynak: ADOT MVD, Getting Your Commercial Driver License / Tests and Manuals sayfaları."},"80":{"q":"Arizona'da CDL beceri sınavına girebilmeniz için, Ticari Öğrenci İzninizi (CLP) ne kadar süre elinizde bulundurmuş olmanız gerekir?","options":["En az 14 gün","En az 30 gün","En az 10 gün","En az 60 gün"],"explanation":"Arizona federal kuralı izler: bir CLP sahibi, CDL beceri sınavına girmeden önce CLP düzenlendikten sonra en az 14 gün beklemelidir. Kaynak: ADOT MVD, Getting Your Commercial Driver License sayfası (49 CFR 383.25)."},"81":{"q":"Bir Arizona Ticari Öğrenci İzni (CLP) en fazla hangi süre için geçerlidir?","options":["12 ay","6 ay","180 gün","24 ay"],"explanation":"Bir Arizona CLP en fazla 12 ay süreyle geçerlidir. Kaynak: ADOT MVD, Getting Your Commercial Driver License sayfası."},"82":{"q":"Bir CDL sahibinin DOT Tıbbi Muayene Sertifikası genel olarak ne sıklıkla yenilenmelidir?","options":["Her 24 ayda bir veya daha erken","Her 12 ayda bir veya daha erken","Her 36 ayda bir veya daha erken","Her 48 ayda bir veya daha erken"],"explanation":"Tıbbi Muayene Sertifikası, tıbbi muayene uzmanı veya düzenleme tarafından belirlendiği üzere her 24 ayda bir veya daha erken yenilenmelidir. Kaynak: ADOT MVD, Medical Certification (CDL) sayfası."},"83":{"q":"Arizona CDL beceri sınavı hangi üç bölüme ayrılır?","options":["Sefer öncesi muayene, temel araç kontrolü ve yolda sürüş","Yazılı bilgi, görme taraması ve yolda sürüş","Sefer öncesi muayene, hazmat taşıma ve gece sürüşü","Yalnızca geri gitme, paralel park ve otoyola katılma"],"explanation":"Arizona CDL beceri sınavının üç bileşeni vardır: sefer öncesi muayene, temel araç kontrolleri ve yolda (yol) sürüş sınavı. Kaynak: ADOT MVD, Tests and Manuals sayfası; Arizona CDL Kılavuzu Bölüm 11-13."},"84":{"q":"Bir CDL fizik muayenesinin Arizona'da kabul edilmesi için bir tıbbi muayene uzmanı nerede listelenmiş olmalıdır?","options":["FMCSA Ulusal Sertifikalı Tıbbi Muayene Uzmanları Sicili'nde","ADOT onaylı hekimler listesinde","Arizona Tıp Kurulu'nun uzmanlar listesinde","Herhangi bir eyaletin DMV onaylı doktor listesinde"],"explanation":"CDL fizik muayenesi, FMCSA Ulusal Sertifikalı Tıbbi Muayene Uzmanları Sicili'nde listelenmiş bir tıbbi muayene uzmanı tarafından yapılmalıdır (49 CFR 391.41/391.43 uyarınca). Kaynak: ADOT MVD, Medical Certification (CDL) sayfası."},"85":{"q":"Standart (eyalet içiyle sınırlı olmayan) bir CDL sahibi için, Tıbbi Muayene Sertifikası normalde Arizona MVD'ye nasıl iletilir?","options":["Sertifikalı tıbbi muayene uzmanı bunu MVD'ye elektronik olarak gönderir","Sürücü kağıt sertifikayı MVD merkezine postalar","İşveren bunu sürücü adına MVD'ye faksla gönderir","FMCSA uzman müdahalesi olmadan otomatik olarak iletir"],"explanation":"Sertifikalı tıbbi muayene uzmanı Tıbbi Muayene Sertifikasını (MEC) MVD'ye elektronik olarak gönderir; sürücüler bir MVD ofisini ziyaret etmeden önce 24 saat beklemelidir. Kaynak: ADOT MVD, Medical Certification (CDL) sayfası."},"86":{"q":"Arizona'da bir CDL başvuru sahibinin aralarından seçim yapması gereken dört öz sertifikasyon kategorisi nedir?","options":["Muaf Olmayan Eyaletler Arası, Muaf Eyaletler Arası, Muaf Olmayan Eyalet İçi ve Muaf Eyalet İçi","Eyaletler Arası, Eyalet İçi, Federal ve Eyalet","Ticari, Ticari Olmayan, Hazmat ve Tanker","Sınıf A, Sınıf B, Sınıf C ve Sınıf D"],"explanation":"CDL öz sertifikasyonu, dört kategoriden birini seçmeyi gerektirir: Muaf Olmayan Eyaletler Arası, Muaf Eyaletler Arası, Muaf Olmayan Eyalet İçi veya Muaf Eyalet İçi. Kaynak: ADOT MVD CDL öz sertifikasyonu / Form 96-0526 (49 CFR 383.71)."},"87":{"q":"Hangi öz sertifikasyon kategorisi, sürücünün federal DOT tıbbi kart gereksinimlerini karşılamasını gerektirir?","options":["Muaf Olmayan Eyaletler Arası","Muaf Eyaletler Arası","Muaf Eyalet İçi","Muaf Olmayan Eyalet İçi"],"explanation":"Muaf Olmayan Eyaletler Arası olarak öz sertifikasyon yapan bir sürücü, eyaletler arası ticarette faaliyet gösterir ve federal DOT tıbbi sertifika gereksinimlerini karşılamalıdır. Muaf kategoriler federal tıbbi kartı gerektirmez. Kaynak: ADOT MVD / FMCSA öz sertifikasyonu (49 CFR 383.71)."},"88":{"q":"Bir Arizona CDL'sinde, 'K' kısıtlaması sürücü hakkında neyi gösterir?","options":["Sürücü eyalet içi (yalnızca Arizona) faaliyetle sınırlıdır","Sürücü hava frenli araçları kullanamaz","Sürücü tehlikeli madde taşıyamaz","Sürücü düzeltici lensler takmalıdır"],"explanation":"Bir 'K' kısıtlaması, sürücünün yalnızca eyalet içi ticaretle (Arizona içinde sürüş) sınırlı olduğu anlamına gelir. Bu tür sürücüler kağıt MEC ve uzun formu MVD'ye göndermeye devam eder. Kaynak: ADOT MVD, Medical Certification (CDL) / CDL Restrictions sayfaları."},"89":{"q":"Arizona'da yalnızca eyalet içi 'K' kısıtlamasına sahip bir CDL sahibi için, tıbbi sertifika nasıl gönderilir?","options":["Kağıt MEC ve uzun formu inceleme için MVD'ye göndermeye devam ederek","Yalnızca Ulusal Sicil aracılığıyla elektronik olarak","Eyalet içi sürücüler için gerekli değildir","FMCSA sürücü portalı üzerinden yükleyerek"],"explanation":"Eyalet içi (K kısıtlamalı) sürücüler, elektronik Ulusal Sicil gönderimine güvenmek yerine kağıt Tıbbi Muayene Sertifikasını ve uzun formu inceleme için MVD'ye göndermeye devam eder. Kaynak: ADOT MVD, Medical Certification (CDL) sayfası."},"90":{"q":"Sahibi MVD'de güncel bir Tıbbi Muayene Sertifikası bulundurmazsa bir CDL'ye ne olur?","options":["CDL askıya alınmaya ve iptal edilmeye tabidir","Sürücü eyalet içinde kaldığı sürece hiçbir şey olmaz","Sürücü bir yıllık otomatik uzatma alır","Yalnızca hazmat onayı kaldırılır"],"explanation":"MVD'de güncel bir Tıbbi Muayene Sertifikası bulundurmamak, CDL ayrıcalıklarının askıya alınması ve iptal edilmesiyle sonuçlanır. Kaynak: ADOT MVD, Medical Certification (CDL) sayfası."},"91":{"q":"Giriş Seviyesi Sürücü Eğitimi (ELDT) kurallarına göre, ilk kez başvuran bir Arizona başvuru sahibi ELDT'yi ne zaman tamamlamalıdır?","options":["İlk Sınıf A veya B CDL için CDL beceri sınavına girmeden önce","Beceri sınavını geçtikten sonra ancak belge basılmadan önce","Yalnızca bir yıl CDL sahibi olduktan sonra","Yalnızca başvuru sahibi 21 yaşından küçükse"],"explanation":"ELDT, ilk kez Sınıf A veya B CDL için, B'den A'ya yükseltme için veya ilk kez S, P veya H onayı için beceri sınavına girmeden önce (FMCSA Eğitim Sağlayıcı Sicili'nde listelenmiş bir okul aracılığıyla) tamamlanmalıdır. Kaynak: ADOT MVD; 49 CFR Part 380."},"92":{"q":"Bir Arizona MVD ofisinde CDL başvurusu yaparken aşağıdakilerden hangisi bir belge gereksinimidir?","options":["ABD'de yasal varlık kanıtı, iki Arizona ikamet kanıtı ve bir Sosyal Güvenlik numarası","Yalnızca mevcut bir işverenden noter onaylı bir mektup","Yalnızca doğum ülkesinden bir pasaport ve başka hiçbir şey","Tamamlanmış bir savunmacı sürüş kursu kanıtı"],"explanation":"Başvuru sahipleri, ABD'deki varlıklarının federal yasa kapsamında yetkili olduğunun kanıtını, iki ikamet adresi kanıtını ve Sosyal Güvenlik numaralarını, ayrıca geçerli bir Tıbbi Muayene Sertifikasını sağlamalıdır. Kaynak: ADOT MVD, Getting Your Commercial Driver License sayfası."},"93":{"q":"MVD CDL ofislerinin yanı sıra, Arizona'da CDL yol/beceri sınavını uygulama yetkisine başka kim sahiptir?","options":["Kamu ve özel kuruluşlardaki MVD sertifikalı üçüncü taraf sınav uygulayıcıları","Beş yıllık deneyime sahip herhangi bir lisanslı ticari sürücü","Arizona'yı ziyaret eden eyalet dışı DMV sınav görevlileri","Yalnızca FMCSA federal müfettişleri"],"explanation":"MVD CDL ofislerine ek olarak, Arizona'daki birçok kamu ve özel kuruluş, yol/beceri sınavını uygulama yetkisine sahip MVD sertifikalı sınav uygulayıcılarına sahiptir. Kaynak: ADOT MVD, CDL Examination Program / sınav lokasyonları sayfaları."},"94":{"q":"Bir Arizona CDL'si en fazla kaç yıl süreyle geçerlidir?","options":["8 yıla kadar","4 yıla kadar","5 yıla kadar","10 yıla kadar"],"explanation":"Arizona CDL'leri 8 yıla kadar bir süre için geçerlidir ve sürücü sona ermeden önce yenilemekten sorumludur. Daha kısa bir tıbbi sertifika döngüsünün yine de bir derece düşürmeyi tetikleyebileceğini unutmayın. Kaynak: ADOT MVD, Managing Your Commercial Driver License sayfası."},"95":{"q":"Arizona'da eyaletler arası (eyalet dışı) ticaret için geçerli bir CDL almak için asgari yaş nedir?","options":["21 yaşında","18 yaşında","19 yaşında","25 yaşında"],"explanation":"Bir sürücünün eyaletler arası ticaret için bir CDL alabilmesi için en az 21 yaşında olması gerekir. 18 ila 20 yaşındaki başvuru sahipleri, eyalet içi (yalnızca Arizona) faaliyetle sınırlı bir CDL alabilir. Kaynak: ADOT MVD, Getting Your Commercial Driver License sayfası (49 CFR 383.3)."},"96":{"q":"Bir sürücü Arizona'da Muaf Olmayan Eyalet İçi veya Muaf Eyalet İçi olarak öz sertifikasyon yaparsa, sonuç ne olur?","options":["Sürücü, eyaletler arası ticarette ticari bir motorlu araç kullanamaz","Sürücü tüm beceri sınavlarından muaftır","Sürücü yalnızca okul otobüsü kullanabilir","Sürücünün CDL'sinin hiçbir zaman yenilenmesine gerek yoktur"],"explanation":"Muaf Olmayan Eyalet İçi veya Muaf Eyalet İçi olarak sertifikasyon, sürücüyü eyalet içi ticaretle sınırlar; eyaletler arası ticarette bir CMV kullanamazlar. Kaynak: ADOT MVD, Managing Your Commercial Driver License sayfası (49 CFR 383.71)."},"97":{"q":"Hangi ifade Arizona'nın CDL sınavı süreç ve ücret yapısını en iyi şekilde açıklar?","options":["Bilgi ve beceri sınavları MVD veya sertifikalı sınav uygulayıcıları aracılığıyla uygulanır ve tam ücretler ADOT tarafından belirlenir ve zaman içinde değişebilir","Arizona'da tüm CDL sınavları her zaman ücretsizdir","Ücretler federal yasayla kalıcı olarak belirlenir ve asla değişmez","Tüm CDL ile ilgili ücretleri yalnızca federal hükümet tahsil eder"],"explanation":"Arizona CDL bilgi ve beceri sınavları, MVD ofisleri ve MVD sertifikalı üçüncü taraf sınav uygulayıcıları aracılığıyla uygulanır; geçerli ücretler ADOT tarafından belirlenir ve değişebilir, bu nedenle başvuru sahipleri güncel tutarları MVD ile doğrulamalıdır. Kaynak: ADOT MVD, CDL Examination Program / ücret çizelgesi sayfaları."}},"es":{"0":{"q":"En la mayoría de las carreteras de Arizona, incluido el sistema interestatal, ¿cuál es el ancho máximo legal de un vehículo comercial o su carga, sin contar el equipo de seguridad?","options":["8 pies 0 pulgadas (96 pulgadas)","8 pies 6 pulgadas (102 pulgadas)","9 pies 0 pulgadas (108 pulgadas)","10 pies 0 pulgadas (120 pulgadas)"],"explanation":"Arizona limita el ancho exterior total a 102 pulgadas (8 pies 6 pulgadas) en el sistema interestatal, en las carreteras con ayuda federal y carreteras estatales designadas, y en las rutas de acceso razonable; las cargas más anchas que esto requieren un permiso de sobredimensión. Fuente: A.R.S. 28-1093 (ancho del vehículo)."},"1":{"q":"Sin un permiso especial, ¿cuál es la altura máxima legal de un vehículo, incluida su carga, por encima de la superficie de la carretera en Arizona?","options":["12 pies 6 pulgadas","13 pies 0 pulgadas","13 pies 6 pulgadas","14 pies 0 pulgadas"],"explanation":"Un vehículo, cargado o descargado, no puede exceder los 13 pies 6 pulgadas de altura por encima de la superficie sobre la que se encuentra sin un permiso. Fuente: A.R.S. 28-1094 (altura del vehículo)."},"2":{"q":"¿Cuál es el peso bruto máximo permitido sobre un eje sencillo en las carreteras de Arizona, incluidas las tolerancias de fiscalización?","options":["18,000 libras","20,000 libras","22,400 libras","24,000 libras"],"explanation":"Arizona limita cualquier eje sencillo a 20,000 libras, incluidas las tolerancias de fiscalización, coincidiendo con el estándar federal. Fuente: A.R.S. 28-1100 y 28-1099 (límite de carga por eje sencillo)."},"3":{"q":"¿Cuál es el peso bruto máximo permitido sobre un eje tándem en las carreteras de Arizona, incluidas las tolerancias de fiscalización?","options":["32,000 libras","34,000 libras","36,000 libras","40,000 libras"],"explanation":"Arizona limita un eje tándem a 34,000 libras, incluidas las tolerancias de fiscalización, en consonancia con el estándar federal. Fuente: A.R.S. 28-1100 (restricciones de peso bruto)."},"4":{"q":"Sin un permiso de sobrepeso, ¿cuál es el peso bruto máximo para una combinación de vehículos de cinco o más ejes en las carreteras de Arizona?","options":["73,280 libras","76,000 libras","80,000 libras","84,000 libras"],"explanation":"Arizona fija el peso bruto máximo legal en 80,000 libras para una combinación de vehículos de cinco o más ejes, igual que el máximo federal. Fuente: A.R.S. 28-1100 (restricciones de peso bruto)."},"5":{"q":"¿Cómo define el estatuto de Arizona un \"eje tándem\" a efectos de los límites de peso por eje?","options":["Dos ejes consecutivos separados por no más de 40 pulgadas","Dos o más ejes consecutivos separados por más de 40 pulgadas pero no más de 96 pulgadas","Cualquier par de ejes separados por más de 96 pulgadas","Dos ejes consecutivos separados exactamente 8 pies"],"explanation":"Arizona define los ejes tándem como dos o más ejes consecutivos cuyos centros están separados por más de 40 pulgadas pero no más de 96 pulgadas. Fuente: A.R.S. 28-1100 (definiciones)."},"6":{"q":"Arizona utiliza la fórmula federal de puentes W = 500(LN/(N-1) + 12N + 36) para limitar el peso bruto sobre un grupo de ejes. En esa fórmula, ¿qué representa \"L\"?","options":["La capacidad nominal legal de carga del eje delantero","La distancia en pies entre los ejes extremos del grupo","La longitud total del vehículo en pies","La capacidad de levantamiento de la suspensión en toneladas"],"explanation":"En la fórmula de puentes adoptada por Arizona, W es el peso bruto máximo sobre el grupo, L es la distancia en pies entre los ejes exteriores (extremos) del grupo y N es el número de ejes en el grupo. Fuente: A.R.S. 28-1100 (restricciones de peso bruto)."},"7":{"q":"Según la fórmula de puentes de Arizona, ¿qué permite generalmente aumentar el espaciamiento (L) entre los ejes extremos de un grupo?","options":["Un peso bruto permitido menor sobre el grupo","Un peso bruto permitido mayor sobre el grupo","Ningún cambio, ya que solo importa el número de ejes","Un límite de eje sencillo mayor pero un peso de grupo menor"],"explanation":"La fórmula de puentes aumenta el peso bruto permisible del grupo a medida que crece la distancia L entre los ejes extremos, distribuyendo la carga sobre una mayor parte de la estructura del puente, hasta el tope de 80,000 libras para la combinación. Fuente: A.R.S. 28-1100 (fórmula de puentes)."},"8":{"q":"Un autobús interurbano (over-the-road bus) en Arizona tiene permitida una excepción al límite de eje sencillo. ¿Cuál es el peso máximo por eje sencillo permitido para tal autobús?","options":["20,000 libras","22,000 libras","24,000 libras","26,000 libras"],"explanation":"Aunque el límite general de eje sencillo es de 20,000 libras, un autobús interurbano puede excederlo pero no debe superar las 24,000 libras en ningún eje sencillo. Fuente: A.R.S. 28-1099 (límite de carga por eje sencillo; excepciones)."},"9":{"q":"¿Cuál es la longitud máxima de un vehículo sencillo (no combinado), incluida su carga, en las carreteras de Arizona sin un permiso?","options":["35 pies","40 pies","45 pies","53 pies"],"explanation":"Un vehículo sencillo, incluida cualquier carga, no puede exceder los 40 pies de dimensión total extrema (con excepciones específicas para autobuses). Fuente: A.R.S. 28-1095 (longitud del vehículo)."},"10":{"q":"En las carreteras de Arizona, ¿cuál es la longitud máxima de un semirremolque operado en una combinación de tractocamión/semirremolque?","options":["48 pies","53 pies","57 pies 6 pulgadas","65 pies"],"explanation":"Arizona permite un semirremolque de hasta 57 pies 6 pulgadas en una combinación de tractocamión/semirremolque, sin límite de longitud total de la combinación en el sistema interestatal y la red designada más allá de la longitud del remolque. Fuente: A.R.S. 28-1095 (longitud del vehículo)."},"11":{"q":"En una combinación de remolque doble (semirremolque-remolque) en las carreteras de Arizona, ¿cuál es la longitud máxima de cada unidad remolcada?","options":["27 pies","28 pies 6 pulgadas","33 pies","40 pies"],"explanation":"Arizona limita cada unidad en una combinación de semirremolque-remolque (doble/dobles) a 28 pies 6 pulgadas. Fuente: A.R.S. 28-1095 (longitud del vehículo; definiciones)."},"12":{"q":"En las carreteras de Arizona que NO forman parte de la red interestatal/nacional designada, ¿cuál es la longitud total máxima típica de un camión-remolque o combinación como un equipo de 53 pies?","options":["56 pies","60 pies","65 pies","70 pies"],"explanation":"En las carreteras de Arizona no designadas (generales), el límite de longitud total de la combinación es de 65 pies, mientras que la red interestatal/nacional designada se rige en cambio por la longitud del remolque en lugar de la longitud total. Fuente: A.R.S. 28-1095 (longitud del vehículo)."},"13":{"q":"¿Cuándo se requiere un permiso especial de sobredimensión/sobrepeso del Departamento de Transporte de Arizona para un vehículo comercial?","options":["Solo cuando el vehículo cruza una línea estatal","Siempre que el vehículo o la carga exceda un límite legal de tamaño o peso y la carga no sea reducible","Solo cuando la carga es material peligroso","Cada vez que el vehículo pese más de 26,001 libras de GVWR"],"explanation":"Se requiere un permiso especial de sobredimensión/sobrepeso de ADOT cuando un vehículo o carga excede los límites legales de dimensión o peso, y los permisos de sobrepeso/sobredimensión se emiten únicamente para cargas no reducibles. Fuente: ADOT Commercial Vehicle Permits (sobredimensión/sobrepeso); A.R.S. 28-1100 a 28-1145."},"14":{"q":"¿A través de qué sistema de ADOT se puede obtener un permiso de viaje único de sobredimensión/sobrepeso en Arizona?","options":["El portal en línea de permisos de vehículos comerciales del estado","Solo enviando por correo un formulario en papel a la oficina del Gobernador","Solo en persona en un tribunal de la ciudad","A través de la oficina del sheriff del condado"],"explanation":"ADOT emite permisos de sobredimensión/sobrepeso a través de su portal en línea de permisos de vehículos comerciales, así como mediante servicios de permisos autorizados, por correo y en persona en los Puertos de Entrada o en la Oficina Central de Permisos. Fuente: ADOT Commercial Vehicle Permits (sobredimensión/sobrepeso)."},"15":{"q":"Para un permiso rutinario de sobredimensión/sobrepeso de ADOT (Clase A), ¿cuál es el peso total máximo del vehículo y la carga que el permiso puede autorizar?","options":["129,000 libras","164,000 libras","250,000 libras","500,000 libras"],"explanation":"El permiso de sobredimensión/sobrepeso Clase A de ADOT cubre cargas de hasta 14 pies de ancho, 16 pies de alto, 120 pies de largo y un peso combinado de vehículo/carga de 250,000 libras; los traslados más pesados o grandes requieren revisión adicional. Fuente: ADOT Commercial Vehicle Permits (sobredimensión/sobrepeso)."},"16":{"q":"¿Cuál de las siguientes duraciones de permiso ofrece ADOT para traslados de sobredimensión/sobrepeso?","options":["Permisos de viaje único, de 30 días y anuales","Solo permisos por hora y semanales","Solo un único permiso vitalicio","Solo permisos mensuales por condado"],"explanation":"ADOT ofrece permisos de sobredimensión/sobrepeso en duraciones de viaje único, de 30 días y anuales, con tarifas escaladas según el tipo de permiso. Fuente: ADOT Commercial Vehicle Permits (sobredimensión/sobrepeso)."},"17":{"q":"Arizona permite una concesión de peso bruto por encima de los límites normales para un vehículo de servicio pesado equipado con tecnología de reducción de ralentí (por ejemplo, una unidad de potencia auxiliar). ¿Cuál es esa concesión de peso adicional máxima?","options":["400 libras","550 libras","1,000 libras","2,000 libras"],"explanation":"Arizona permite hasta 550 libras (o el peso real de la tecnología de reducción de ralentí, lo que sea menor) por encima de los límites de peso para tener en cuenta una unidad de potencia auxiliar. Fuente: A.R.S. 28-1100 (restricciones de peso bruto; excepciones)."},"18":{"q":"Arizona otorga una concesión de peso bruto para vehículos impulsados principalmente por gas natural, batería eléctrica o hidrógeno. ¿Hasta qué peso bruto total puede operar tal vehículo bajo esa concesión?","options":["80,000 libras","82,000 libras","85,000 libras","88,000 libras"],"explanation":"Arizona permite que un vehículo alimentado principalmente por gas natural, batería eléctrica o hidrógeno exceda los límites estándar por el peso del sistema de combustible alternativo, pero el peso bruto no puede exceder las 82,000 libras. Fuente: A.R.S. 28-1100 (restricciones de peso bruto; excepciones)."},"19":{"q":"Dos conjuntos consecutivos de ejes tándem en Arizona pueden cargar cada uno hasta 34,000 libras cuando están separados 36 pies o más, sujeto a ¿qué límite general sobre la combinación?","options":["El peso bruto de la combinación no puede exceder las 80,000 libras","El peso bruto de la combinación no puede exceder las 68,000 libras","No hay límite general una vez que los tándem están separados 36 pies","El peso bruto de la combinación no puede exceder las 100,000 libras"],"explanation":"Arizona permite que dos conjuntos consecutivos de ejes tándem carguen cada uno 34,000 libras cuando están separados 36 pies o más, siempre que el peso bruto total de la combinación aún no exceda las 80,000 libras. Fuente: A.R.S. 28-1100 (restricciones de peso bruto)."},"20":{"q":"En Arizona, ¿qué clase de CDL se requiere para conducir un vehículo sencillo con una clasificación de peso bruto vehicular (GVWR) de 26,001 libras o más que NO esté remolcando nada de más de 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Arizona requiere una CDL Clase B para cualquier vehículo sencillo con un GVWR de 26,001 libras o más. La Clase A cubre vehículos combinados con un GCWR de 26,001 libras o más donde el GVWR de la unidad remolcada excede las 10,000 libras. Fuente: Arizona Commercial Driver License Manual (ADOT MVD), Sección 1."},"21":{"q":"Según las normas de Arizona, se requiere una CDL Clase A para un vehículo combinado con una clasificación de peso bruto combinado (GCWR) de 26,001 libras o más, siempre que el GVWR de la(s) unidad(es) que se remolca(n) exceda qué peso?","options":["6,000 libras","10,000 libras","15,000 libras","26,001 libras"],"explanation":"Arizona requiere una CDL Clase A para un vehículo combinado con un GCWR de 26,001 libras o más cuando el GVWR de la(s) unidad(es) remolcada(s) excede las 10,000 libras. Fuente: Arizona CDL Manual (ADOT MVD), Sección 1 (clases de CDL)."},"22":{"q":"¿Qué clase de CDL de Arizona aplica a un vehículo con un GVWR de 26,000 libras o menos que está diseñado para transportar 16 o más pasajeros (incluido el conductor) o que transporta materiales peligrosos con letrero (placarded)?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"La CDL Clase C de Arizona cubre vehículos que no cumplen los umbrales de peso de Clase A o B que están diseñados para transportar 16 o más pasajeros (incluido el conductor) o que transportan materiales peligrosos con letrero (placarded). Fuente: Arizona CDL Manual (ADOT MVD), Sección 1."},"23":{"q":"¿Para transportar al menos cuántas personas (incluido el conductor) debe estar diseñado un vehículo antes de que caiga bajo el umbral de pasajeros que activa el requisito de CDL en Arizona?","options":["9 pasajeros","12 pasajeros","15 pasajeros","16 pasajeros"],"explanation":"Arizona requiere una CDL para operar un vehículo diseñado para transportar 16 o más pasajeros, incluido el conductor. Fuente: Arizona CDL Manual (ADOT MVD), lista \"You must have a CDL to operate\"."},"24":{"q":"¿Cuál es la edad mínima general para obtener una Licencia de Conducir Comercial de Arizona completa (interestatal)?","options":["16","18","21","25"],"explanation":"La edad mínima para una CDL de Arizona es 21. Los solicitantes que tengan al menos 18 años pueden solicitar una CDL solo intraestatal, válida únicamente dentro de Arizona. Fuente: Arizona CDL Manual / Customer Service Guide for Commercial Drivers (ADOT MVD), Introducción."},"25":{"q":"Un residente de Arizona de 18 años quiere una CDL pero aún no tiene 21. ¿Qué puede solicitar esa persona?","options":["Una CDL interestatal completa con todos los endosos","Una CDL intraestatal válida solo dentro de Arizona","Una exención federal para conducir a través de líneas estatales","Nada; la edad mínima para la CDL es 21 sin excepciones"],"explanation":"En Arizona, un solicitante que tenga al menos 18 años pero menos de 21 puede solicitar una licencia de conducir comercial intraestatal que es válida solo dentro de Arizona. Fuente: Arizona CDL Manual / Customer Service Guide (ADOT MVD), Introducción."},"26":{"q":"En Arizona, a los conductores menores de 21 años se les prohíbe específicamente hacer qué con un vehículo comercial?","options":["Transportar cantidades de materiales peligrosos que requieran letrero (placarded)","Conducir cualquier vehículo de más de 10,000 libras","Operar un vehículo con frenos de aire","Remolcar cualquier remolque"],"explanation":"A los conductores de Arizona menores de 21 años se les prohíbe transportar cantidades de materiales peligrosos que requieran letrero (placarded). Pueden tener una CDL/CLP intraestatal pero no pueden transportar materiales peligrosos con letrero. Fuente: Arizona CDL Manual / Customer Service Guide (ADOT MVD)."},"27":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Arizona?","options":["Por un máximo de 12 meses","Por 30 días","Por 6 meses","Por 4 años"],"explanation":"El Permiso de Aprendiz Comercial de Arizona es válido por un período de 12 meses. Fuente: Arizona CDL Manual / Customer Service Guide (ADOT MVD), \"Commercial Learner Permit (CLP)\"."},"28":{"q":"Después de que se emite inicialmente un CLP en Arizona, ¿cuánto tiempo debe esperar el titular antes de ser elegible para tomar el examen de habilidades (de manejo) de la CDL?","options":["Al menos 14 días","Al menos 24 horas","Al menos 30 días","Al menos 60 días"],"explanation":"Un titular de CLP no es elegible para tomar el examen de habilidades de la CDL dentro de los 14 días posteriores a la emisión inicial del permiso, en consonancia con el período de espera federal de 14 días. Fuente: Arizona CDL Manual / Customer Service Guide (ADOT MVD), \"Skills (Driving) Test\"; 49 CFR 383.25."},"29":{"q":"¿Qué endoso NO puede colocarse en un Permiso de Aprendiz Comercial (CLP) de Arizona?","options":["Pasajeros (P)","Autobús Escolar (S)","Materiales Peligrosos (H)","Tanque (N)"],"explanation":"Un endoso de Materiales Peligrosos (H) no puede colocarse en un CLP. El solicitante recibe el CLP sin el HME, completa la Evaluación de Amenazas a la Seguridad (Security Threat Assessment) de la TSA y obtiene el HME solo después de que se apruebe la evaluación. Fuente: Arizona CDL Manual / Customer Service Guide (ADOT MVD)."},"30":{"q":"Para conducir legalmente un autobús escolar en Arizona, un titular de CDL debe portar qué combinación de endosos?","options":["Solo el endoso P","Solo el endoso S","Tanto el endoso P (Pasajeros) como el S (Autobús Escolar)","Los endosos H y S"],"explanation":"Los conductores de autobús escolar de Arizona deben tener AMBOS endosos, el \"P\" (Pasajeros) y el \"S\" (Autobús Escolar), para operar un autobús escolar. Fuente: Arizona CDL Manual / Customer Service Guide (ADOT MVD), sección de endosos."},"31":{"q":"Antes de que el MVD de Arizona emita el endoso de Materiales Peligrosos, el solicitante debe aprobar qué evaluación federal de antecedentes?","options":["Una Evaluación de Amenazas a la Seguridad (Security Threat Assessment) de la TSA","Una apelación de antecedentes penales del FBI","Una autorización de sustancias controladas de la DEA","Una auditoría de residencia de ICE"],"explanation":"El endoso de Materiales Peligrosos requiere que el solicitante apruebe una Evaluación de Amenazas a la Seguridad (Security Threat Assessment) de la Administración de Seguridad en el Transporte (TSA), que incluye una verificación de antecedentes y toma de huellas dactilares. Fuente: Arizona CDL Manual (ADOT MVD); 49 CFR 1572."},"32":{"q":"Una vez completada, ¿por cuánto tiempo es válida la Evaluación de Amenazas a la Seguridad (STA) de la TSA de un endoso HazMat de Arizona antes de que deba renovarse?","options":["1 año","3 años","5 años","8 años"],"explanation":"Una Evaluación de Amenazas a la Seguridad (STA) tiene una validez de 5 años a partir de la fecha de finalización; el MVD notifica al titular 60 días antes de que expire la STA. Fuente: Arizona CDL Manual / Customer Service Guide (ADOT MVD)."},"33":{"q":"El endoso de Vehículo Cisterna (N) de Arizona se requiere para transportar líquidos o gases en un tanque con una capacidad nominal individual de más de 119 galones y una capacidad nominal agregada de al menos cuántos galones?","options":["500 galones","750 galones","1,000 galones","2,000 galones"],"explanation":"Se requiere un endoso de Cisterna para tanques con una capacidad nominal individual de más de 119 galones y una capacidad nominal agregada de 1,000 galones o más. Fuente: Arizona CDL Manual (ADOT MVD), Sección 1; 49 CFR 383.5."},"34":{"q":"¿Qué endoso necesita un conductor de Arizona para arrastrar remolques dobles o triples?","options":["N (Cisterna)","T (Dobles/Triples)","H (Materiales Peligrosos)","P (Pasajeros)"],"explanation":"El endoso de Dobles/Triples (T) se requiere para arrastrar remolques dobles o triples y requiere aprobar el examen de conocimientos de dobles/triples. Fuente: Arizona CDL Manual (ADOT MVD), lista de endosos de la Sección 1."},"35":{"q":"¿Qué puntaje mínimo debe lograr un solicitante en cada examen de conocimientos de la CDL de Arizona para aprobar?","options":["70 por ciento","75 por ciento","80 por ciento","90 por ciento"],"explanation":"Los solicitantes deben responder correctamente al menos el 80 por ciento de las preguntas en cada examen de conocimientos para lograr un puntaje aprobatorio, y deben esperar hasta el siguiente día hábil para volver a tomar cualquier examen reprobado. Fuente: Arizona CDL Manual / Customer Service Guide (ADOT MVD), \"Additional Testing Information\"."},"36":{"q":"La Capacitación para Conductores de Nivel Inicial (ELDT) requerida antes de ciertos exámenes de habilidades o de conocimientos de la CDL de Arizona debe completarse a través de un proveedor que figure en dónde?","options":["El Registro de Proveedores de Capacitación (TPR) de la FMCSA","Solo el directorio de escuelas del MVD de Arizona","Cualquier concesionario de camiones con licencia estatal","El Registro Nacional de Examinadores Médicos Certificados"],"explanation":"Las regulaciones federales de ELDT requieren que los conductores de nivel inicial se capaciten con un proveedor que figure en el Registro de Proveedores de Capacitación de la FMCSA (tpr.fmcsa.dot.gov) antes de tomar ciertos exámenes de habilidades o de conocimientos de la CDL. Fuente: Arizona CDL Manual / Customer Service Guide (ADOT MVD), \"Entry-Level Driver Training (ELDT)\"; 49 CFR Part 380."},"37":{"q":"En la solicitud de CDL de Arizona, un conductor que opera únicamente dentro de Arizona y que debe cumplir con los requisitos médicos del estado se autocertifica bajo qué categoría?","options":["Interestatal No Exento (NI)","Intraestatal No Exento (NA)","Interestatal Exento (EI)","Intraestatal Exento (EA)"],"explanation":"Un conductor que opera completamente dentro de Arizona y que debe cumplir con los requisitos médicos se autocertifica como Intraestatal No Exento (NA); esto coloca una restricción intraestatal en la CDL/CLP. Interestatal No Exento (NI) permite operación a nivel nacional bajo la tarjeta médica federal del DOT. Fuente: Arizona CDL Manual / Customer Service Guide (ADOT MVD), \"Self-Certification\"."},"38":{"q":"Mientras opera un vehículo motorizado comercial (CMV) en Arizona, ¿a partir de qué concentración de alcohol en la sangre (BAC) se considera que un conductor con CDL está conduciendo bajo los efectos del alcohol?","options":["0.02 o más","0.04 o más","0.08 o más","0.10 o más"],"explanation":"Arizona, siguiendo el estándar federal en 49 CFR 383.51 y A.R.S. 28-1381/28-3312, prohíbe operar un CMV con un BAC de 0.04 o más (la mitad del límite de 0.08 para vehículos no comerciales). Fuente: Arizona CDL Manual; A.R.S. 28-3312."},"39":{"q":"En Arizona, ¿cuál es el período mínimo de descalificación para la PRIMERA ofensa mayor de un titular de CDL (como un DUI en un CMV) cuando NO se transportan materiales peligrosos?","options":["60 días","120 días","1 año","3 años"],"explanation":"Una primera ofensa mayor resulta en una descalificación de al menos un año. Fuente: A.R.S. 28-3312; Arizona CDL Manual (refleja 49 CFR 383.51)."},"40":{"q":"Si un titular de CDL comete una primera ofensa mayor en Arizona mientras transporta materiales peligrosos con letrero (placarded), la descalificación mínima aumenta a:","options":["1 año","2 años","3 años","5 años"],"explanation":"Una primera ofensa mayor cometida mientras se transportan materiales peligrosos con letrero (placarded) resulta en una descalificación de tres años en lugar de un año. Fuente: A.R.S. 28-3312; Arizona CDL Manual."},"41":{"q":"Según la ley de Arizona, ¿cuál es la descalificación para una SEGUNDA ofensa mayor cometida por un titular de CDL?","options":["1 año","5 años","10 años","De por vida"],"explanation":"Dos ofensas mayores separadas resultan en una descalificación de por vida, aunque la reincorporación puede ser posible después de 10 años tras un programa de rehabilitación aprobado. Fuente: A.R.S. 28-3312; Arizona CDL Manual."},"42":{"q":"En Arizona, ¿cuántas infracciones de tránsito GRAVES dentro de un período de 3 años activan una descalificación de 60 días de una CDL?","options":["1","2","3","4"],"explanation":"Dos infracciones de tránsito graves dentro de tres años resultan en una descalificación de 60 días. Fuente: A.R.S. 28-3312; Arizona CDL Manual."},"43":{"q":"A un conductor con CDL en Arizona se le condena por TRES infracciones de tránsito graves dentro de un período de 3 años. ¿Cuál es el período de descalificación?","options":["60 días","90 días","120 días","1 año"],"explanation":"Tres infracciones de tránsito graves dentro de tres años resultan en una descalificación de 120 días. Fuente: A.R.S. 28-3312; Arizona CDL Manual."},"44":{"q":"En Arizona, ¿exceder el límite de velocidad indicado por cuánto en una sola infracción cuenta como una \"infracción de tránsito grave\" para un titular de CDL?","options":["10 mph o más por encima","15 mph o más por encima","20 mph o más por encima","25 mph o más por encima"],"explanation":"Según A.R.S. 28-3312(J), el exceso de velocidad de 15 mph o más por encima del límite indicado es una infracción de tránsito grave. Fuente: A.R.S. 28-3312; Arizona CDL Manual."},"45":{"q":"¿Cuál de las siguientes se clasifica como una ofensa MAYOR (no meramente una infracción de tránsito grave) para un titular de CDL de Arizona?","options":["Seguir demasiado de cerca (pegado al de adelante)","Exceder el límite de velocidad por 15 mph","Cambio de carril indebido o errático","Abandonar el lugar de un accidente que involucra un CMV"],"explanation":"Abandonar el lugar de un accidente (darse a la fuga) que involucra un CMV es una ofensa mayor que conlleva una descalificación de 1 año (3 años si hay materiales peligrosos). Las otras tres son infracciones de tránsito graves. Fuente: A.R.S. 28-3312; Arizona CDL Manual."},"46":{"q":"Bajo la ley de consentimiento implícito de Arizona, ¿qué le sucede a un titular de CDL que se niega a una prueba química (de aliento/sangre) legal durante una parada por DUI, en cuanto a su privilegio de conducir comercialmente?","options":["Solo una advertencia en una primera negativa","Una descalificación de la CDL de 30 días","Al menos una descalificación de la CDL de 1 año","Ningún efecto en la CDL si no conduce comercialmente"],"explanation":"Negarse a una prueba química legal se trata como una ofensa mayor: al menos una descalificación de la CDL de un año (tres años si se transportan materiales peligrosos con letrero), además de la suspensión de licencia por consentimiento implícito. Fuente: A.R.S. 28-1321 (consentimiento implícito); A.R.S. 28-3312; Arizona CDL Manual."},"47":{"q":"En Arizona, una ofensa de DUI que descalifica a un titular de CDL puede cometerse en:","options":["Solo un vehículo motorizado comercial","Solo un vehículo que transporta materiales peligrosos","Ya sea un vehículo comercial O uno personal (no comercial)","Solo un vehículo que pese más de 26,001 libras"],"explanation":"Una condena por DUI en CUALQUIER vehículo, comercial o personal, descalifica la CDL. Un conductor puede perder la CDL por un DUI cometido en un automóvil privado. Fuente: A.R.S. 28-3312; Arizona CDL Manual."},"48":{"q":"¿Cuál es el período de descalificación para la PRIMERA violación de una orden de fuera de servicio (OOS) de un titular de CDL en Arizona?","options":["60 días","90 días","180 días","1 año"],"explanation":"Una primera violación de una orden de fuera de servicio resulta en una descalificación de al menos 180 días. Fuente: A.R.S. 28-3312; Arizona CDL Manual (refleja 49 CFR 383.51)."},"49":{"q":"En Arizona, ¿cuál es la descalificación para una SEGUNDA violación de una orden de fuera de servicio dentro de un período de 10 años (sin materiales peligrosos, sin pasajeros)?","options":["180 días","1 año","2 años","5 años"],"explanation":"Una segunda violación de una orden de fuera de servicio dentro de 10 años resulta en una descalificación de al menos 2 años. Fuente: A.R.S. 28-3312; Arizona CDL Manual."},"50":{"q":"Un conductor con CDL en Arizona comete una TERCERA violación de una orden de fuera de servicio dentro de 10 años. La descalificación mínima es:","options":["1 año","2 años","3 años","De por vida"],"explanation":"Una tercera o posterior violación de una orden de fuera de servicio dentro de 10 años resulta en una descalificación de al menos 3 años. Fuente: A.R.S. 28-3312; Arizona CDL Manual."},"51":{"q":"¿Cuál es la descalificación para la PRIMERA violación de un cruce a nivel ferroviario de un titular de CDL en Arizona?","options":["No menos de 60 días","No menos de 90 días","No menos de 120 días","1 año"],"explanation":"Una primera violación de un cruce a nivel ferroviario resulta en una descalificación de no menos de 60 días. Fuente: A.R.S. 28-3312; Arizona CDL Manual."},"52":{"q":"En Arizona, la SEGUNDA violación de un cruce a nivel ferroviario de un conductor con CDL dentro de 3 años resulta en una descalificación de no menos de:","options":["60 días","120 días","180 días","1 año"],"explanation":"Una segunda violación de un cruce a nivel ferroviario dentro de tres años resulta en una descalificación de no menos de 120 días. Fuente: A.R.S. 28-3312; Arizona CDL Manual."},"53":{"q":"Un titular de CDL en Arizona comete una TERCERA violación de un cruce a nivel ferroviario dentro de un período de 3 años. La descalificación es de no menos de:","options":["120 días","180 días","1 año","3 años"],"explanation":"Una tercera o posterior violación de un cruce a nivel ferroviario dentro de tres años resulta en una descalificación de no menos de un año. Fuente: A.R.S. 28-3312; Arizona CDL Manual."},"54":{"q":"Usar un vehículo en la comisión de un delito grave que involucre la fabricación, distribución o dispensación de una sustancia controlada resulta en qué descalificación de la CDL en Arizona?","options":["1 año","3 años","10 años","Una descalificación permanente (de por vida) sin reincorporación"],"explanation":"Usar un vehículo motorizado en un delito grave que involucre la fabricación, distribución o dispensación de una sustancia controlada resulta en una descalificación permanente (de por vida) que NO es elegible para la reincorporación a los 10 años. Fuente: A.R.S. 28-3312; Arizona CDL Manual."},"55":{"q":"Según la regla que aplica a los conductores con CDL de Arizona, enviar o leer un mensaje de texto mientras se conduce un CMV puede someter al CONDUCTOR a una sanción civil de hasta:","options":["$500","$1,000","$2,750","$11,000"],"explanation":"Enviar mensajes de texto mientras se conduce un CMV puede resultar en una sanción civil federal de hasta $2,750 para el conductor (los empleadores enfrentan hasta $11,000 por permitirlo o exigirlo). Una condena por mensajes de texto/teléfono de mano también es una infracción de tránsito grave. Fuente: 49 CFR 392.80/392.82 (FMCSA No-Texting Rule); Arizona CDL Manual."},"56":{"q":"Para un conductor con CDL de Arizona, usar un teléfono móvil DE MANO mientras se conduce un CMV está permitido solo si el conductor:","options":["Mantiene la llamada en menos de un minuto","Está detenido en un semáforo en rojo","Usa una configuración de manos libres y presiona no más de un solo botón mientras está sentado y con el cinturón puesto","Está en un camino privado"],"explanation":"La regla prohíbe sostener el teléfono, alcanzarlo o presionar más de un botón; el uso de manos libres está permitido solo si el conductor puede iniciar/contestar con un solo toque de botón mientras permanece en la posición de conducción sentado y con el cinturón puesto. Las violaciones cuentan como infracciones de tránsito graves. Fuente: 49 CFR 392.82; Arizona CDL Manual."},"57":{"q":"A un titular de CDL se le condena por una ofensa mayor y alcanza una descalificación de por vida. Según las reglas de Arizona/federales, la reincorporación puede ser posible solo después de un mínimo de:","options":["3 años","5 años","10 años y la finalización de un programa de rehabilitación aprobado","Nunca puede reincorporarse"],"explanation":"Una descalificación de por vida por dos ofensas mayores puede reducirse para permitir la reincorporación después de al menos 10 años si el conductor completa un programa de rehabilitación aprobado; las descalificaciones por delito grave de sustancias controladas permanecen permanentes. Fuente: A.R.S. 28-3312; Arizona CDL Manual."},"58":{"q":"En un cruce de ferrocarril con carretera donde no hay una línea blanca de alto pintada en el pavimento, ¿dónde debe detener su vehículo un conductor con CDL de Arizona que está obligado a parar?","options":["A no menos de 5 feet y no más de 25 feet del riel más cercano","A no menos de 15 feet y no más de 50 feet del riel más cercano","A no menos de 20 feet y no más de 75 feet del riel más cercano","A no menos de 10 feet y no más de 100 feet del riel más cercano"],"explanation":"El Manual de CDL de Arizona y la ARS 28-853 exigen que los autobuses, los vehículos que transportan pasajeros por contratación y los vehículos con carga inflamable o que llevan rótulos (placards) se detengan dentro de 50 feet, pero a no menos de 15 feet del riel más cercano cuando no hay línea de alto. Fuente: Manual de CDL de Arizona secc. 2.15; ARS 28-853."},"59":{"q":"Según la ley Move Over de Arizona, cuando un conductor en una carretera de cuatro carriles (dos o más carriles en el mismo sentido) se acerca a un vehículo detenido que muestra luces intermitentes o de advertencia, ¿qué es lo primero que el conductor está obligado a hacer?","options":["Detenerse por completo hasta que el vehículo detenido se retire","Tocar el claxon continuamente mientras pasa junto al vehículo detenido","Orillarse al acotamiento y esperar a que un oficial le indique que puede pasar","Cambiarse a un carril que se aleje del vehículo detenido si es seguro y posible"],"explanation":"La ARS 28-775 exige que los conductores cedan el paso cambiándose a un carril no adyacente cuando sea seguro; solo si un cambio de carril no es seguro el conductor debe reducir a una velocidad segura. Fuente: ARS 28-775; página de la ley Move Over de AZDPS."},"60":{"q":"¿Cuál es el límite máximo de velocidad en Arizona para un vehículo motorizado o combinación con un peso bruto declarado superior a 26,000 pounds (que no sea un autobús de pasajeros), a menos que ADOT haya señalizado un límite mayor?","options":["55 miles per hour","60 miles per hour","75 miles per hour","65 miles per hour"],"explanation":"La ARS 28-709 limita a los vehículos comerciales pesados de más de 26,000 lbs (y a los vehículos que remolcan un pole trailer de 6,000+ lbs) a 65 mph, a menos que ADOT señalice un límite mayor tras un estudio de ingeniería. Fuente: ARS 28-709."},"61":{"q":"Según el Manual de CDL de Arizona, al detenerse sobre o junto a una carretera de un solo sentido o de calzadas divididas, ¿dónde se deben colocar los tres triángulos reflectantes de advertencia hacia el tránsito que se aproxima?","options":["A 10 feet, 50 feet y 150 feet hacia el tránsito que se aproxima","A 25 feet, 75 feet y 125 feet hacia el tránsito que se aproxima","A 10 feet, 100 feet y 200 feet hacia el tránsito que se aproxima","A 15 feet, 100 feet y 300 feet hacia el tránsito que se aproxima"],"explanation":"El Manual de CDL de Arizona indica a los conductores detenidos en una carretera de un solo sentido o de calzadas divididas que coloquen los dispositivos de advertencia a 10, 100 y 200 feet hacia el tránsito que se aproxima, dentro de un plazo de 10 minutos. Fuente: Manual de CDL de Arizona secc. 2.5."},"62":{"q":"En un camino de dos carriles con tránsito en ambos sentidos (carretera no dividida), ¿dónde indica el Manual de CDL de Arizona que se deben colocar los triángulos de advertencia después de detenerse?","options":["A no más de 25 feet del vehículo y a 200 feet adelante y atrás de él","A no más de 50 feet del vehículo y a 150 feet adelante y atrás de él","A no más de 10 feet del vehículo y a 250 feet adelante y atrás de él","A no más de 10 feet del vehículo y a 100 feet adelante y atrás de él"],"explanation":"En un camino de doble sentido no dividido, el Manual de CDL de Arizona exige un triángulo a no más de 10 feet del vehículo, más uno a 100 feet adelante y otro a 100 feet atrás. Fuente: Manual de CDL de Arizona secc. 2.5."},"63":{"q":"Al cruzar vías de ferrocarril en un vehículo comercial en Arizona, ¿qué le prohíben hacer al conductor la ley y el Manual de CDL?","options":["Usar las luces intermitentes de emergencia de cuatro direcciones","Mirar a izquierda y derecha en busca de trenes","Cambiar de velocidad (engranaje) mientras cruza la o las vías","Cruzar cuando las barreras están levantadas"],"explanation":"La ARS 28-853 y el Manual de CDL de Arizona establecen que el conductor no debe cambiar de velocidad mientras cruza las vías, para evitar quedarse atascado sobre el cruce. Fuente: ARS 28-853; Manual de CDL de Arizona secc. 2.15.5."},"64":{"q":"Según las reglas de detención para autobuses escolares de Arizona (ARS 28-857), ¿cuál de los siguientes conductores que se aproxima NO está obligado a detenerse ante un autobús escolar que tiene activadas sus luces rojas intermitentes alternantes?","options":["Un conductor en el carril que está justo al otro lado de un carril central de vuelta respecto al autobús","Un conductor que se aproxima al autobús en un camino de dos carriles no dividido","Un conductor detrás del autobús en el mismo sentido de circulación","Un conductor que circula por una calzada distinta de una carretera con calzadas separadas"],"explanation":"La ARS 28-857 exime a un conductor que circula por una calzada distinta de una carretera con calzadas separadas (una carretera dividida físicamente); las líneas pintadas o un carril central de vuelta de doble sentido NO crean calzadas separadas. Fuente: ARS 28-857."},"65":{"q":"En una carretera de Arizona con un carril central de vuelta de doble sentido pero sin camellón físico, ¿qué debe hacer un conductor que viene en sentido contrario cuando un autobús escolar se detiene con las luces rojas intermitentes?","options":["Continuar sin detenerse, porque el carril de vuelta divide el camino","Reducir a 15 mph pero sin necesidad de detenerse","Detenerse solo si hay niños cruzando visiblemente","Detenerse, porque un carril central de vuelta no es una calzada separada"],"explanation":"La ARS 28-857 especifica que un carril o grupo de carriles a cualquier lado de un carril central de vuelta de doble sentido no es una calzada separada, por lo que el tránsito en sentido contrario debe detenerse. Fuente: ARS 28-857."},"66":{"q":"¿A qué vehículos exige específicamente la ley de Arizona (ARS 28-853) que se detengan en todo cruce a nivel de ferrocarril antes de continuar?","options":["Solo a los vehículos que muestran rótulos (placards) de materiales peligrosos","A todos los vehículos comerciales que pesan más de 10,000 pounds","A autobuses y vehículos de pasajeros por contratación, autobuses escolares y vehículos que transportan explosivos o líquidos inflamables","Solo a los autobuses escolares cuando llevan estudiantes a bordo"],"explanation":"La ARS 28-853 menciona a los vehículos motorizados que transportan pasajeros por contratación, los autobuses escolares que transportan niños y los vehículos que llevan sustancias explosivas o líquidos inflamables como carga. Fuente: ARS 28-853."},"67":{"q":"Según la sección de Autobuses Escolares del CDL de Arizona, ¿cuándo debe un conductor de autobús escolar activar las luces de advertencia (hazard) al acercarse a un cruce de ferrocarril?","options":["Al menos aproximadamente 100 feet antes del cruce","Al menos aproximadamente 300 feet antes del cruce","Solo después de que el autobús se haya detenido por completo","Aproximadamente 50 feet antes del cruce"],"explanation":"La sección de autobuses escolares del Manual de CDL de Arizona indica a los conductores que activen las luces de advertencia al menos aproximadamente 100 feet antes del cruce para señalar sus intenciones. Fuente: Manual de CDL de Arizona secc. 10.4."},"68":{"q":"¿Cuál es la sanción civil por una PRIMERA infracción de la ley Move Over de Arizona (ARS 28-775)?","options":["$150","$275","$500","$1,000"],"explanation":"La ARS 28-775 establece una sanción civil de $275 por una primera infracción, que aumenta a $500 por una segunda y a $1,000 por una tercera dentro de un periodo de cinco años. Fuente: ARS 28-775."},"69":{"q":"En las carreteras de varios carriles de Arizona, ¿qué exige la ARS 28-721 a un conductor que circula a menor velocidad que la velocidad normal del tránsito?","options":["Permanecer en el carril central en todo momento","Circular en el carril de la derecha, excepto al rebasar o al prepararse para dar vuelta a la izquierda","Usar solo el carril izquierdo para que el tránsito más rápido pueda rebasar por la derecha","Mantener al menos 45 mph en cualquier carril"],"explanation":"La ARS 28-721 exige que un vehículo que circula a menor velocidad que el tránsito normal se mantenga en el carril de la derecha, excepto al rebasar/adelantar o al prepararse para una vuelta a la izquierda. Fuente: ARS 28-721."},"70":{"q":"¿Cuál es el ANCHO máximo legal de un vehículo en las carreteras de Arizona antes de que se requiera un permiso de sobredimensión de ADOT?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"El ancho máximo legal de Arizona es de 8 feet 6 inches (102 inches); cualquier vehículo más ancho requiere un permiso de sobredimensión de ADOT. Fuente: regulaciones de permisos de sobredimensión/sobrepeso de ADOT."},"71":{"q":"Sin un permiso de sobredimensión/sobrepeso de Arizona, ¿cuál es el peso bruto vehicular máximo generalmente permitido?","options":["80,000 pounds","100,000 pounds","26,000 pounds","120,000 pounds"],"explanation":"Arizona sigue el límite legal federal de 80,000 lbs de peso bruto; superarlo requiere un permiso de sobrepeso de ADOT. Fuente: permisos de sobredimensión/sobrepeso de ADOT; ARS Título 28."},"72":{"q":"Un camión que va hacia el sur descendiendo la pendiente pronunciada de la I-17 cerca del Verde Valley ve un letrero de 'Runaway Truck Ramp'. ¿Cuál es el propósito de esta medida de seguridad de Arizona?","options":["Proporcionar una salida obligatoria a una estación de pesaje para todos los camiones","Permitir que un vehículo con frenos averiados o sobrecalentados salga de la carretera y se detenga de forma segura","Servir como zona designada para colocar cadenas en invierno","Funcionar como área de descanso para conductores fatigados"],"explanation":"Las rampas para camiones sin control (rampas de escape) de ADOT en pendientes como la I-17 permiten que los camiones fuera de control con falla de frenos salgan y se detengan de forma segura; su necesidad se basa en lo pronunciado de la pendiente, su longitud y la frecuencia de accidentes. Fuente: ADOT (Runaway Truck Ramps)."},"73":{"q":"¿Dentro de cuántos minutos debe un conductor con CDL de Arizona colocar los dispositivos de advertencia de emergencia después de detenerse en un camino o acotamiento?","options":["Dentro de 5 minutos","Dentro de 15 minutos","Dentro de 10 minutos","Dentro de 30 minutos"],"explanation":"El Manual de CDL de Arizona exige que los dispositivos de advertencia de emergencia se coloquen dentro de los 10 minutos posteriores a detenerse en un camino o acotamiento. Fuente: Manual de CDL de Arizona secc. 2.5."},"74":{"q":"Si no se puede realizar un cambio de carril de forma segura al pasar junto a un vehículo detenido con luces intermitentes en Arizona, ¿qué exige la ARS 28-775 que haga el conductor en su lugar?","options":["Mantener el límite de velocidad señalizado pero tocar el claxon","Continuar con la debida precaución y reducir la velocidad a una velocidad segura para las condiciones","Detenerse por completo sobre la carretera hasta que sea seguro cambiarse de carril","Continuar a velocidad normal, ya que cambiarse de carril es imposible"],"explanation":"La ARS 28-775 dispone que, cuando no es posible un cambio de carril seguro, el conductor debe reducir la velocidad y continuar con precaución a una velocidad segura para las condiciones. Fuente: ARS 28-775."},"75":{"q":"El Manual de CDL de Arizona señala que un tractocamión con remolque necesita aproximadamente cuánto tiempo para librar UNA SOLA vía de ferrocarril, lo que subraya por qué debes asegurarte de poder librarla por completo antes de empezar a cruzar.","options":["Al menos unos 14 segundos","Unos 5 segundos","Unos 30 segundos","Unos 8 segundos"],"explanation":"El Manual de CDL de Arizona indica que un tractocamión con remolque típico necesita al menos 14 segundos para librar una sola vía y más de 15 segundos para una vía doble, así que nunca empieces a cruzar a menos que puedas librarla por completo. Fuente: Manual de CDL de Arizona secc. 2.15.5."},"76":{"q":"En una carretera dividida con un camellón físico, ¿cómo debe responder un conductor de Arizona ante un autobús escolar detenido con las luces rojas intermitentes en la calzada OPUESTA, y ante uno detenido en la MISMA calzada?","options":["No se requiere detenerse por el de la calzada opuesta, pero sí se requiere detenerse en la misma calzada","Se requiere detenerse en ambos sentidos sin importar el camellón","No se requiere detenerse en ninguno de los dos sentidos porque la carretera está dividida","Se requiere detenerse únicamente en la calzada opuesta"],"explanation":"Conforme a la ARS 28-857, el tránsito en una calzada físicamente separada (opuesta) no necesita detenerse, pero los vehículos que se encuentran con el autobús o lo siguen en la misma calzada deben detenerse hasta que las luces se apaguen. Fuente: ARS 28-857."},"77":{"q":"Para los infractores, ¿cuál es la sanción civil MÍNIMA en Arizona por una primera infracción de rebasar ilegalmente un autobús escolar detenido que muestra sus luces rojas intermitentes (ARS 28-857)?","options":["$100","$500","$250","$1,000"],"explanation":"La ARS 28-857 establece una sanción civil mínima de $250 por una primera infracción; una segunda dentro de 36 months es de al menos $750 y una tercera de al menos $1,000, ambas con posible suspensión de la licencia. Fuente: ARS 28-857."},"78":{"q":"¿Qué agencia de Arizona emite las Licencias de Conducir Comerciales (CDL)?","options":["La Motor Vehicle Division del Arizona Department of Transportation (ADOT)","El Arizona Department of Public Safety","El Arizona Department of Weights and Measures","La Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"En Arizona, las CDL son emitidas por la Motor Vehicle Division (MVD) del Arizona Department of Transportation (ADOT). La FMCSA establece los estándares federales, pero no emite la licencia en sí. Fuente: ADOT MVD, página Getting Your Commercial Driver License."},"79":{"q":"¿Qué puntaje mínimo debes obtener en cada examen de conocimientos (escrito) del CDL en Arizona para aprobar?","options":["80 percent","70 percent","75 percent","85 percent"],"explanation":"Los exámenes de conocimientos de la MVD de Arizona requieren un puntaje mínimo de 80 percent para aprobar cada examen. Fuente: ADOT MVD, páginas Getting Your Commercial Driver License / Tests and Manuals."},"80":{"q":"Antes de poder presentar el examen de habilidades del CDL en Arizona, ¿por cuánto tiempo debes haber tenido tu Commercial Learner's Permit (CLP)?","options":["Al menos 14 days","Al menos 30 days","Al menos 10 days","Al menos 60 days"],"explanation":"Arizona sigue la regla federal: el titular de un CLP debe esperar al menos 14 days después de la emisión del CLP antes de presentar el examen de habilidades del CDL. Fuente: ADOT MVD, página Getting Your Commercial Driver License (49 CFR 383.25)."},"81":{"q":"¿Cuál es el periodo máximo de vigencia de un Commercial Learner's Permit (CLP) de Arizona?","options":["12 months","6 months","180 days","24 months"],"explanation":"Un CLP de Arizona tiene una vigencia máxima de 12 months. Fuente: ADOT MVD, página Getting Your Commercial Driver License."},"82":{"q":"¿Con qué frecuencia debe renovarse generalmente el DOT Medical Examiner's Certificate de un titular de CDL?","options":["Cada 24 months o antes","Cada 12 months o antes","Cada 36 months o antes","Cada 48 months o antes"],"explanation":"El Medical Examiner's Certificate debe renovarse cada 24 months o antes, según lo determine el examinador médico o conforme a la regulación. Fuente: ADOT MVD, página Medical Certification (CDL)."},"83":{"q":"El examen de habilidades del CDL de Arizona se divide en ¿cuáles tres partes?","options":["Inspección previaje (pre-trip), control básico del vehículo y conducción en carretera","Conocimientos escritos, examen de la vista y conducción en carretera","Inspección previaje (pre-trip), manejo de hazmat y conducción nocturna","Solo reversa, estacionamiento en paralelo e incorporación a autopista"],"explanation":"El examen de habilidades del CDL de Arizona tiene tres componentes: la inspección previaje (pre-trip), los controles básicos del vehículo y el examen de conducción en carretera (road). Fuente: ADOT MVD, página Tests and Manuals; Manual de CDL de Arizona Secciones 11-13."},"84":{"q":"¿Dónde debe estar registrado un examinador médico para que un examen físico de CDL sea aceptado en Arizona?","options":["En el FMCSA National Registry of Certified Medical Examiners","En la lista de médicos aprobados de ADOT","En la lista de especialistas del Arizona Medical Board","En la lista de médicos aprobados por el DMV de cualquier estado"],"explanation":"El examen físico del CDL debe ser realizado por un examinador médico registrado en el FMCSA National Registry of Certified Medical Examiners (conforme a 49 CFR 391.41/391.43). Fuente: ADOT MVD, página Medical Certification (CDL)."},"85":{"q":"Para un titular de CDL estándar (sin restricción intraestatal), ¿cómo se transmite normalmente el Medical Examiner's Certificate a la MVD de Arizona?","options":["El examinador médico certificado lo envía a la MVD de forma electrónica","El conductor envía por correo el certificado en papel a las oficinas centrales de la MVD","El empleador lo envía por fax a la MVD en nombre del conductor","La FMCSA lo reenvía automáticamente sin acción del examinador"],"explanation":"El examinador médico certificado envía el Medical Examiner's Certificate (MEC) a la MVD de forma electrónica; los conductores deben prever 24 horas antes de acudir a una oficina de la MVD. Fuente: ADOT MVD, página Medical Certification (CDL)."},"86":{"q":"¿Cuáles son las cuatro categorías de autocertificación entre las que debe elegir un solicitante de CDL en Arizona?","options":["Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate y Excepted Intrastate","Interstate, Intrastate, Federal y Estatal","Comercial, No Comercial, Hazmat y Tanque (Tanker)","Class A, Class B, Class C y Class D"],"explanation":"La autocertificación del CDL requiere elegir una de cuatro categorías: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate o Excepted Intrastate. Fuente: autocertificación de CDL de ADOT MVD / Formulario 96-0526 (49 CFR 383.71)."},"87":{"q":"¿Cuál categoría de autocertificación exige que el conductor cumpla con los requisitos federales de la tarjeta médica del DOT?","options":["Non-Excepted Interstate","Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"explanation":"Un conductor que se autocertifica como Non-Excepted Interstate opera en el comercio interestatal y debe cumplir con los requisitos federales del certificado médico del DOT. Las categorías Excepted no requieren la tarjeta médica federal. Fuente: autocertificación de ADOT MVD / FMCSA (49 CFR 383.71)."},"88":{"q":"En una CDL de Arizona, ¿qué indica la restricción 'K' acerca del conductor?","options":["El conductor está limitado a la operación intraestatal (solo dentro de Arizona)","El conductor no puede operar vehículos con frenos de aire","El conductor no puede transportar materiales peligrosos","El conductor debe usar lentes correctivos"],"explanation":"Una restricción 'K' significa que el conductor está restringido únicamente al comercio intraestatal (conducir dentro de Arizona). Dichos conductores continúan enviando el MEC en papel y la forma larga (long form) a la MVD. Fuente: ADOT MVD, páginas Medical Certification (CDL) / CDL Restrictions."},"89":{"q":"Para un titular de CDL con la restricción 'K' de solo intraestatal en Arizona, ¿cómo se envía el certificado médico?","options":["Continuando con el envío del MEC en papel y la forma larga (long form) a la MVD para su revisión","De forma electrónica únicamente a través del National Registry","No se requiere para conductores intraestatales","Subiéndolo a través del portal de conductores de la FMCSA"],"explanation":"Los conductores intraestatales (con restricción K) continúan enviando el Medical Examiner's Certificate en papel y la forma larga (long form) a la MVD para su revisión, en lugar de depender del envío electrónico al National Registry. Fuente: ADOT MVD, página Medical Certification (CDL)."},"90":{"q":"¿Qué sucede con una CDL si el titular no mantiene un Medical Examiner's Certificate vigente en los registros de la MVD?","options":["La CDL queda sujeta a suspensión y revocación","Nada, siempre y cuando el conductor se mantenga en el ámbito intraestatal","El conductor recibe una prórroga automática de un año","Solo se elimina el endoso de hazmat"],"explanation":"No mantener un Medical Examiner's Certificate vigente en los registros de la MVD resulta en la suspensión y revocación de los privilegios de la CDL. Fuente: ADOT MVD, página Medical Certification (CDL)."},"91":{"q":"Conforme a las reglas de Entry-Level Driver Training (ELDT), ¿cuándo debe completar el ELDT un solicitante primerizo de Arizona?","options":["Antes de presentar el examen de habilidades del CDL para una CDL inicial de Class A o B","Después de aprobar el examen de habilidades, pero antes de que se imprima la licencia","Solo después de un año de tener una CDL","Solo si el solicitante es menor de 21 años"],"explanation":"El ELDT debe completarse (a través de una escuela registrada en el FMCSA Training Provider Registry) antes de presentar el examen de habilidades para una primera CDL de Class A o B, una actualización de B a A, o un primer endoso S, P o H. Fuente: ADOT MVD; 49 CFR Part 380."},"92":{"q":"¿Cuál de los siguientes es un requisito de documentación al solicitar una CDL en una oficina de la MVD de Arizona?","options":["Prueba de presencia autorizada en los EE. UU., dos pruebas de residencia en Arizona y un número de Seguro Social","Solo una carta notariada de un empleador actual","Un pasaporte del país de nacimiento y nada más","Prueba de haber completado un curso de manejo defensivo"],"explanation":"Los solicitantes deben presentar prueba de que su presencia en los EE. UU. está autorizada conforme a la ley federal, dos pruebas del domicilio de residencia y su número de Seguro Social, además de un Medical Examiner's Certificate válido. Fuente: ADOT MVD, página Getting Your Commercial Driver License."},"93":{"q":"Además de las oficinas de CDL de la MVD, ¿quién más está autorizado a aplicar el examen de conducción/habilidades del CDL en Arizona?","options":["Examinadores externos (third-party) certificados por la MVD en organizaciones públicas y privadas","Cualquier conductor comercial con licencia y cinco años de experiencia","Examinadores del DMV de otros estados que visiten Arizona","Únicamente inspectores federales de la FMCSA"],"explanation":"Además de las oficinas de CDL de la MVD, muchas organizaciones públicas y privadas en Arizona cuentan con examinadores certificados por la MVD autorizados para aplicar el examen de conducción/habilidades. Fuente: ADOT MVD, páginas CDL Examination Program / ubicaciones de examen."},"94":{"q":"¿Una CDL de Arizona es válida por un periodo máximo de cuántos años?","options":["Hasta 8 años","Hasta 4 años","Hasta 5 años","Hasta 10 años"],"explanation":"Las CDL de Arizona son válidas por un periodo de hasta 8 años, y el conductor es responsable de renovarla antes de su vencimiento. Ten en cuenta que un ciclo más corto del certificado médico aún puede provocar una degradación (downgrade). Fuente: ADOT MVD, página Managing Your Commercial Driver License."},"95":{"q":"¿Cuál es la edad mínima para obtener una CDL válida para el comercio interestatal (fuera del estado) en Arizona?","options":["21 años","18 años","19 años","25 años"],"explanation":"Un conductor debe tener al menos 21 años para obtener una CDL para el comercio interestatal. Los solicitantes de 18 a 20 años pueden obtener una CDL restringida a la operación intraestatal (solo dentro de Arizona). Fuente: ADOT MVD, página Getting Your Commercial Driver License (49 CFR 383.3)."},"96":{"q":"Si un conductor se autocertifica como Non-Excepted Intrastate o Excepted Intrastate en Arizona, ¿cuál es la consecuencia?","options":["El conductor no puede operar un vehículo motorizado comercial en el comercio interestatal","El conductor queda exento de todo examen de habilidades","El conductor solo puede manejar autobuses escolares","La CDL del conductor nunca necesita renovación"],"explanation":"Certificarse como Non-Excepted Intrastate o Excepted Intrastate limita al conductor al comercio intraestatal; no puede operar un CMV en el comercio interestatal. Fuente: ADOT MVD, página Managing Your Commercial Driver License (49 CFR 383.71)."},"97":{"q":"¿Cuál afirmación describe mejor el proceso y la estructura de tarifas de Arizona para los exámenes de CDL?","options":["Los exámenes de conocimientos y habilidades se aplican a través de la MVD o de examinadores certificados, y las tarifas exactas son establecidas por ADOT y pueden cambiar con el tiempo","Todos los exámenes de CDL son gratuitos en Arizona en todo momento","Las tarifas las fija de forma permanente la ley federal y nunca cambian","Solo el gobierno federal cobra todas las tarifas relacionadas con el CDL"],"explanation":"Los exámenes de conocimientos y habilidades del CDL de Arizona se aplican a través de las oficinas de la MVD y de examinadores externos (third-party) certificados por la MVD; las tarifas aplicables son establecidas por ADOT y están sujetas a cambios, por lo que los solicitantes deben verificar los montos vigentes con la MVD. Fuente: ADOT MVD, páginas CDL Examination Program / tabla de tarifas."}},"hi":{"0":{"q":"Interstate प्रणाली सहित Arizona के अधिकांश राजमार्गों पर, सुरक्षा उपकरणों को छोड़कर, किसी वाणिज्यिक वाहन या उसके लदान की अधिकतम कानूनी चौड़ाई क्या है?","options":["8 feet 0 inches (96 inches)","8 feet 6 inches (102 inches)","9 feet 0 inches (108 inches)","10 feet 0 inches (120 inches)"],"explanation":"Arizona Interstate प्रणाली, federal-aid तथा निर्दिष्ट राज्य राजमार्गों और उचित-पहुँच मार्गों पर कुल बाहरी चौड़ाई को 102 inches (8 feet 6 inches) तक सीमित करता है; इससे अधिक चौड़े लदान के लिए oversize परमिट आवश्यक है। स्रोत: A.R.S. 28-1093 (वाहन चौड़ाई)।"},"1":{"q":"किसी विशेष परमिट के बिना, Arizona में सड़क की सतह से ऊपर वाहन की, उसके लदान सहित, अधिकतम कानूनी ऊँचाई क्या है?","options":["12 feet 6 inches","13 feet 0 inches","13 feet 6 inches","14 feet 0 inches"],"explanation":"कोई वाहन, चाहे लदा हो या बिना लदा, परमिट के बिना जिस सतह पर खड़ा है उससे ऊपर ऊँचाई में 13 feet 6 inches से अधिक नहीं हो सकता। स्रोत: A.R.S. 28-1094 (वाहन ऊँचाई)।"},"2":{"q":"प्रवर्तन सहनशीलता सहित, Arizona राजमार्गों पर किसी एकल धुरी (single axle) पर अनुमत अधिकतम सकल वजन क्या है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"Arizona किसी भी एकल धुरी को, प्रवर्तन सहनशीलता सहित, 20,000 pounds तक सीमित करता है, जो संघीय मानक के अनुरूप है। स्रोत: A.R.S. 28-1100 और 28-1099 (एकल धुरी भार सीमा)।"},"3":{"q":"प्रवर्तन सहनशीलता सहित, Arizona राजमार्गों पर किसी युग्म धुरी (tandem axle) पर अनुमत अधिकतम सकल वजन क्या है?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Arizona किसी युग्म धुरी को, प्रवर्तन सहनशीलता सहित, 34,000 pounds तक सीमित करता है, जो संघीय मानक के अनुरूप है। स्रोत: A.R.S. 28-1100 (सकल वजन प्रतिबंध)।"},"4":{"q":"overweight परमिट के बिना, Arizona राजमार्गों पर पाँच या अधिक धुरियों वाले वाहन संयोजन के लिए अधिकतम सकल वजन क्या है?","options":["73,280 pounds","76,000 pounds","80,000 pounds","84,000 pounds"],"explanation":"Arizona पाँच या अधिक धुरियों वाले वाहन संयोजन के लिए अधिकतम कानूनी सकल वजन 80,000 pounds निर्धारित करता है, जो संघीय अधिकतम के समान है। स्रोत: A.R.S. 28-1100 (सकल वजन प्रतिबंध)।"},"5":{"q":"धुरी भार सीमाओं के प्रयोजनों के लिए Arizona क़ानून 'tandem axle' को कैसे परिभाषित करता है?","options":["दो क्रमागत धुरियाँ जो 40 inches से अधिक दूर न हों","दो या अधिक क्रमागत धुरियाँ जो 40 inches से अधिक परंतु 96 inches से अधिक दूर न हों","कोई भी दो धुरियाँ जो 96 inches से अधिक दूरी पर हों","दो क्रमागत धुरियाँ जो ठीक 8 feet की दूरी पर हों"],"explanation":"Arizona युग्म धुरियों को दो या अधिक क्रमागत धुरियों के रूप में परिभाषित करता है जिनके केंद्र 40 inches से अधिक परंतु 96 inches से अधिक दूर न हों। स्रोत: A.R.S. 28-1100 (परिभाषाएँ)।"},"6":{"q":"Arizona धुरियों के समूह पर सकल वजन सीमित करने के लिए संघीय bridge formula W = 500(LN/(N-1) + 12N + 36) का उपयोग करता है। उस सूत्र में 'L' क्या दर्शाता है?","options":["अग्रणी धुरी की कानूनी भार रेटिंग","समूह की चरम धुरियों के बीच feet में दूरी","वाहन की कुल लंबाई feet में","निलंबन की उठाने की क्षमता tons में"],"explanation":"Arizona द्वारा अपनाए गए bridge formula में, W समूह पर अधिकतम सकल वजन है, L समूह की बाहरी (चरम) धुरियों के बीच feet में दूरी है, और N समूह में धुरियों की संख्या है। स्रोत: A.R.S. 28-1100 (सकल वजन प्रतिबंध)।"},"7":{"q":"Arizona के bridge formula के अंतर्गत, किसी समूह की चरम धुरियों के बीच की दूरी (L) बढ़ाने से सामान्यतः क्या अनुमत होता है?","options":["समूह पर कम अनुमेय सकल वजन","समूह पर अधिक अनुमेय सकल वजन","कोई परिवर्तन नहीं, क्योंकि केवल धुरियों की संख्या मायने रखती है","अधिक एकल-धुरी सीमा परंतु कम समूह वजन"],"explanation":"bridge formula समूह की अनुमेय सकल वजन सीमा को तब बढ़ाता है जब चरम धुरियों के बीच की दूरी L बढ़ती है, जिससे भार पुल संरचना के अधिक हिस्से पर फैलता है, 80,000-pound संयोजन सीमा तक। स्रोत: A.R.S. 28-1100 (bridge formula)।"},"8":{"q":"Arizona में एक over-the-road बस को एकल-धुरी सीमा में अपवाद की अनुमति है। ऐसी बस के लिए अधिकतम एकल-धुरी वजन कितना अनुमत है?","options":["20,000 pounds","22,000 pounds","24,000 pounds","26,000 pounds"],"explanation":"जबकि सामान्य एकल-धुरी सीमा 20,000 pounds है, एक over-the-road बस इससे अधिक हो सकती है परंतु किसी भी एकल धुरी पर 24,000 pounds से अधिक नहीं होनी चाहिए। स्रोत: A.R.S. 28-1099 (एकल धुरी भार सीमा; अपवाद)।"},"9":{"q":"परमिट के बिना Arizona राजमार्गों पर किसी एकल (गैर-संयोजन) वाहन की, उसके लदान सहित, अधिकतम लंबाई क्या है?","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"एक एकल वाहन, किसी भी लदान सहित, चरम कुल आयाम में 40 feet से अधिक नहीं हो सकता (बसों के लिए विशिष्ट अपवादों के साथ)। स्रोत: A.R.S. 28-1095 (वाहन लंबाई)।"},"10":{"q":"Arizona राजमार्गों पर, truck-tractor/semitrailer संयोजन में संचालित किसी semitrailer की अधिकतम लंबाई क्या है?","options":["48 feet","53 feet","57 feet 6 inches","65 feet"],"explanation":"Arizona truck-tractor/semitrailer संयोजन में 57 feet 6 inches तक के semitrailer की अनुमति देता है, और Interstate तथा निर्दिष्ट नेटवर्क पर ट्रेलर लंबाई के अलावा कोई समग्र संयोजन लंबाई सीमा नहीं है। स्रोत: A.R.S. 28-1095 (वाहन लंबाई)।"},"11":{"q":"Arizona राजमार्गों पर एक twin-trailer (semitrailer-trailer) संयोजन में, प्रत्येक पीछे चलने वाली इकाई की अधिकतम लंबाई क्या है?","options":["27 feet","28 feet 6 inches","33 feet","40 feet"],"explanation":"Arizona एक semitrailer-trailer (twin/double) संयोजन में प्रत्येक इकाई को 28 feet 6 inches तक सीमित करता है। स्रोत: A.R.S. 28-1095 (वाहन लंबाई; परिभाषाएँ)।"},"12":{"q":"Arizona के उन राजमार्गों पर जो निर्दिष्ट Interstate/राष्ट्रीय नेटवर्क का हिस्सा नहीं हैं, किसी truck-trailer या 53-foot rig जैसे संयोजन की सामान्य अधिकतम समग्र लंबाई क्या है?","options":["56 feet","60 feet","65 feet","70 feet"],"explanation":"गैर-निर्दिष्ट (सामान्य) Arizona राजमार्गों पर संयोजन की समग्र लंबाई सीमा 65 feet है, जबकि निर्दिष्ट Interstate/राष्ट्रीय नेटवर्क इसके बजाय समग्र लंबाई के बजाय ट्रेलर लंबाई द्वारा शासित होता है। स्रोत: A.R.S. 28-1095 (वाहन लंबाई)।"},"13":{"q":"किसी वाणिज्यिक वाहन के लिए Arizona Department of Transportation का oversize/overweight विशेष परमिट कब आवश्यक होता है?","options":["केवल जब वाहन किसी राज्य सीमा को पार करता है","जब भी वाहन या लदान किसी कानूनी आकार या वजन सीमा से अधिक होता है और लदान गैर-घटाने योग्य होता है","केवल जब माल खतरनाक सामग्री हो","जब भी वाहन का वजन 26,001 pounds GVWR से अधिक हो"],"explanation":"ADOT oversize/overweight विशेष परमिट तब आवश्यक होता है जब कोई वाहन या लदान कानूनी आयाम या वजन सीमाओं से अधिक होता है, और overweight/oversize परमिट केवल गैर-घटाने योग्य लदान के लिए जारी किए जाते हैं। स्रोत: ADOT Commercial Vehicle Permits (Oversize/Overweight); A.R.S. 28-1100 से 28-1145।"},"14":{"q":"किस ADOT प्रणाली के माध्यम से Arizona का oversize/overweight एकल-यात्रा परमिट प्राप्त किया जा सकता है?","options":["राज्य का ऑनलाइन वाणिज्यिक वाहन परमिट पोर्टल","केवल Governor's office को कागज़ी फॉर्म डाक से भेजकर","केवल किसी शहर न्यायालय में व्यक्तिगत रूप से","county sheriff's office के माध्यम से"],"explanation":"ADOT अपने ऑनलाइन वाणिज्यिक वाहन परमिट पोर्टल के माध्यम से, साथ ही अधिकृत परमिट सेवाओं, डाक द्वारा, और Ports of Entry या Central Permit Office में व्यक्तिगत रूप से oversize/overweight परमिट जारी करता है। स्रोत: ADOT Commercial Vehicle Permits (Oversize/Overweight)।"},"15":{"q":"एक नियमित ADOT oversize/overweight परमिट (Class A) के लिए, परमिट जिस वाहन और लदान के अधिकतम कुल वजन को अधिकृत कर सकता है, वह क्या है?","options":["129,000 pounds","164,000 pounds","250,000 pounds","500,000 pounds"],"explanation":"ADOT का Class A oversize/overweight परमिट 14 feet चौड़े, 16 feet ऊँचे, 120 feet लंबे, और 250,000 pounds के संयुक्त वाहन/लदान वजन तक के लदान को कवर करता है; इससे भारी या बड़े संचलन के लिए अतिरिक्त समीक्षा आवश्यक होती है। स्रोत: ADOT Commercial Vehicle Permits (Oversize/Overweight)।"},"16":{"q":"निम्नलिखित में से कौन सी परमिट अवधि ADOT द्वारा oversize/overweight संचलन के लिए प्रदान की जाती है?","options":["एकल-यात्रा, 30-day, और वार्षिक परमिट","केवल प्रति घंटा और साप्ताहिक परमिट","केवल एकल आजीवन परमिट","केवल प्रति-county मासिक परमिट"],"explanation":"ADOT oversize/overweight परमिट एकल-यात्रा, 30-day, और वार्षिक अवधियों में प्रदान करता है, जिसमें शुल्क परमिट प्रकार के अनुसार निर्धारित होते हैं। स्रोत: ADOT Commercial Vehicle Permits (Oversize/Overweight)।"},"17":{"q":"Arizona idle reduction technology (जैसे, एक auxiliary power unit) से सुसज्जित heavy-duty वाहन के लिए सामान्य सीमाओं से अधिक सकल वजन भत्ता देता है। वह अधिकतम अतिरिक्त वजन भत्ता क्या है?","options":["400 pounds","550 pounds","1,000 pounds","2,000 pounds"],"explanation":"Arizona किसी auxiliary power unit का हिसाब रखने के लिए वजन सीमाओं से ऊपर 550 pounds तक (या idle reduction technology का वास्तविक वजन, जो भी कम हो) की अनुमति देता है। स्रोत: A.R.S. 28-1100 (सकल वजन प्रतिबंध; अपवाद)।"},"18":{"q":"Arizona मुख्य रूप से प्राकृतिक गैस, इलेक्ट्रिक बैटरी, या हाइड्रोजन से चलने वाले वाहनों के लिए सकल वजन भत्ता देता है। उस भत्ते के अंतर्गत ऐसा वाहन कितने कुल सकल वजन तक संचालित हो सकता है?","options":["80,000 pounds","82,000 pounds","85,000 pounds","88,000 pounds"],"explanation":"Arizona मुख्य रूप से प्राकृतिक गैस, बैटरी-इलेक्ट्रिक, या हाइड्रोजन से चलने वाले वाहन को वैकल्पिक-ईंधन प्रणाली के वजन से मानक सीमाओं से अधिक होने की अनुमति देता है, परंतु सकल वजन 82,000 pounds से अधिक नहीं हो सकता। स्रोत: A.R.S. 28-1100 (सकल वजन प्रतिबंध; अपवाद)।"},"19":{"q":"Arizona में दो क्रमागत युग्म धुरी सेट जब 36 feet या अधिक दूरी पर हों तो प्रत्येक 34,000 pounds तक वहन कर सकते हैं, जो संयोजन पर किस समग्र सीमा के अधीन है?","options":["संयोजन का सकल वजन 80,000 pounds से अधिक नहीं हो सकता","संयोजन का सकल वजन 68,000 pounds से अधिक नहीं हो सकता","एक बार युग्म धुरियाँ 36 feet दूर होने पर कोई समग्र सीमा नहीं है","संयोजन का सकल वजन 100,000 pounds से अधिक नहीं हो सकता"],"explanation":"Arizona दो क्रमागत युग्म-धुरी सेटों को प्रत्येक 34,000 pounds वहन करने की अनुमति देता है जब वे 36 feet या अधिक दूरी पर हों, बशर्ते समग्र संयोजन का सकल वजन फिर भी 80,000 pounds से अधिक न हो। स्रोत: A.R.S. 28-1100 (सकल वजन प्रतिबंध)।"},"20":{"q":"Arizona में, 26,001 pounds या अधिक के gross vehicle weight rating (GVWR) वाले एकल वाहन को चलाने के लिए, जो 10,000 pounds से अधिक कुछ भी नहीं खींच रहा हो, कौन सा CDL वर्ग आवश्यक है?","options":["Class A","Class B","Class C","Class D"],"explanation":"Arizona 26,001 pounds या अधिक GVWR वाले किसी भी एकल वाहन के लिए Class B CDL की आवश्यकता रखता है। Class A उन संयोजन वाहनों को कवर करता है जिनका GCWR 26,001+ pounds है और जहाँ खींची गई इकाई का GVWR 10,000 pounds से अधिक है। स्रोत: Arizona Commercial Driver License Manual (ADOT MVD), Section 1।"},"21":{"q":"Arizona नियमों के अंतर्गत, 26,001 pounds या अधिक के gross combination weight rating (GCWR) वाले संयोजन वाहन के लिए Class A CDL आवश्यक है, बशर्ते खींची जा रही इकाई(यों) का GVWR किस वजन से अधिक हो?","options":["6,000 pounds","10,000 pounds","15,000 pounds","26,001 pounds"],"explanation":"Arizona 26,001+ pounds के GCWR वाले संयोजन वाहन के लिए Class A CDL की आवश्यकता तब रखता है जब खींची गई इकाई(यों) का GVWR 10,000 pounds से अधिक हो। स्रोत: Arizona CDL Manual (ADOT MVD), Section 1 (CDL वर्ग)।"},"22":{"q":"26,000 pounds या उससे कम GVWR वाले वाहन पर, जो 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किया गया है या जो placarded खतरनाक सामग्री ले जाता है, कौन सा Arizona CDL वर्ग लागू होता है?","options":["Class A","Class B","Class C","Class M"],"explanation":"Arizona का Class C CDL उन वाहनों को कवर करता है जो Class A या B वजन सीमा को पूरा नहीं करते और जो 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किए गए हैं या जो placarded खतरनाक सामग्री का परिवहन करते हैं। स्रोत: Arizona CDL Manual (ADOT MVD), Section 1।"},"23":{"q":"Arizona में CDL आवश्यकता को सक्रिय करने वाली यात्री सीमा के अंतर्गत आने से पहले, किसी वाहन को कम से कम कितने लोगों (चालक सहित) को ले जाने के लिए डिज़ाइन किया जाना चाहिए?","options":["9 passengers","12 passengers","15 passengers","16 passengers"],"explanation":"Arizona 16 या अधिक यात्रियों, चालक सहित, को ले जाने के लिए डिज़ाइन किए गए वाहन को संचालित करने के लिए CDL की आवश्यकता रखता है। स्रोत: Arizona CDL Manual (ADOT MVD), 'You must have a CDL to operate' सूची।"},"24":{"q":"एक पूर्ण (interstate) Arizona Commercial Driver License प्राप्त करने के लिए सामान्य न्यूनतम आयु क्या है?","options":["16","18","21","25"],"explanation":"Arizona CDL के लिए न्यूनतम आयु 21 है। जो आवेदक कम से कम 18 वर्ष के हैं वे केवल Arizona के भीतर मान्य intrastate-only CDL के लिए आवेदन कर सकते हैं। स्रोत: Arizona CDL Manual / Customer Service Guide for Commercial Drivers (ADOT MVD), परिचय।"},"25":{"q":"एक 18 वर्षीय Arizona निवासी CDL चाहता है परंतु अभी 21 वर्ष का नहीं है। वह व्यक्ति किसके लिए आवेदन कर सकता है?","options":["सभी endorsement के साथ पूर्ण interstate CDL","केवल Arizona के भीतर मान्य intrastate CDL","राज्य सीमाओं के पार चलने के लिए संघीय छूट","कुछ नहीं; न्यूनतम CDL आयु 21 है जिसमें कोई अपवाद नहीं"],"explanation":"Arizona में, जो आवेदक कम से कम 18 परंतु 21 से कम है, वह intrastate commercial driver license के लिए आवेदन कर सकता है जो केवल Arizona के भीतर मान्य है। स्रोत: Arizona CDL Manual / Customer Service Guide (ADOT MVD), परिचय।"},"26":{"q":"Arizona में, 21 वर्ष से कम आयु के चालकों को वाणिज्यिक वाहन के साथ विशेष रूप से क्या करने से प्रतिबंधित किया गया है?","options":["placarded मात्रा में खतरनाक सामग्री का परिवहन करना","10,000 pounds से अधिक का कोई भी वाहन चलाना","air brakes वाले वाहन का संचालन करना","किसी भी ट्रेलर को खींचना"],"explanation":"Arizona में 21 वर्ष से कम आयु के चालकों को placarded मात्रा में खतरनाक सामग्री का परिवहन करने से प्रतिबंधित किया गया है। वे intrastate CDL/CLP रख सकते हैं परंतु placarded hazmat नहीं ढो सकते। स्रोत: Arizona CDL Manual / Customer Service Guide (ADOT MVD)।"},"27":{"q":"एक Arizona Commercial Learner Permit (CLP) कितने समय तक मान्य रहता है?","options":["अधिकतम 12 months के लिए","30 days के लिए","6 months के लिए","4 years के लिए"],"explanation":"Arizona Commercial Learner Permit 12-month अवधि के लिए मान्य होता है। स्रोत: Arizona CDL Manual / Customer Service Guide (ADOT MVD), 'Commercial Learner Permit (CLP)'।"},"28":{"q":"Arizona में CLP प्रारंभ में जारी होने के बाद, CDL skills (driving) test देने के योग्य होने से पहले धारक को कितनी प्रतीक्षा करनी चाहिए?","options":["कम से कम 14 days","कम से कम 24 hours","कम से कम 30 days","कम से कम 60 days"],"explanation":"एक CLP धारक परमिट प्रारंभ में जारी होने के 14 days के भीतर CDL skills test देने के योग्य नहीं होता, जो संघीय 14-day होल्ड के अनुरूप है। स्रोत: Arizona CDL Manual / Customer Service Guide (ADOT MVD), 'Skills (Driving) Test'; 49 CFR 383.25।"},"29":{"q":"कौन सा endorsement Arizona Commercial Learner Permit (CLP) पर नहीं रखा जा सकता?","options":["Passenger (P)","School Bus (S)","Hazardous Materials (H)","Tank (N)"],"explanation":"Hazardous Materials (H) endorsement को CLP पर नहीं रखा जा सकता। आवेदक को HME के बिना CLP प्राप्त होता है, TSA Security Threat Assessment पूरा करता है, और मूल्यांकन अनुमोदित होने के बाद ही HME प्राप्त करता है। स्रोत: Arizona CDL Manual / Customer Service Guide (ADOT MVD)।"},"30":{"q":"Arizona में कानूनी रूप से school bus चलाने के लिए, एक CDL धारक के पास endorsement का कौन सा संयोजन होना चाहिए?","options":["केवल P endorsement","केवल S endorsement","दोनों P (Passenger) और S (School Bus) endorsement","H और S endorsement"],"explanation":"Arizona school bus चालकों के पास school bus संचालित करने के लिए दोनों 'P' (Passenger) और 'S' (School Bus) endorsement होने चाहिए। स्रोत: Arizona CDL Manual / Customer Service Guide (ADOT MVD), endorsement अनुभाग।"},"31":{"q":"Arizona MVD द्वारा Hazardous Materials endorsement जारी करने से पहले, आवेदक को कौन सी संघीय पृष्ठभूमि जाँच पास करनी होगी?","options":["एक TSA Security Threat Assessment","एक FBI आपराधिक रिकॉर्ड अपील","एक DEA नियंत्रित-पदार्थ मंजूरी","एक ICE निवास ऑडिट"],"explanation":"Hazardous Materials endorsement के लिए आवेदक को Transportation Security Administration (TSA) Security Threat Assessment पास करना आवश्यक है, जिसमें पृष्ठभूमि जाँच और फिंगरप्रिंटिंग शामिल है। स्रोत: Arizona CDL Manual (ADOT MVD); 49 CFR 1572।"},"32":{"q":"एक बार पूरा होने के बाद, Arizona HazMat endorsement का TSA Security Threat Assessment (STA) नवीनीकरण से पहले कितने समय तक मान्य रहता है?","options":["1 year","3 years","5 years","8 years"],"explanation":"एक Security Threat Assessment (STA) पूरा होने की तारीख से 5 years तक अच्छा रहता है; MVD STA समाप्त होने से 60 days पहले धारक को सूचित करता है। स्रोत: Arizona CDL Manual / Customer Service Guide (ADOT MVD)।"},"33":{"q":"Arizona Tank Vehicle (N) endorsement किसी टैंक में तरल या गैसों को ढोने के लिए आवश्यक है जिसकी व्यक्तिगत रेटेड क्षमता 119 gallons से अधिक हो और समग्र रेटेड क्षमता कम से कम कितने gallons हो?","options":["500 gallons","750 gallons","1,000 gallons","2,000 gallons"],"explanation":"Tank endorsement उन टैंकों के लिए आवश्यक है जिनकी व्यक्तिगत रेटेड क्षमता 119 gallons से अधिक हो और समग्र रेटेड क्षमता 1,000 gallons या अधिक हो। स्रोत: Arizona CDL Manual (ADOT MVD), Section 1; 49 CFR 383.5।"},"34":{"q":"double या triple ट्रेलर खींचने के लिए एक Arizona चालक को किस endorsement की आवश्यकता होती है?","options":["N (Tank)","T (Doubles/Triples)","H (Hazardous Materials)","P (Passenger)"],"explanation":"Doubles/Triples (T) endorsement double या triple ट्रेलर खींचने के लिए आवश्यक है और इसके लिए doubles/triples ज्ञान परीक्षण पास करना आवश्यक है। स्रोत: Arizona CDL Manual (ADOT MVD), Section 1 endorsement सूची।"},"35":{"q":"पास होने के लिए किसी आवेदक को प्रत्येक Arizona CDL ज्ञान परीक्षण पर कौन सा न्यूनतम स्कोर प्राप्त करना चाहिए?","options":["70 percent","75 percent","80 percent","90 percent"],"explanation":"आवेदकों को पास स्कोर प्राप्त करने के लिए प्रत्येक ज्ञान परीक्षण पर कम से कम 80 percent प्रश्नों का सही उत्तर देना चाहिए, और किसी भी असफल परीक्षण को दोबारा देने के लिए अगले कार्य दिवस तक प्रतीक्षा करनी चाहिए। स्रोत: Arizona CDL Manual / Customer Service Guide (ADOT MVD), 'Additional Testing Information'।"},"36":{"q":"कुछ Arizona CDL skills या ज्ञान परीक्षणों से पहले आवश्यक Entry-Level Driver Training (ELDT) किस प्रदाता के माध्यम से पूरा किया जाना चाहिए?","options":["FMCSA Training Provider Registry (TPR)","केवल Arizona MVD स्कूल निर्देशिका","कोई भी राज्य-लाइसेंस प्राप्त ट्रक डीलरशिप","National Registry of Certified Medical Examiners"],"explanation":"संघीय ELDT विनियम entry-level चालकों को कुछ CDL skills या ज्ञान परीक्षण देने से पहले FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) पर सूचीबद्ध प्रदाता के साथ प्रशिक्षण लेने की आवश्यकता रखते हैं। स्रोत: Arizona CDL Manual / Customer Service Guide (ADOT MVD), 'Entry-Level Driver Training (ELDT)'; 49 CFR Part 380।"},"37":{"q":"Arizona CDL आवेदन पर, एक चालक जो केवल Arizona के भीतर संचालन करता है और राज्य की चिकित्सा आवश्यकताओं को पूरा करना चाहिए, किस श्रेणी के अंतर्गत स्व-प्रमाणन करता है?","options":["Non-excepted Interstate (NI)","Non-excepted Intrastate (NA)","Excepted Interstate (EI)","Excepted Intrastate (EA)"],"explanation":"पूरी तरह से Arizona के भीतर संचालन करने वाला एक चालक जिसे चिकित्सा आवश्यकताओं को पूरा करना चाहिए, Non-excepted Intrastate (NA) के रूप में स्व-प्रमाणन करता है; यह CDL/CLP पर एक intrastate प्रतिबंध लगाता है। Non-excepted Interstate (NI) संघीय DOT चिकित्सा कार्ड के तहत देशव्यापी संचालन की अनुमति देता है। स्रोत: Arizona CDL Manual / Customer Service Guide (ADOT MVD), 'Self-Certification'।"},"38":{"q":"Arizona में एक commercial motor vehicle (CMV) का संचालन करते समय, किसी CDL चालक को किस blood alcohol concentration (BAC) पर नशे में गाड़ी चलाने वाला माना जाता है?","options":["0.02 या अधिक","0.04 या अधिक","0.08 या अधिक","0.10 या अधिक"],"explanation":"Arizona, 49 CFR 383.51 के संघीय मानक और A.R.S. 28-1381/28-3312 का पालन करते हुए, 0.04 या अधिक के BAC के साथ CMV संचालित करने पर प्रतिबंध लगाता है (गैर-वाणिज्यिक वाहनों के लिए 0.08 सीमा का आधा)। स्रोत: Arizona CDL Manual; A.R.S. 28-3312।"},"39":{"q":"Arizona में, खतरनाक सामग्री का परिवहन न करते समय किसी CDL धारक के पहले प्रमुख अपराध (जैसे CMV में DUI) के लिए न्यूनतम अयोग्यता अवधि क्या है?","options":["60 days","120 days","1 year","3 years"],"explanation":"पहला प्रमुख अपराध कम से कम एक वर्ष की अयोग्यता में परिणत होता है। स्रोत: A.R.S. 28-3312; Arizona CDL Manual (49 CFR 383.51 को प्रतिबिंबित करता है)।"},"40":{"q":"यदि कोई CDL धारक Arizona में placarded खतरनाक सामग्री का परिवहन करते समय पहला प्रमुख अपराध करता है, तो न्यूनतम अयोग्यता बढ़कर हो जाती है:","options":["1 year","2 years","3 years","5 years"],"explanation":"placarded खतरनाक सामग्री का परिवहन करते समय किया गया पहला प्रमुख अपराध एक वर्ष के बजाय तीन वर्ष की अयोग्यता में परिणत होता है। स्रोत: A.R.S. 28-3312; Arizona CDL Manual।"},"41":{"q":"Arizona कानून के अंतर्गत, किसी CDL धारक द्वारा किए गए दूसरे प्रमुख अपराध के लिए अयोग्यता क्या है?","options":["1 year","5 years","10 years","आजीवन"],"explanation":"दो अलग-अलग प्रमुख अपराध आजीवन अयोग्यता में परिणत होते हैं, हालाँकि अनुमोदित पुनर्वास कार्यक्रम के बाद 10 years के पश्चात बहाली संभव हो सकती है। स्रोत: A.R.S. 28-3312; Arizona CDL Manual।"},"42":{"q":"Arizona में, 3-year अवधि के भीतर कितने गंभीर यातायात उल्लंघन किसी CDL की 60-day अयोग्यता को सक्रिय करते हैं?","options":["1","2","3","4"],"explanation":"तीन वर्ष के भीतर दो गंभीर यातायात उल्लंघन 60-day अयोग्यता में परिणत होते हैं। स्रोत: A.R.S. 28-3312; Arizona CDL Manual।"},"43":{"q":"Arizona में एक CDL चालक 3-year अवधि के भीतर तीन गंभीर यातायात उल्लंघनों के लिए दोषी ठहराया जाता है। अयोग्यता अवधि क्या है?","options":["60 days","90 days","120 days","1 year"],"explanation":"तीन वर्ष के भीतर तीन गंभीर यातायात उल्लंघन 120-day अयोग्यता में परिणत होते हैं। स्रोत: A.R.S. 28-3312; Arizona CDL Manual।"},"44":{"q":"Arizona में, एकल अपराध में निर्धारित सीमा से कितना अधिक तेज गति किसी CDL धारक के लिए 'गंभीर यातायात उल्लंघन' के रूप में गिना जाता है?","options":["10 mph या अधिक ऊपर","15 mph या अधिक ऊपर","20 mph या अधिक ऊपर","25 mph या अधिक ऊपर"],"explanation":"A.R.S. 28-3312(J) के अंतर्गत, निर्धारित सीमा से 15 mph या अधिक की अत्यधिक तेज गति एक गंभीर यातायात उल्लंघन है। स्रोत: A.R.S. 28-3312; Arizona CDL Manual।"},"45":{"q":"निम्नलिखित में से कौन सा एक Arizona CDL धारक के लिए प्रमुख अपराध (न कि केवल गंभीर यातायात उल्लंघन) के रूप में वर्गीकृत है?","options":["बहुत पास से चलना (tailgating)","सीमा से 15 mph अधिक तेज गति","अनुचित या अनियमित लेन परिवर्तन","CMV से जुड़ी दुर्घटना के स्थल से भाग जाना"],"explanation":"CMV से जुड़ी दुर्घटना के स्थल से भाग जाना (hit-and-run) एक प्रमुख अपराध है जिसमें 1-year (hazmat होने पर 3-year) अयोग्यता होती है। अन्य तीन गंभीर यातायात उल्लंघन हैं। स्रोत: A.R.S. 28-3312; Arizona CDL Manual।"},"46":{"q":"Arizona के implied consent कानून के अंतर्गत, एक CDL धारक जो DUI रोक के दौरान कानूनी रासायनिक (सांस/रक्त) परीक्षण से इनकार करता है, उसके वाणिज्यिक ड्राइविंग विशेषाधिकार के संबंध में क्या होता है?","options":["पहली बार इनकार पर केवल चेतावनी","30-day CDL अयोग्यता","कम से कम 1-year CDL अयोग्यता","यदि वाणिज्यिक रूप से नहीं चला रहे तो CDL पर कोई प्रभाव नहीं"],"explanation":"कानूनी रासायनिक परीक्षण से इनकार करने को प्रमुख अपराध की तरह माना जाता है: कम से कम एक वर्ष की CDL अयोग्यता (placarded खतरनाक सामग्री का परिवहन करने पर तीन वर्ष), implied-consent लाइसेंस निलंबन के अतिरिक्त। स्रोत: A.R.S. 28-1321 (implied consent); A.R.S. 28-3312; Arizona CDL Manual।"},"47":{"q":"Arizona में, एक DUI अपराध जो किसी CDL धारक को अयोग्य ठहराता है, किसमें किया जा सकता है:","options":["केवल एक commercial motor vehicle में","केवल खतरनाक सामग्री ले जाने वाले वाहन में","किसी commercial या personal (गैर-वाणिज्यिक) वाहन में","केवल 26,001 pounds से अधिक वजन वाले वाहन में"],"explanation":"किसी भी वाहन में, वाणिज्यिक या व्यक्तिगत, DUI दोषसिद्धि CDL को अयोग्य ठहराती है। एक चालक निजी कार में किए गए DUI के लिए CDL खो सकता है। स्रोत: A.R.S. 28-3312; Arizona CDL Manual।"},"48":{"q":"Arizona में किसी CDL धारक के out-of-service (OOS) आदेश के पहले उल्लंघन के लिए अयोग्यता अवधि क्या है?","options":["60 days","90 days","180 days","1 year"],"explanation":"पहला out-of-service आदेश उल्लंघन कम से कम 180 days की अयोग्यता में परिणत होता है। स्रोत: A.R.S. 28-3312; Arizona CDL Manual (49 CFR 383.51 को प्रतिबिंबित करता है)।"},"49":{"q":"Arizona में, 10-year अवधि के भीतर दूसरे out-of-service आदेश उल्लंघन (गैर-hazmat, गैर-passenger) के लिए अयोग्यता क्या है?","options":["180 days","1 year","2 years","5 years"],"explanation":"10 years के भीतर दूसरा out-of-service आदेश उल्लंघन कम से कम 2 years की अयोग्यता में परिणत होता है। स्रोत: A.R.S. 28-3312; Arizona CDL Manual।"},"50":{"q":"Arizona में एक CDL चालक 10 years के भीतर तीसरा out-of-service आदेश उल्लंघन करता है। न्यूनतम अयोग्यता है:","options":["1 year","2 years","3 years","आजीवन"],"explanation":"10 years के भीतर तीसरा या बाद का out-of-service आदेश उल्लंघन कम से कम 3 years की अयोग्यता में परिणत होता है। स्रोत: A.R.S. 28-3312; Arizona CDL Manual।"},"51":{"q":"Arizona में किसी CDL धारक के पहले railroad grade-crossing उल्लंघन के लिए अयोग्यता क्या है?","options":["60 days से कम नहीं","90 days से कम नहीं","120 days से कम नहीं","1 year"],"explanation":"पहला railroad grade-crossing उल्लंघन 60 days से कम नहीं की अयोग्यता में परिणत होता है। स्रोत: A.R.S. 28-3312; Arizona CDL Manual।"},"52":{"q":"Arizona में, किसी CDL चालक का 3 years के भीतर दूसरा railroad grade-crossing उल्लंघन कितने से कम नहीं की अयोग्यता में परिणत होता है:","options":["60 days","120 days","180 days","1 year"],"explanation":"तीन वर्ष के भीतर दूसरा railroad grade-crossing उल्लंघन 120 days से कम नहीं की अयोग्यता में परिणत होता है। स्रोत: A.R.S. 28-3312; Arizona CDL Manual।"},"53":{"q":"Arizona में एक CDL धारक 3-year अवधि के भीतर तीसरा railroad grade-crossing उल्लंघन करता है। अयोग्यता कितने से कम नहीं है:","options":["120 days","180 days","1 year","3 years"],"explanation":"तीन वर्ष के भीतर तीसरा या बाद का railroad grade-crossing उल्लंघन एक वर्ष से कम नहीं की अयोग्यता में परिणत होता है। स्रोत: A.R.S. 28-3312; Arizona CDL Manual।"},"54":{"q":"किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से जुड़े अपराध (felony) में वाहन का उपयोग करना Arizona में किस CDL अयोग्यता में परिणत होता है?","options":["1 year","3 years","10 years","बिना बहाली के स्थायी (आजीवन) अयोग्यता"],"explanation":"किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से जुड़े felony में मोटर वाहन का उपयोग करना स्थायी (आजीवन) अयोग्यता में परिणत होता है जो 10-year बहाली के लिए पात्र नहीं है। स्रोत: A.R.S. 28-3312; Arizona CDL Manual।"},"55":{"q":"Arizona CDL चालकों पर लागू होने वाले नियम के अंतर्गत, CMV चलाते समय कोई टेक्स्ट संदेश भेजना या पढ़ना चालक को कितने तक के नागरिक दंड के अधीन कर सकता है:","options":["$500","$1,000","$2,750","$11,000"],"explanation":"CMV चलाते समय टेक्स्टिंग चालक के लिए $2,750 तक के संघीय नागरिक दंड में परिणत हो सकती है (नियोक्ताओं को इसकी अनुमति देने या आवश्यक करने पर $11,000 तक का सामना करना पड़ता है)। एक टेक्स्टिंग/हैंडहेल्ड-फोन दोषसिद्धि भी एक गंभीर यातायात उल्लंघन है। स्रोत: 49 CFR 392.80/392.82 (FMCSA No-Texting Rule); Arizona CDL Manual।"},"56":{"q":"एक Arizona CDL चालक के लिए, CMV चलाते समय हैंड-हेल्ड मोबाइल फोन का उपयोग केवल तभी अनुमत है जब चालक:","options":["कॉल को एक मिनट से कम रखे","लाल बत्ती पर रुका हो","हैंड्स-फ्री सेटअप का उपयोग करे और बैठे तथा बेल्ट लगाए हुए केवल एक बटन से अधिक न दबाए","एक निजी सड़क पर हो"],"explanation":"नियम फोन को पकड़ने, उसके लिए पहुँचने, या एक से अधिक बटन दबाने पर प्रतिबंध लगाता है; हैंड्स-फ्री उपयोग केवल तभी अनुमत है जब चालक बैठे, बेल्ट लगाए ड्राइविंग स्थिति में रहते हुए एक बटन स्पर्श से कॉल आरंभ/उत्तर दे सके। उल्लंघन गंभीर यातायात उल्लंघनों के रूप में गिने जाते हैं। स्रोत: 49 CFR 392.82; Arizona CDL Manual।"},"57":{"q":"एक CDL धारक प्रमुख अपराध के लिए दोषी ठहराया जाता है और आजीवन अयोग्यता तक पहुँच जाता है। Arizona/संघीय नियमों के अंतर्गत, बहाली केवल कम से कम कितने समय बाद संभव हो सकती है:","options":["3 years","5 years","10 years और एक अनुमोदित पुनर्वास कार्यक्रम पूरा करना","इसे कभी बहाल नहीं किया जा सकता"],"explanation":"दो प्रमुख अपराधों से आजीवन अयोग्यता को कम किया जा सकता है ताकि कम से कम 10 years के बाद बहाली की अनुमति मिल सके यदि चालक एक अनुमोदित पुनर्वास कार्यक्रम पूरा करता है; नियंत्रित-पदार्थ felony अयोग्यताएँ स्थायी रहती हैं। स्रोत: A.R.S. 28-3312; Arizona CDL Manual।"},"58":{"q":"ऐसे रेलरोड-हाईवे क्रॉसिंग पर जहाँ सड़क पर कोई सफेद स्टॉप लाइन पेंट नहीं की गई है, वहाँ जिस एरिज़ोना CDL ड्राइवर को रुकना आवश्यक है, उसे वाहन कहाँ रोकना चाहिए?","options":["निकटतम रेल से 5 फीट से अधिक पास नहीं और 25 फीट से अधिक दूर नहीं","निकटतम रेल से 15 फीट से अधिक पास नहीं और 50 फीट से अधिक दूर नहीं","निकटतम रेल से 20 फीट से अधिक पास नहीं और 75 फीट से अधिक दूर नहीं","निकटतम रेल से 10 फीट से अधिक पास नहीं और 100 फीट से अधिक दूर नहीं"],"explanation":"एरिज़ोना का CDL मैनुअल और ARS 28-853 यह आवश्यक करते हैं कि जब कोई स्टॉप लाइन मौजूद न हो, तो बसें, किराए पर यात्रियों को ले जाने वाले वाहन, और प्लेकार्ड लगे/ज्वलनशील-माल ले जाने वाले वाहन निकटतम रेल से 50 फीट के भीतर लेकिन 15 फीट से कम नहीं की दूरी पर रुकें। स्रोत: Arizona CDL Manual sec. 2.15; ARS 28-853।"},"59":{"q":"एरिज़ोना के Move Over कानून के तहत, जब चार-लेन हाईवे (एक ही दिशा में दो या अधिक लेन) पर कोई ड्राइवर ऐसे खड़े वाहन के पास पहुँचता है जिसकी फ्लैशिंग या चेतावनी लाइटें जल रही हों, तो ड्राइवर को सबसे पहले क्या करना आवश्यक है?","options":["जब तक खड़ा वाहन वहाँ से न चला जाए, तब तक पूरी तरह रुके रहें","खड़े वाहन के पास से गुज़रते समय लगातार हॉर्न बजाएँ","शोल्डर पर खींच लें और किसी अधिकारी के हाथ से इशारा करके आगे जाने देने का इंतज़ार करें","यदि सुरक्षित और संभव हो तो खड़े वाहन से दूर वाली लेन में लेन बदलें"],"explanation":"ARS 28-775 यह आवश्यक करता है कि ड्राइवर, जब सुरक्षित हो, किसी गैर-निकटवर्ती लेन में जाकर रास्ता दें; केवल तभी जब लेन बदलना असुरक्षित हो, ड्राइवर को सुरक्षित गति तक धीमा होना चाहिए। स्रोत: ARS 28-775; AZDPS Move Over Law पेज।"},"60":{"q":"एरिज़ोना में 26,000 पाउंड से अधिक घोषित सकल वज़न वाले मोटर वाहन या संयोजन (यात्री बस को छोड़कर) के लिए अधिकतम गति सीमा क्या है, जब तक कि ADOT ने उससे अधिक सीमा पोस्ट न की हो?","options":["55 मील प्रति घंटा","60 मील प्रति घंटा","75 मील प्रति घंटा","65 मील प्रति घंटा"],"explanation":"ARS 28-709, 26,000 lbs से अधिक के भारी वाणिज्यिक वाहनों (और 6,000+ lbs के पोल ट्रेलर खींचने वाले वाहनों) को 65 mph तक सीमित करता है, जब तक कि ADOT किसी इंजीनियरिंग अध्ययन के बाद उससे अधिक सीमा पोस्ट न करे। स्रोत: ARS 28-709।"},"61":{"q":"एरिज़ोना CDL मैनुअल के अनुसार, जब किसी एक-तरफा या विभाजित हाईवे पर या उसके किनारे रुका जाए, तो आती हुई यातायात की ओर तीन परावर्तक चेतावनी त्रिकोण कहाँ रखे जाने चाहिए?","options":["आती हुई यातायात की ओर 10 फीट, 50 फीट और 150 फीट पर","आती हुई यातायात की ओर 25 फीट, 75 फीट और 125 फीट पर","आती हुई यातायात की ओर 10 फीट, 100 फीट और 200 फीट पर","आती हुई यातायात की ओर 15 फीट, 100 फीट और 300 फीट पर"],"explanation":"एरिज़ोना CDL मैनुअल किसी एक-तरफा या विभाजित हाईवे पर रुके ड्राइवरों को 10 मिनट के भीतर आती हुई यातायात की ओर 10, 100 और 200 फीट पर चेतावनी उपकरण रखने का निर्देश देता है। स्रोत: Arizona CDL Manual sec. 2.5।"},"62":{"q":"दोनों दिशाओं में यातायात ले जाने वाली दो-लेन वाली सड़क (अविभाजित हाईवे) पर, एरिज़ोना CDL मैनुअल रुकने के बाद चेतावनी त्रिकोण कहाँ रखने को कहता है?","options":["वाहन के 25 फीट के भीतर और उसके 200 फीट आगे व पीछे","वाहन के 50 फीट के भीतर और उसके 150 फीट आगे व पीछे","वाहन के 10 फीट के भीतर और उसके 250 फीट आगे व पीछे","वाहन के 10 फीट के भीतर और उसके 100 फीट आगे व पीछे"],"explanation":"किसी अविभाजित दो-तरफा सड़क पर, एरिज़ोना CDL मैनुअल वाहन के 10 फीट के भीतर एक त्रिकोण, साथ ही एक 100 फीट आगे और एक 100 फीट पीछे रखना आवश्यक करता है। स्रोत: Arizona CDL Manual sec. 2.5।"},"63":{"q":"एरिज़ोना में किसी वाणिज्यिक वाहन में रेलरोड पटरियों को पार करते समय, कानून और CDL मैनुअल ड्राइवर को क्या करने से रोकते हैं?","options":["चार-तरफा आपातकालीन फ्लैशर का उपयोग करना","ट्रेनों के लिए बाएँ और दाएँ देखना","पटरी या पटरियों को पार करते समय गियर बदलना","गेट ऊपर होने पर पार करना"],"explanation":"ARS 28-853 और एरिज़ोना CDL मैनुअल कहते हैं कि क्रॉसिंग पर वाहन के रुक जाने (स्टॉल) से बचने के लिए ड्राइवर पटरियों को पार करते समय गियर नहीं बदलेगा। स्रोत: ARS 28-853; Arizona CDL Manual sec. 2.15.5।"},"64":{"q":"एरिज़ोना के स्कूल-बस रुकने के नियमों (ARS 28-857) के तहत, ऐसी स्कूल बस के लिए जिसकी बारी-बारी से फ्लैश होने वाली लाल लाइटें चालू हैं, निम्न में से किस आती हुई ड्राइवर को रुकना आवश्यक नहीं है?","options":["बस से सेंटर टर्न लेन के ठीक उस पार वाली लेन में मौजूद ड्राइवर","दो-लेन वाली अविभाजित सड़क पर बस की ओर आती हुई ड्राइवर","यात्रा की उसी दिशा में बस के पीछे मौजूद ड्राइवर","अलग-अलग सड़कमार्गों वाले किसी हाईवे के एक भिन्न सड़कमार्ग पर यात्रा करता ड्राइवर"],"explanation":"ARS 28-857 अलग-अलग सड़कमार्गों वाले हाईवे (भौतिक रूप से विभाजित हाईवे) के किसी भिन्न सड़कमार्ग पर मौजूद ड्राइवर को छूट देता है; पेंट की गई लाइनें या दो-तरफा बाएँ-मुड़ने वाली लेन अलग सड़कमार्ग नहीं बनातीं। स्रोत: ARS 28-857।"},"65":{"q":"एरिज़ोना के ऐसे हाईवे पर जिसमें दो-तरफा बाएँ-मुड़ने वाली (सेंटर) लेन है लेकिन कोई भौतिक मीडियन नहीं है, जब कोई स्कूल बस लाल लाइटें फ्लैश करते हुए रुकती है, तो विपरीत दिशा से आते ड्राइवर को क्या करना चाहिए?","options":["बिना रुके आगे बढ़ें, क्योंकि टर्न लेन सड़क को विभाजित करती है","15 mph तक धीमा हों लेकिन रुकने की ज़रूरत नहीं","केवल तभी रुकें जब बच्चे स्पष्ट रूप से पार करते दिखें","रुकें, क्योंकि सेंटर टर्न लेन कोई अलग सड़कमार्ग नहीं है"],"explanation":"ARS 28-857 निर्दिष्ट करता है कि दो-तरफा बाएँ-मुड़ने वाली लेन के दोनों ओर की कोई लेन या लेनों का समूह कोई अलग सड़कमार्ग नहीं है, इसलिए विपरीत दिशा के यातायात को रुकना ही होगा। स्रोत: ARS 28-857।"},"66":{"q":"एरिज़ोना कानून (ARS 28-853) विशेष रूप से किन वाहनों को आगे बढ़ने से पहले हर रेलरोड ग्रेड क्रॉसिंग पर रुकना आवश्यक करता है?","options":["केवल खतरनाक-सामग्री प्लेकार्ड प्रदर्शित करने वाले वाहन","10,000 पाउंड से अधिक वज़न वाले सभी वाणिज्यिक वाहन","बसें/किराए पर यात्री ले जाने वाले वाहन, स्कूल बसें, और विस्फोटक या ज्वलनशील तरल पदार्थ ढोने वाले वाहन","केवल स्कूल बसें जब छात्र उनमें सवार हों"],"explanation":"ARS 28-853 किराए पर यात्रियों को ले जाने वाले मोटर वाहनों, बच्चों को ले जाने वाली स्कूल बसों, और कार्गो के रूप में विस्फोटक पदार्थ या ज्वलनशील तरल पदार्थ ले जाने वाले वाहनों का नाम लेता है। स्रोत: ARS 28-853।"},"67":{"q":"एरिज़ोना CDL स्कूल बस अनुभाग के अनुसार, किसी रेलरोड क्रॉसिंग के पास पहुँचते समय स्कूल बस ड्राइवर को हैज़र्ड लाइटें कब चालू करनी चाहिए?","options":["क्रॉसिंग से कम से कम लगभग 100 फीट पहले","क्रॉसिंग से कम से कम लगभग 300 फीट पहले","केवल बस के पूरी तरह रुक जाने के बाद","क्रॉसिंग से लगभग 50 फीट पहले"],"explanation":"एरिज़ोना CDL मैनुअल का स्कूल बस अनुभाग ड्राइवरों को अपने इरादों का संकेत देने के लिए क्रॉसिंग से कम से कम लगभग 100 फीट पहले हैज़र्ड लाइटें चालू करने का निर्देश देता है। स्रोत: Arizona CDL Manual sec. 10.4।"},"68":{"q":"एरिज़ोना के Move Over कानून (ARS 28-775) के पहले उल्लंघन के लिए सिविल जुर्माना कितना है?","options":["$150","$275","$500","$1,000"],"explanation":"ARS 28-775 पहले उल्लंघन के लिए $275 का सिविल जुर्माना निर्धारित करता है, जो पाँच वर्षों के भीतर दूसरे के लिए $500 और तीसरे के लिए $1,000 हो जाता है। स्रोत: ARS 28-775।"},"69":{"q":"एरिज़ोना के बहु-लेन सड़कमार्गों पर, ARS 28-721 सामान्य यातायात गति से धीमे चलने वाले ड्राइवर से क्या आवश्यक करता है?","options":["हर समय सेंटर लेन में रहें","ओवरटेक करते समय या बाएँ मुड़ने की तैयारी के अलावा दाहिनी-ओर वाली लेन में चलें","केवल बाईं लेन का उपयोग करें ताकि तेज़ यातायात दाईं ओर से पार कर सके","किसी भी लेन में कम से कम 45 mph बनाए रखें"],"explanation":"ARS 28-721 आवश्यक करता है कि सामान्य यातायात से धीमे चल रहे वाहन को दाहिनी-ओर वाली लेन में रहना चाहिए, सिवाय तब के जब ओवरटेक/पास कर रहा हो या बाएँ मुड़ने की तैयारी कर रहा हो। स्रोत: ARS 28-721।"},"70":{"q":"ADOT से ओवरसाइज़ परमिट आवश्यक होने से पहले एरिज़ोना हाईवे पर अधिकतम कानूनी वाहन चौड़ाई क्या है?","options":["8 फीट 6 इंच","8 फीट 0 इंच","9 फीट 0 इंच","10 फीट 0 इंच"],"explanation":"एरिज़ोना की कानूनी अधिकतम चौड़ाई 8 फीट 6 इंच (102 inches) है; इससे अधिक चौड़ी किसी भी चीज़ के लिए ADOT ओवरसाइज़ परमिट आवश्यक है। स्रोत: ADOT Oversize/Overweight परमिट नियम।"},"71":{"q":"एरिज़ोना ओवरसाइज़/ओवरवेट परमिट के बिना, सामान्यतः अधिकतम सकल वाहन वज़न कितना अनुमत है?","options":["80,000 पाउंड","100,000 पाउंड","26,000 पाउंड","120,000 पाउंड"],"explanation":"एरिज़ोना 80,000 lbs सकल की संघीय कानूनी सीमा का पालन करता है; इससे अधिक होने पर ADOT ओवरवेट परमिट आवश्यक है। स्रोत: ADOT Oversize/Overweight परमिट; ARS Title 28।"},"72":{"q":"वर्दे वैली के पास I-17 की खड़ी ढलान पर उतरते हुए एक दक्षिण-दिशा वाला ट्रक 'Runaway Truck Ramp' का संकेत देखता है। इस एरिज़ोना सुरक्षा सुविधा का उद्देश्य क्या है?","options":["सभी ट्रकों के लिए एक अनिवार्य वज़न-स्टेशन पुल-ऑफ प्रदान करना","विफल या अधिक गर्म हो चुके ब्रेक वाले वाहन को हाईवे छोड़कर सुरक्षित रूप से रुकने देना","सर्दियों में एक निर्धारित चेन-अप क्षेत्र के रूप में काम करना","थके हुए ड्राइवरों के लिए विश्राम क्षेत्र के रूप में काम करना"],"explanation":"I-17 जैसी ढलानों पर ADOT रनअवे ट्रक (एस्केप) रैंप, ब्रेक विफलता वाले बेकाबू ट्रकों को बाहर निकलकर सुरक्षित रूप से रुकने देते हैं; इनकी आवश्यकता ढलान की तीव्रता, लंबाई और दुर्घटना की आवृत्ति पर आधारित होती है। स्रोत: ADOT (Runaway Truck Ramps)।"},"73":{"q":"किसी सड़क या शोल्डर पर रुकने के बाद एरिज़ोना CDL ड्राइवर को कितने मिनटों के भीतर आपातकालीन चेतावनी उपकरण रखने चाहिए?","options":["5 मिनट के भीतर","15 मिनट के भीतर","10 मिनट के भीतर","30 मिनट के भीतर"],"explanation":"एरिज़ोना CDL मैनुअल आवश्यक करता है कि किसी सड़क या शोल्डर पर रुकने के 10 मिनट के भीतर आपातकालीन चेतावनी उपकरण रखे जाएँ। स्रोत: Arizona CDL Manual sec. 2.5।"},"74":{"q":"यदि एरिज़ोना में फ्लैशिंग लाइटों वाले किसी खड़े वाहन के पास से गुज़रते समय लेन बदलना सुरक्षित रूप से नहीं किया जा सकता, तो ARS 28-775 ड्राइवर से इसके बजाय क्या करने को आवश्यक करता है?","options":["पोस्ट की गई गति सीमा बनाए रखें लेकिन हॉर्न बजाएँ","उचित सावधानी के साथ आगे बढ़ें और परिस्थितियों के अनुकूल सुरक्षित गति तक गति कम करें","जब तक हट जाना स्पष्ट न हो जाए, तब तक सड़कमार्ग पर पूरी तरह रुक जाएँ","सामान्य गति से चलते रहें क्योंकि हटना असंभव है"],"explanation":"ARS 28-775 प्रावधान करता है कि जब सुरक्षित लेन बदलना संभव न हो, तो ड्राइवर को धीमा होना चाहिए और परिस्थितियों के अनुकूल सुरक्षित गति पर सावधानी से आगे बढ़ना चाहिए। स्रोत: ARS 28-775।"},"75":{"q":"एरिज़ोना CDL मैनुअल बताता है कि एक ट्रैक्टर-ट्रेलर को एक अकेली (SINGLE) रेलरोड पटरी पार करने में लगभग कितना समय लगता है, जो इस बात को रेखांकित करता है कि पार करना शुरू करने से पहले आपको यह सुनिश्चित कर लेना चाहिए कि आप पूरी तरह पार कर सकते हैं?","options":["कम से कम लगभग 14 सेकंड","लगभग 5 सेकंड","लगभग 30 सेकंड","लगभग 8 सेकंड"],"explanation":"एरिज़ोना CDL मैनुअल कहता है कि एक सामान्य ट्रैक्टर-ट्रेलर को एक अकेली पटरी पार करने में कम से कम 14 सेकंड और दोहरी पटरी के लिए 15 सेकंड से अधिक की ज़रूरत होती है, इसलिए तब तक पार करना शुरू न करें जब तक आप पूरी तरह पार न कर सकें। स्रोत: Arizona CDL Manual sec. 2.15.5।"},"76":{"q":"भौतिक मीडियन वाले किसी विभाजित हाईवे पर, एरिज़ोना ड्राइवर को विपरीत (OPPOSITE) सड़कमार्ग पर लाल लाइटें फ्लैश करती रुकी स्कूल बस के प्रति और उसी (SAME) सड़कमार्ग पर रुकी बस के प्रति कैसे प्रतिक्रिया करनी चाहिए?","options":["विपरीत सड़कमार्ग के लिए रुकना आवश्यक नहीं, लेकिन उसी सड़कमार्ग पर रुकना आवश्यक है","मीडियन की परवाह किए बिना दोनों दिशाओं में रुकना आवश्यक है","किसी भी दिशा में रुकना आवश्यक नहीं क्योंकि हाईवे विभाजित है","रुकना केवल विपरीत सड़कमार्ग पर आवश्यक है"],"explanation":"ARS 28-857 के तहत, भौतिक रूप से अलग (विपरीत) सड़कमार्ग पर यातायात को रुकने की ज़रूरत नहीं, लेकिन उसी सड़कमार्ग पर बस से मिलने वाले या उसके पीछे चल रहे वाहनों को तब तक रुकना चाहिए जब तक लाइटें बंद न हो जाएँ। स्रोत: ARS 28-857।"},"77":{"q":"उल्लंघनकर्ताओं के लिए, अपनी फ्लैशिंग लाल लाइटें प्रदर्शित करती रुकी स्कूल बस को गैरकानूनी रूप से पार करने (ARS 28-857) के पहले अपराध के लिए एरिज़ोना में न्यूनतम (MINIMUM) सिविल जुर्माना कितना है?","options":["$100","$500","$250","$1,000"],"explanation":"ARS 28-857 पहले उल्लंघन के लिए न्यूनतम $250 का सिविल जुर्माना निर्धारित करता है; 36 महीनों के भीतर दूसरा कम से कम $750 और तीसरा कम से कम $1,000 होता है, दोनों में संभावित लाइसेंस निलंबन के साथ। स्रोत: ARS 28-857।"},"78":{"q":"कौन सी एरिज़ोना एजेंसी कमर्शियल ड्राइवर लाइसेंस (CDL) जारी करती है?","options":["एरिज़ोना डिपार्टमेंट ऑफ ट्रांसपोर्टेशन (ADOT) मोटर व्हीकल डिवीज़न","एरिज़ोना डिपार्टमेंट ऑफ पब्लिक सेफ्टी","एरिज़ोना डिपार्टमेंट ऑफ वेट्स एंड मेज़र्स","फेडरल मोटर कैरियर सेफ्टी एडमिनिस्ट्रेशन (FMCSA)"],"explanation":"एरिज़ोना में, CDL एरिज़ोना डिपार्टमेंट ऑफ ट्रांसपोर्टेशन (ADOT) मोटर व्हीकल डिवीज़न (MVD) द्वारा जारी किए जाते हैं। FMCSA संघीय मानक निर्धारित करता है लेकिन वास्तविक लाइसेंस जारी नहीं करता। स्रोत: ADOT MVD, Getting Your Commercial Driver License पेज।"},"79":{"q":"एरिज़ोना में प्रत्येक CDL ज्ञान (लिखित) परीक्षा पास करने के लिए आपको न्यूनतम कितने अंक प्राप्त करने होंगे?","options":["80 प्रतिशत","70 प्रतिशत","75 प्रतिशत","85 प्रतिशत"],"explanation":"एरिज़ोना MVD ज्ञान परीक्षाओं में प्रत्येक परीक्षा पास करने के लिए न्यूनतम 80 प्रतिशत अंक आवश्यक हैं। स्रोत: ADOT MVD, Getting Your Commercial Driver License / Tests and Manuals पेज।"},"80":{"q":"एरिज़ोना में CDL स्किल्स टेस्ट देने से पहले, आपको अपना कमर्शियल लर्नर्स परमिट (CLP) कितने समय तक रखना आवश्यक है?","options":["कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 10 दिन","कम से कम 60 दिन"],"explanation":"एरिज़ोना संघीय नियम का पालन करता है: CLP धारक को CDL स्किल्स टेस्ट देने से पहले CLP जारी होने के बाद कम से कम 14 दिन प्रतीक्षा करनी चाहिए। स्रोत: ADOT MVD, Getting Your Commercial Driver License पेज (49 CFR 383.25)।"},"81":{"q":"एरिज़ोना कमर्शियल लर्नर्स परमिट (CLP) अधिकतम कितनी अवधि के लिए वैध होता है?","options":["12 महीने","6 महीने","180 दिन","24 महीने"],"explanation":"एरिज़ोना CLP अधिकतम 12 महीने के लिए वैध होता है। स्रोत: ADOT MVD, Getting Your Commercial Driver License पेज।"},"82":{"q":"किसी CDL धारक के DOT मेडिकल एग्ज़ामिनर्स सर्टिफिकेट को सामान्यतः कितनी बार नवीनीकृत किया जाना चाहिए?","options":["हर 24 महीने या उससे पहले","हर 12 महीने या उससे पहले","हर 36 महीने या उससे पहले","हर 48 महीने या उससे पहले"],"explanation":"मेडिकल एग्ज़ामिनर्स सर्टिफिकेट को हर 24 महीने या उससे पहले नवीनीकृत किया जाना चाहिए, जैसा कि मेडिकल एग्ज़ामिनर द्वारा या नियमन द्वारा निर्धारित किया जाए। स्रोत: ADOT MVD, Medical Certification (CDL) पेज।"},"83":{"q":"एरिज़ोना CDL स्किल्स टेस्ट किन तीन भागों में विभाजित है?","options":["प्री-ट्रिप निरीक्षण, बुनियादी वाहन नियंत्रण, और ऑन-रोड ड्राइविंग","लिखित ज्ञान, दृष्टि जाँच, और ऑन-रोड ड्राइविंग","प्री-ट्रिप निरीक्षण, हैज़मैट हैंडलिंग, और रात्रि ड्राइविंग","केवल बैकिंग, पैरेलल पार्किंग, और फ्रीवे मर्जिंग"],"explanation":"एरिज़ोना CDL स्किल्स टेस्ट के तीन घटक हैं: प्री-ट्रिप निरीक्षण, बुनियादी वाहन नियंत्रण, और ऑन-रोड (रोड) ड्राइविंग टेस्ट। स्रोत: ADOT MVD, Tests and Manuals पेज; Arizona CDL Manual Sections 11-13।"},"84":{"q":"एरिज़ोना में CDL फिजिकल को स्वीकार किए जाने के लिए किसी मेडिकल एग्ज़ामिनर का नाम कहाँ सूचीबद्ध होना चाहिए?","options":["FMCSA National Registry of Certified Medical Examiners पर","अनुमोदित चिकित्सकों की ADOT सूची पर","Arizona Medical Board की विशेषज्ञ सूची पर","किसी भी राज्य की DMV-अनुमोदित डॉक्टर सूची पर"],"explanation":"CDL फिजिकल किसी ऐसे मेडिकल एग्ज़ामिनर द्वारा किया जाना चाहिए जिसका नाम FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध हो (49 CFR 391.41/391.43 के अनुसार)। स्रोत: ADOT MVD, Medical Certification (CDL) पेज।"},"85":{"q":"किसी मानक (गैर-इंट्रास्टेट-प्रतिबंधित) CDL धारक के लिए, मेडिकल एग्ज़ामिनर्स सर्टिफिकेट सामान्यतः एरिज़ोना MVD को कैसे भेजा जाता है?","options":["प्रमाणित मेडिकल एग्ज़ामिनर इसे MVD को इलेक्ट्रॉनिक रूप से भेजता है","ड्राइवर कागज़ी सर्टिफिकेट को MVD मुख्यालय को डाक से भेजता है","नियोक्ता इसे ड्राइवर की ओर से MVD को फैक्स करता है","FMCSA इसे एग्ज़ामिनर की कार्रवाई के बिना स्वचालित रूप से अग्रेषित करता है"],"explanation":"प्रमाणित मेडिकल एग्ज़ामिनर मेडिकल एग्ज़ामिनर्स सर्टिफिकेट (MEC) को MVD को इलेक्ट्रॉनिक रूप से भेजता है; ड्राइवरों को MVD कार्यालय जाने से पहले 24 घंटे का समय देना चाहिए। स्रोत: ADOT MVD, Medical Certification (CDL) पेज।"},"86":{"q":"एरिज़ोना में किसी CDL आवेदक को जिन चार स्व-प्रमाणन श्रेणियों में से चुनना होता है, वे कौन सी हैं?","options":["Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, और Excepted Intrastate","Interstate, Intrastate, Federal, और State","Commercial, Non-Commercial, Hazmat, और Tanker","Class A, Class B, Class C, और Class D"],"explanation":"CDL स्व-प्रमाणन में चार श्रेणियों में से एक चुनना आवश्यक है: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, या Excepted Intrastate। स्रोत: ADOT MVD CDL स्व-प्रमाणन / Form 96-0526 (49 CFR 383.71)।"},"87":{"q":"किस स्व-प्रमाणन श्रेणी में ड्राइवर को संघीय DOT मेडिकल कार्ड आवश्यकताओं को पूरा करना आवश्यक है?","options":["Non-Excepted Interstate","Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"explanation":"जो ड्राइवर Non-Excepted Interstate के रूप में स्व-प्रमाणन करता है, वह इंटरस्टेट कॉमर्स में संचालन करता है और उसे संघीय DOT मेडिकल सर्टिफिकेट आवश्यकताओं को पूरा करना होगा। Excepted श्रेणियों में संघीय मेडिकल कार्ड आवश्यक नहीं होता। स्रोत: ADOT MVD / FMCSA स्व-प्रमाणन (49 CFR 383.71)।"},"88":{"q":"एरिज़ोना CDL पर, 'K' प्रतिबंध ड्राइवर के बारे में क्या दर्शाता है?","options":["ड्राइवर इंट्रास्टेट (केवल-एरिज़ोना) संचालन तक सीमित है","ड्राइवर एयर ब्रेक वाले वाहन नहीं चला सकता","ड्राइवर खतरनाक सामग्री नहीं ले जा सकता","ड्राइवर को सुधारात्मक लेंस पहनने चाहिए"],"explanation":"'K' प्रतिबंध का अर्थ है कि ड्राइवर केवल इंट्रास्टेट कॉमर्स (एरिज़ोना के भीतर ड्राइविंग) तक सीमित है। ऐसे ड्राइवर कागज़ी MEC और लॉन्ग फॉर्म को MVD को भेजना जारी रखते हैं। स्रोत: ADOT MVD, Medical Certification (CDL) / CDL Restrictions पेज।"},"89":{"q":"एरिज़ोना में केवल-इंट्रास्टेट 'K' प्रतिबंध वाले किसी CDL धारक के लिए, मेडिकल सर्टिफिकेट कैसे जमा किया जाता है?","options":["समीक्षा के लिए कागज़ी MEC और लॉन्ग फॉर्म को MVD को जमा करना जारी रखकर","केवल National Registry के माध्यम से इलेक्ट्रॉनिक रूप से","इंट्रास्टेट ड्राइवरों के लिए यह आवश्यक नहीं है","FMCSA ड्राइवर पोर्टल के माध्यम से अपलोड करके"],"explanation":"इंट्रास्टेट (K-प्रतिबंधित) ड्राइवर इलेक्ट्रॉनिक National Registry सबमिशन पर निर्भर रहने के बजाय, समीक्षा के लिए कागज़ी मेडिकल एग्ज़ामिनर्स सर्टिफिकेट और लॉन्ग फॉर्म को MVD को जमा करना जारी रखते हैं। स्रोत: ADOT MVD, Medical Certification (CDL) पेज।"},"90":{"q":"यदि धारक MVD के पास एक वर्तमान मेडिकल एग्ज़ामिनर्स सर्टिफिकेट फाइल पर रखने में विफल रहता है, तो CDL का क्या होता है?","options":["CDL निलंबन और निरस्तीकरण के अधीन है","कुछ नहीं, जब तक ड्राइवर इंट्रास्टेट रहता है","ड्राइवर को एक वर्ष का स्वचालित विस्तार मिलता है","केवल हैज़मैट एंडोर्समेंट हटा दिया जाता है"],"explanation":"MVD के पास एक वर्तमान मेडिकल एग्ज़ामिनर्स सर्टिफिकेट फाइल पर बनाए रखने में विफलता के परिणामस्वरूप CDL विशेषाधिकारों का निलंबन और निरस्तीकरण होता है। स्रोत: ADOT MVD, Medical Certification (CDL) पेज।"},"91":{"q":"एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT) नियमों के तहत, किसी पहली-बार के एरिज़ोना आवेदक को ELDT कब पूरा करना आवश्यक है?","options":["किसी आरंभिक Class A या B CDL के लिए CDL स्किल्स टेस्ट देने से पहले","स्किल्स टेस्ट पास करने के बाद लेकिन लाइसेंस प्रिंट होने से पहले","केवल एक वर्ष तक CDL रखने के बाद","केवल यदि आवेदक 21 वर्ष से कम आयु का हो"],"explanation":"ELDT को (किसी FMCSA Training Provider Registry-सूचीबद्ध स्कूल के माध्यम से) पहली-बार के Class A या B CDL, B से A में अपग्रेड, या पहली-बार के S, P, या H एंडोर्समेंट के लिए स्किल्स टेस्ट देने से पहले पूरा किया जाना चाहिए। स्रोत: ADOT MVD; 49 CFR Part 380।"},"92":{"q":"एरिज़ोना MVD कार्यालय में CDL के लिए आवेदन करते समय निम्न में से कौन सी एक दस्तावेज़ीकरण आवश्यकता है?","options":["अमेरिका में अधिकृत उपस्थिति का प्रमाण, एरिज़ोना निवास के दो प्रमाण, और एक सोशल सिक्योरिटी नंबर","केवल किसी वर्तमान नियोक्ता का नोटरीकृत पत्र","जन्म के देश का पासपोर्ट और कुछ नहीं","पूर्ण किए गए डिफेंसिव-ड्राइविंग पाठ्यक्रम का प्रमाण"],"explanation":"आवेदकों को यह प्रमाण देना होगा कि अमेरिका में उनकी उपस्थिति संघीय कानून के तहत अधिकृत है, निवास पते के दो प्रमाण, और उनका सोशल सिक्योरिटी नंबर, साथ ही एक वैध मेडिकल एग्ज़ामिनर्स सर्टिफिकेट। स्रोत: ADOT MVD, Getting Your Commercial Driver License पेज।"},"93":{"q":"MVD CDL कार्यालयों के अलावा, एरिज़ोना में CDL रोड/स्किल्स टेस्ट आयोजित करने के लिए और कौन अधिकृत है?","options":["सार्वजनिक और निजी संगठनों में MVD-प्रमाणित थर्ड-पार्टी टेस्टर","पाँच वर्ष के अनुभव वाला कोई भी लाइसेंस प्राप्त वाणिज्यिक ड्राइवर","एरिज़ोना आने वाले राज्य-बाहर के DMV एग्ज़ामिनर","केवल FMCSA संघीय निरीक्षक"],"explanation":"MVD CDL कार्यालयों के अलावा, एरिज़ोना के कई सार्वजनिक और निजी संगठनों के पास MVD-प्रमाणित टेस्टर होते हैं जो रोड/स्किल्स टेस्ट आयोजित करने के लिए अधिकृत होते हैं। स्रोत: ADOT MVD, CDL Examination Program / testing locations पेज।"},"94":{"q":"एरिज़ोना CDL अधिकतम कितने वर्ष की अवधि के लिए वैध होता है?","options":["8 वर्ष तक","4 वर्ष तक","5 वर्ष तक","10 वर्ष तक"],"explanation":"एरिज़ोना CDL 8 वर्ष तक की अवधि के लिए वैध होते हैं, और समाप्ति से पहले नवीनीकरण करना ड्राइवर की ज़िम्मेदारी है। ध्यान दें कि एक छोटा मेडिकल सर्टिफिकेट चक्र फिर भी डाउनग्रेड ट्रिगर कर सकता है। स्रोत: ADOT MVD, Managing Your Commercial Driver License पेज।"},"95":{"q":"एरिज़ोना में इंटरस्टेट (राज्य-बाहर) कॉमर्स के लिए वैध CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["21 वर्ष","18 वर्ष","19 वर्ष","25 वर्ष"],"explanation":"इंटरस्टेट कॉमर्स के लिए CDL प्राप्त करने के लिए ड्राइवर की आयु कम से कम 21 वर्ष होनी चाहिए। 18 से 20 वर्ष के आवेदक इंट्रास्टेट (केवल-एरिज़ोना) संचालन तक सीमित CDL प्राप्त कर सकते हैं। स्रोत: ADOT MVD, Getting Your Commercial Driver License पेज (49 CFR 383.3)।"},"96":{"q":"यदि कोई ड्राइवर एरिज़ोना में Non-Excepted Intrastate या Excepted Intrastate के रूप में स्व-प्रमाणन करता है, तो इसका क्या परिणाम होता है?","options":["ड्राइवर इंटरस्टेट कॉमर्स में कोई कमर्शियल मोटर वाहन नहीं चला सकता","ड्राइवर सभी स्किल्स टेस्टिंग से छूट प्राप्त है","ड्राइवर केवल स्कूल बसें चला सकता है","ड्राइवर के CDL को कभी नवीनीकरण की आवश्यकता नहीं होती"],"explanation":"Non-Excepted Intrastate या Excepted Intrastate के रूप में प्रमाणन ड्राइवर को इंट्रास्टेट कॉमर्स तक सीमित करता है; वे इंटरस्टेट कॉमर्स में कोई CMV नहीं चला सकते। स्रोत: ADOT MVD, Managing Your Commercial Driver License पेज (49 CFR 383.71)।"},"97":{"q":"कौन सा कथन एरिज़ोना की CDL परीक्षण प्रक्रिया और शुल्क संरचना का सबसे अच्छा वर्णन करता है?","options":["ज्ञान और स्किल्स टेस्ट MVD या प्रमाणित टेस्टरों के माध्यम से आयोजित किए जाते हैं, और सटीक शुल्क ADOT द्वारा निर्धारित होते हैं और समय के साथ बदल सकते हैं","एरिज़ोना में सभी CDL परीक्षण हर समय निःशुल्क हैं","शुल्क संघीय कानून द्वारा स्थायी रूप से निर्धारित होते हैं और कभी नहीं बदलते","केवल संघीय सरकार सभी CDL-संबंधी शुल्क एकत्र करती है"],"explanation":"एरिज़ोना CDL ज्ञान और स्किल्स टेस्ट MVD कार्यालयों और MVD-प्रमाणित थर्ड-पार्टी टेस्टरों के माध्यम से आयोजित किए जाते हैं; लागू शुल्क ADOT द्वारा स्थापित किए जाते हैं और परिवर्तन के अधीन हैं, इसलिए आवेदकों को MVD से वर्तमान राशि सत्यापित करनी चाहिए। स्रोत: ADOT MVD, CDL Examination Program / fee schedule पेज।"}},"ar":{"0":{"q":"في معظم الطرق السريعة في ولاية أريزونا، بما في ذلك شبكة الطرق السريعة بين الولايات (Interstate)، ما هو الحد الأقصى القانوني لعرض المركبة التجارية أو حمولتها، باستثناء معدات السلامة؟","options":["8 أقدام و0 بوصة (96 بوصة)","8 أقدام و6 بوصات (102 بوصة)","9 أقدام و0 بوصة (108 بوصات)","10 أقدام و0 بوصة (120 بوصة)"],"explanation":"تحدّ أريزونا إجمالي العرض الخارجي بـ 102 بوصة (8 أقدام و6 بوصات) على شبكة الطرق بين الولايات (Interstate)، والطرق السريعة الممولة اتحاديًا والطرق السريعة المخصصة للولاية، ومسارات الوصول المعقولة؛ وتتطلب الحمولات الأعرض من ذلك تصريح حمولة كبيرة الحجم. المصدر: A.R.S. 28-1093 (عرض المركبة)."},"1":{"q":"بدون تصريح خاص، ما هو الحد الأقصى القانوني لارتفاع المركبة، بما في ذلك حمولتها، فوق سطح الطريق في أريزونا؟","options":["12 قدمًا و6 بوصات","13 قدمًا و0 بوصة","13 قدمًا و6 بوصات","14 قدمًا و0 بوصة"],"explanation":"لا يجوز أن يتجاوز ارتفاع المركبة، محمّلة كانت أم غير محمّلة، 13 قدمًا و6 بوصات فوق السطح الذي تقف عليه بدون تصريح. المصدر: A.R.S. 28-1094 (ارتفاع المركبة)."},"2":{"q":"ما هو الحد الأقصى للوزن الإجمالي المسموح به على محور مفرد على الطرق السريعة في أريزونا، بما في ذلك هوامش الإنفاذ المسموح بها؟","options":["18,000 رطل","20,000 رطل","22,400 رطل","24,000 رطل"],"explanation":"تحدّ أريزونا أي محور مفرد بـ 20,000 رطل، بما في ذلك هوامش الإنفاذ المسموح بها، بما يتوافق مع المعيار الاتحادي. المصدر: A.R.S. 28-1100 و28-1099 (حد حمولة المحور المفرد)."},"3":{"q":"ما هو الحد الأقصى للوزن الإجمالي المسموح به على محور مزدوج (tandem) على الطرق السريعة في أريزونا، بما في ذلك هوامش الإنفاذ المسموح بها؟","options":["32,000 رطل","34,000 رطل","36,000 رطل","40,000 رطل"],"explanation":"تحدّ أريزونا المحور المزدوج (tandem) بـ 34,000 رطل، بما في ذلك هوامش الإنفاذ المسموح بها، بما يتوافق مع المعيار الاتحادي. المصدر: A.R.S. 28-1100 (قيود الوزن الإجمالي)."},"4":{"q":"بدون تصريح حمولة زائدة، ما هو الحد الأقصى للوزن الإجمالي لمركبة مركّبة مكوّنة من خمسة محاور أو أكثر على الطرق السريعة في أريزونا؟","options":["73,280 رطلًا","76,000 رطل","80,000 رطل","84,000 رطل"],"explanation":"تحدد أريزونا الحد الأقصى القانوني للوزن الإجمالي بـ 80,000 رطل لمركبة مركّبة مكوّنة من خمسة محاور أو أكثر، وهو نفس الحد الأقصى الاتحادي. المصدر: A.R.S. 28-1100 (قيود الوزن الإجمالي)."},"5":{"q":"كيف يعرّف قانون أريزونا 'المحور المزدوج (tandem axle)' لأغراض حدود وزن المحاور؟","options":["محوران متتاليان لا تزيد المسافة بينهما عن 40 بوصة","محوران متتاليان أو أكثر تزيد المسافة بينهما عن 40 بوصة ولكن لا تتجاوز 96 بوصة","أي محورين تزيد المسافة بينهما عن 96 بوصة","محوران متتاليان تفصل بينهما مسافة 8 أقدام بالضبط"],"explanation":"تعرّف أريزونا المحاور المزدوجة (tandem) بأنها محوران متتاليان أو أكثر تزيد المسافة بين مركزيهما عن 40 بوصة ولكن لا تتجاوز 96 بوصة. المصدر: A.R.S. 28-1100 (التعريفات)."},"6":{"q":"تستخدم أريزونا معادلة الجسور الاتحادية W = 500(LN/(N-1) + 12N + 36) لتحديد الوزن الإجمالي على مجموعة من المحاور. في تلك المعادلة، ماذا يمثّل الرمز 'L'؟","options":["التصنيف القانوني لحمولة المحور الأمامي","المسافة بالأقدام بين المحورين الطرفيين للمجموعة","الطول الإجمالي للمركبة بالأقدام","قدرة رفع نظام التعليق بالأطنان"],"explanation":"في معادلة الجسور التي اعتمدتها أريزونا، يمثّل W الحد الأقصى للوزن الإجمالي على المجموعة، ويمثّل L المسافة بالأقدام بين المحورين الخارجيين (الطرفيين) للمجموعة، ويمثّل N عدد المحاور في المجموعة. المصدر: A.R.S. 28-1100 (قيود الوزن الإجمالي)."},"7":{"q":"بموجب معادلة الجسور في أريزونا، ماذا يسمح به عمومًا زيادة المسافة (L) بين المحورين الطرفيين للمجموعة؟","options":["وزنًا إجماليًا مسموحًا به أقل على المجموعة","وزنًا إجماليًا مسموحًا به أعلى على المجموعة","لا تغيير، لأن عدد المحاور وحده هو المهم","حدًا أعلى للمحور المفرد ولكن وزنًا أقل للمجموعة"],"explanation":"تزيد معادلة الجسور الوزن الإجمالي المسموح به للمجموعة كلما زادت المسافة L بين المحورين الطرفيين، مما يوزّع الحمولة على جزء أكبر من بنية الجسر، حتى الحد الأقصى للمركبة المركّبة البالغ 80,000 رطل. المصدر: A.R.S. 28-1100 (معادلة الجسور)."},"8":{"q":"يُسمح لحافلة الطرق الطويلة (over-the-road bus) في أريزونا باستثناء من حد المحور المفرد. ما هو الحد الأقصى لوزن المحور المفرد المسموح به لمثل هذه الحافلة؟","options":["20,000 رطل","22,000 رطل","24,000 رطل","26,000 رطل"],"explanation":"في حين أن الحد العام للمحور المفرد هو 20,000 رطل، فإن حافلة الطرق الطويلة (over-the-road bus) قد تتجاوزه ولكن يجب ألا تتجاوز 24,000 رطل على أي محور مفرد. المصدر: A.R.S. 28-1099 (حد حمولة المحور المفرد؛ الاستثناءات)."},"9":{"q":"ما هو الحد الأقصى لطول مركبة مفردة (غير مركّبة)، بما في ذلك حمولتها، على الطرق السريعة في أريزونا بدون تصريح؟","options":["35 قدمًا","40 قدمًا","45 قدمًا","53 قدمًا"],"explanation":"لا يجوز أن تتجاوز المركبة المفردة، بما في ذلك أي حمولة، 40 قدمًا كأقصى بُعد إجمالي (مع استثناءات محددة للحافلات). المصدر: A.R.S. 28-1095 (طول المركبة)."},"10":{"q":"على الطرق السريعة في أريزونا، ما هو الحد الأقصى لطول المقطورة النصفية (semitrailer) المُشغّلة ضمن مجموعة شاحنة-قاطرة/مقطورة نصفية؟","options":["48 قدمًا","53 قدمًا","57 قدمًا و6 بوصات","65 قدمًا"],"explanation":"تسمح أريزونا بمقطورة نصفية (semitrailer) يصل طولها إلى 57 قدمًا و6 بوصات ضمن مجموعة شاحنة-قاطرة/مقطورة نصفية، دون حد إجمالي لطول المركبة المركّبة على شبكة الطرق بين الولايات والشبكة المخصصة بخلاف طول المقطورة. المصدر: A.R.S. 28-1095 (طول المركبة)."},"11":{"q":"في مجموعة مزدوجة المقطورات (مقطورة نصفية-مقطورة) على الطرق السريعة في أريزونا، ما هو الحد الأقصى لطول كل وحدة مقطورة؟","options":["27 قدمًا","28 قدمًا و6 بوصات","33 قدمًا","40 قدمًا"],"explanation":"تحدّ أريزونا كل وحدة في مجموعة مقطورة نصفية-مقطورة (مزدوجة/ثنائية) بـ 28 قدمًا و6 بوصات. المصدر: A.R.S. 28-1095 (طول المركبة؛ التعريفات)."},"12":{"q":"على الطرق السريعة في أريزونا التي لا تُعد جزءًا من شبكة الطرق بين الولايات/الشبكة الوطنية المخصصة، ما هو الحد الأقصى النموذجي للطول الإجمالي لشاحنة-مقطورة أو مجموعة مثل مركبة بطول 53 قدمًا؟","options":["56 قدمًا","60 قدمًا","65 قدمًا","70 قدمًا"],"explanation":"على الطرق السريعة غير المخصصة (العامة) في أريزونا يكون الحد الأقصى للطول الإجمالي للمركبة المركّبة 65 قدمًا، في حين تخضع شبكة الطرق بين الولايات/الشبكة الوطنية المخصصة لطول المقطورة بدلًا من الطول الإجمالي. المصدر: A.R.S. 28-1095 (طول المركبة)."},"13":{"q":"متى يُطلب تصريح خاص للحمولة كبيرة الحجم/زائدة الوزن من إدارة النقل في أريزونا (ADOT) لمركبة تجارية؟","options":["فقط عندما تعبر المركبة حدود الولاية","كلما تجاوزت المركبة أو الحمولة حدًا قانونيًا للحجم أو الوزن وكانت الحمولة غير قابلة للتقليل","فقط عندما تكون الحمولة من المواد الخطرة","في أي وقت يتجاوز فيه وزن المركبة 26,001 رطلًا من حيث وزن المركبة الإجمالي المصنّف (GVWR)"],"explanation":"يُطلب تصريح خاص للحمولة كبيرة الحجم/زائدة الوزن من ADOT عندما تتجاوز المركبة أو الحمولة الحدود القانونية للأبعاد أو الوزن، ولا تُصدر تصاريح الحمولة زائدة الوزن/كبيرة الحجم إلا للحمولات غير القابلة للتقليل. المصدر: ADOT Commercial Vehicle Permits (Oversize/Overweight)؛ A.R.S. 28-1100 إلى 28-1145."},"14":{"q":"من خلال أي نظام تابع لـ ADOT يمكن الحصول على تصريح رحلة مفردة للحمولة كبيرة الحجم/زائدة الوزن في أريزونا؟","options":["بوابة الولاية الإلكترونية لتصاريح المركبات التجارية","فقط عن طريق إرسال نموذج ورقي بالبريد إلى مكتب الحاكم","فقط شخصيًا في محكمة المدينة","من خلال مكتب مأمور المقاطعة (sheriff)"],"explanation":"تُصدر ADOT تصاريح الحمولة كبيرة الحجم/زائدة الوزن من خلال بوابتها الإلكترونية لتصاريح المركبات التجارية، وكذلك عبر خدمات التصاريح المعتمدة، وبالبريد، وشخصيًا في منافذ الدخول (Ports of Entry) أو مكتب التصاريح المركزي. المصدر: ADOT Commercial Vehicle Permits (Oversize/Overweight)."},"15":{"q":"بالنسبة لتصريح ADOT الاعتيادي للحمولة كبيرة الحجم/زائدة الوزن (الفئة A)، ما هو الحد الأقصى للوزن الإجمالي للمركبة والحمولة الذي قد يأذن به التصريح؟","options":["129,000 رطل","164,000 رطل","250,000 رطل","500,000 رطل"],"explanation":"يغطي تصريح الفئة A من ADOT للحمولة كبيرة الحجم/زائدة الوزن الحمولات حتى 14 قدمًا عرضًا، و16 قدمًا ارتفاعًا، و120 قدمًا طولًا، ووزنًا مجمّعًا للمركبة/الحمولة يبلغ 250,000 رطل؛ وتتطلب عمليات النقل الأثقل أو الأكبر مراجعة إضافية. المصدر: ADOT Commercial Vehicle Permits (Oversize/Overweight)."},"16":{"q":"أي من مدد التصاريح التالية تقدّمها ADOT لعمليات النقل كبيرة الحجم/زائدة الوزن؟","options":["تصاريح الرحلة المفردة، ومدة 30 يومًا، والسنوية","تصاريح بالساعة وبالأسبوع فقط","تصريح واحد مدى الحياة فقط","تصاريح شهرية لكل مقاطعة فقط"],"explanation":"تقدّم ADOT تصاريح الحمولة كبيرة الحجم/زائدة الوزن بمدد الرحلة المفردة، و30 يومًا، والسنوية، مع رسوم تتناسب مع نوع التصريح. المصدر: ADOT Commercial Vehicle Permits (Oversize/Overweight)."},"17":{"q":"تسمح أريزونا بزيادة في الوزن الإجمالي تتجاوز الحدود الاعتيادية لمركبة شديدة التحمّل مزوّدة بتقنية تقليل التشغيل في وضع الخمول (مثل وحدة طاقة مساعدة). ما هو الحد الأقصى لهذه الزيادة الإضافية في الوزن؟","options":["400 رطل","550 رطلًا","1,000 رطل","2,000 رطل"],"explanation":"تسمح أريزونا بزيادة تصل إلى 550 رطلًا (أو الوزن الفعلي لتقنية تقليل التشغيل في وضع الخمول، أيهما أقل) فوق حدود الوزن لمراعاة وحدة الطاقة المساعدة. المصدر: A.R.S. 28-1100 (قيود الوزن الإجمالي؛ الاستثناءات)."},"18":{"q":"تمنح أريزونا زيادة في الوزن الإجمالي للمركبات التي تعمل بشكل أساسي بالغاز الطبيعي أو ببطارية كهربائية أو بالهيدروجين. حتى أي وزن إجمالي يجوز لمثل هذه المركبة أن تعمل بموجب هذه الزيادة؟","options":["80,000 رطل","82,000 رطل","85,000 رطل","88,000 رطل"],"explanation":"تسمح أريزونا للمركبة التي تعمل بشكل أساسي بالغاز الطبيعي أو الكهربائية بالبطارية أو بالهيدروجين بتجاوز الحدود القياسية بمقدار وزن نظام الوقود البديل، لكن لا يجوز أن يتجاوز الوزن الإجمالي 82,000 رطل. المصدر: A.R.S. 28-1100 (قيود الوزن الإجمالي؛ الاستثناءات)."},"19":{"q":"يجوز لمجموعتين متتاليتين من المحاور المزدوجة (tandem) في أريزونا أن تحمل كل منهما حتى 34,000 رطل عندما تكون المسافة بينهما 36 قدمًا أو أكثر، رهنًا بأي حد إجمالي على المركبة المركّبة؟","options":["لا يجوز أن يتجاوز الوزن الإجمالي للمركبة المركّبة 80,000 رطل","لا يجوز أن يتجاوز الوزن الإجمالي للمركبة المركّبة 68,000 رطل","لا يوجد حد إجمالي بمجرد أن تكون المسافة بين المحورين المزدوجين 36 قدمًا","لا يجوز أن يتجاوز الوزن الإجمالي للمركبة المركّبة 100,000 رطل"],"explanation":"تسمح أريزونا لمجموعتين متتاليتين من المحاور المزدوجة (tandem) بأن تحمل كل منهما 34,000 رطل عندما تكون المسافة بينهما 36 قدمًا أو أكثر، شريطة ألا يتجاوز الوزن الإجمالي للمركبة المركّبة 80,000 رطل. المصدر: A.R.S. 28-1100 (قيود الوزن الإجمالي)."},"20":{"q":"في أريزونا، أي فئة من رخصة القيادة التجارية (CDL) مطلوبة لقيادة مركبة مفردة بوزن مركبة إجمالي مصنّف (GVWR) يبلغ 26,001 رطلًا أو أكثر ولا تقطر شيئًا يزيد وزنه عن 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تتطلب أريزونا رخصة CDL من الفئة B لأي مركبة مفردة بوزن مركبة إجمالي مصنّف (GVWR) يبلغ 26,001 رطلًا أو أكثر. وتغطي الفئة A المركبات المركّبة بوزن مركبة مجمّع مصنّف (GCWR) يبلغ 26,001 رطلًا أو أكثر حيث يتجاوز وزن المركبة الإجمالي المصنّف (GVWR) للوحدة المقطورة 10,000 رطل. المصدر: دليل رخصة القيادة التجارية بأريزونا (ADOT MVD)، القسم 1."},"21":{"q":"بموجب قواعد أريزونا، تُطلب رخصة CDL من الفئة A لمركبة مركّبة بوزن مركبة مجمّع مصنّف (GCWR) يبلغ 26,001 رطلًا أو أكثر، شريطة أن يتجاوز وزن المركبة الإجمالي المصنّف (GVWR) للوحدة (الوحدات) المقطورة أي وزن؟","options":["6,000 رطل","10,000 رطل","15,000 رطل","26,001 رطلًا"],"explanation":"تتطلب أريزونا رخصة CDL من الفئة A لمركبة مركّبة بوزن مركبة مجمّع مصنّف (GCWR) يبلغ 26,001 رطلًا أو أكثر عندما يتجاوز وزن المركبة الإجمالي المصنّف (GVWR) للوحدة (الوحدات) المقطورة 10,000 رطل. المصدر: دليل CDL بأريزونا (ADOT MVD)، القسم 1 (فئات CDL)."},"22":{"q":"أي فئة من رخصة CDL بأريزونا تنطبق على مركبة بوزن مركبة إجمالي مصنّف (GVWR) يبلغ 26,000 رطل أو أقل ومصممة لنقل 16 راكبًا أو أكثر (بما في ذلك السائق) أو تنقل مواد خطرة تستوجب اللصاقات التحذيرية (placarded)؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"تغطي الفئة C من CDL بأريزونا المركبات التي لا تستوفي حدود وزن الفئة A أو B والمصممة لنقل 16 راكبًا أو أكثر (بما في ذلك السائق) أو التي تنقل مواد خطرة تستوجب اللصاقات التحذيرية (placarded). المصدر: دليل CDL بأريزونا (ADOT MVD)، القسم 1."},"23":{"q":"يجب أن تكون المركبة مصممة لنقل ما لا يقل عن كم شخصًا (بما في ذلك السائق) قبل أن تندرج ضمن حد عدد الركاب الذي يستوجب اشتراط رخصة CDL في أريزونا؟","options":["9 ركاب","12 راكبًا","15 راكبًا","16 راكبًا"],"explanation":"تتطلب أريزونا رخصة CDL لتشغيل مركبة مصممة لنقل 16 راكبًا أو أكثر، بما في ذلك السائق. المصدر: دليل CDL بأريزونا (ADOT MVD)، قائمة 'يجب أن تحمل رخصة CDL لتشغيل'."},"24":{"q":"ما هو الحد الأدنى العام للسن للحصول على رخصة القيادة التجارية الكاملة (بين الولايات) في أريزونا؟","options":["16","18","21","25"],"explanation":"الحد الأدنى للسن للحصول على رخصة CDL بأريزونا هو 21. ويجوز للمتقدمين الذين لا تقل أعمارهم عن 18 عامًا التقدم بطلب للحصول على رخصة CDL سارية داخل الولاية فقط (intrastate) في أريزونا حصرًا. المصدر: دليل CDL بأريزونا / دليل خدمة العملاء للسائقين التجاريين (ADOT MVD)، المقدمة."},"25":{"q":"يرغب مقيم بأريزونا يبلغ من العمر 18 عامًا في الحصول على رخصة CDL لكنه لم يبلغ 21 بعد. ما الذي يمكن لهذا الشخص التقدم بطلب للحصول عليه؟","options":["رخصة CDL كاملة بين الولايات مع جميع التظهيرات (الاعتمادات)","رخصة CDL سارية داخل أريزونا فقط (intrastate)","إعفاء اتحادي للقيادة عبر حدود الولايات","لا شيء؛ فالحد الأدنى لسن CDL هو 21 دون استثناءات"],"explanation":"في أريزونا، يجوز للمتقدم الذي لا يقل عمره عن 18 عامًا ولكنه دون 21 التقدم بطلب للحصول على رخصة قيادة تجارية سارية داخل أريزونا فقط (intrastate). المصدر: دليل CDL بأريزونا / دليل خدمة العملاء (ADOT MVD)، المقدمة."},"26":{"q":"في أريزونا، يُحظر تحديدًا على السائقين الذين تقل أعمارهم عن 21 عامًا فعل ماذا بمركبة تجارية؟","options":["نقل كميات من المواد الخطرة تستوجب اللصاقات التحذيرية (placarded)","قيادة أي مركبة يزيد وزنها عن 10,000 رطل","تشغيل مركبة مزوّدة بمكابح هوائية","قطر أي مقطورة"],"explanation":"يُحظر على سائقي أريزونا الذين تقل أعمارهم عن 21 عامًا نقل كميات من المواد الخطرة تستوجب اللصاقات التحذيرية (placarded). ويجوز لهم حمل رخصة CDL/CLP سارية داخل الولاية فقط (intrastate) لكن لا يمكنهم نقل المواد الخطرة التي تستوجب اللصاقات التحذيرية. المصدر: دليل CDL بأريزونا / دليل خدمة العملاء (ADOT MVD)."},"27":{"q":"ما مدة صلاحية تصريح المتعلم التجاري (CLP) في أريزونا؟","options":["لمدة أقصاها 12 شهرًا","لمدة 30 يومًا","لمدة 6 أشهر","لمدة 4 سنوات"],"explanation":"تصريح المتعلم التجاري (CLP) في أريزونا ساري المفعول لمدة 12 شهرًا. المصدر: دليل CDL بأريزونا / دليل خدمة العملاء (ADOT MVD)، 'تصريح المتعلم التجاري (CLP)'."},"28":{"q":"بعد إصدار تصريح CLP لأول مرة في أريزونا، كم يجب أن ينتظر حامله قبل أن يصبح مؤهلًا لإجراء اختبار المهارات (القيادة) لرخصة CDL؟","options":["14 يومًا على الأقل","24 ساعة على الأقل","30 يومًا على الأقل","60 يومًا على الأقل"],"explanation":"لا يكون حامل تصريح CLP مؤهلًا لإجراء اختبار المهارات لرخصة CDL خلال 14 يومًا من الإصدار الأولي للتصريح، بما يتوافق مع فترة الانتظار الاتحادية البالغة 14 يومًا. المصدر: دليل CDL بأريزونا / دليل خدمة العملاء (ADOT MVD)، 'اختبار المهارات (القيادة)'؛ 49 CFR 383.25."},"29":{"q":"أي تظهير (اعتماد) لا يمكن وضعه على تصريح المتعلم التجاري (CLP) في أريزونا؟","options":["الركاب (P)","الحافلة المدرسية (S)","المواد الخطرة (H)","الصهريج (N)"],"explanation":"لا يمكن وضع تظهير المواد الخطرة (H) على تصريح CLP. يحصل المتقدم على تصريح CLP بدون تظهير المواد الخطرة (HME)، ويكمل تقييم التهديد الأمني لإدارة أمن النقل (TSA)، ولا يحصل على تظهير HME إلا بعد الموافقة على التقييم. المصدر: دليل CDL بأريزونا / دليل خدمة العملاء (ADOT MVD)."},"30":{"q":"لقيادة حافلة مدرسية بشكل قانوني في أريزونا، يجب على حامل رخصة CDL حمل أي مجموعة من التظهيرات (الاعتمادات)؟","options":["تظهير P فقط","تظهير S فقط","كل من تظهير P (الركاب) وتظهير S (الحافلة المدرسية)","تظهيري H وS"],"explanation":"يجب أن يحمل سائقو الحافلات المدرسية في أريزونا كلا تظهيري 'P' (الركاب) و'S' (الحافلة المدرسية) لتشغيل حافلة مدرسية. المصدر: دليل CDL بأريزونا / دليل خدمة العملاء (ADOT MVD)، قسم التظهيرات."},"31":{"q":"قبل أن تصدر MVD بأريزونا تظهير المواد الخطرة، يجب على المتقدم اجتياز أي فحص خلفية اتحادي؟","options":["تقييم التهديد الأمني لإدارة أمن النقل (TSA)","استئناف سجلات جنائية لدى مكتب التحقيقات الفيدرالي (FBI)","تصريح المواد الخاضعة للرقابة من إدارة مكافحة المخدرات (DEA)","تدقيق إقامة من دائرة الهجرة والجمارك (ICE)"],"explanation":"يتطلب تظهير المواد الخطرة أن يجتاز المتقدم تقييم التهديد الأمني الخاص بإدارة أمن النقل (TSA)، والذي يشمل فحص الخلفية وأخذ البصمات. المصدر: دليل CDL بأريزونا (ADOT MVD)؛ 49 CFR 1572."},"32":{"q":"بمجرد إتمامه، كم مدة صلاحية تقييم التهديد الأمني (STA) من TSA لتظهير المواد الخطرة بأريزونا قبل وجوب تجديده؟","options":["سنة واحدة","3 سنوات","5 سنوات","8 سنوات"],"explanation":"يكون تقييم التهديد الأمني (STA) ساريًا لمدة 5 سنوات من تاريخ إتمامه؛ وتُخطر MVD حامله قبل 60 يومًا من انتهاء صلاحية STA. المصدر: دليل CDL بأريزونا / دليل خدمة العملاء (ADOT MVD)."},"33":{"q":"يُطلب تظهير مركبة الصهريج (N) بأريزونا لنقل السوائل أو الغازات في صهريج بسعة مصنّفة فردية تزيد عن 119 جالونًا وسعة مصنّفة إجمالية لا تقل عن كم جالونًا؟","options":["500 جالون","750 جالونًا","1,000 جالون","2,000 جالون"],"explanation":"يُطلب تظهير الصهريج للصهاريج ذات السعة المصنّفة الفردية التي تزيد عن 119 جالونًا والسعة المصنّفة الإجمالية البالغة 1,000 جالون أو أكثر. المصدر: دليل CDL بأريزونا (ADOT MVD)، القسم 1؛ 49 CFR 383.5."},"34":{"q":"أي تظهير يحتاجه السائق في أريزونا لقطر مقطورات مزدوجة أو ثلاثية؟","options":["N (الصهريج)","T (المزدوجة/الثلاثية)","H (المواد الخطرة)","P (الركاب)"],"explanation":"يُطلب تظهير المزدوجة/الثلاثية (T) لقطر مقطورات مزدوجة أو ثلاثية ويتطلب اجتياز اختبار المعرفة الخاص بالمزدوجة/الثلاثية. المصدر: دليل CDL بأريزونا (ADOT MVD)، قائمة التظهيرات بالقسم 1."},"35":{"q":"ما هو الحد الأدنى للدرجة التي يجب أن يحققها المتقدم في كل اختبار معرفة لرخصة CDL بأريزونا للنجاح؟","options":["70 بالمئة","75 بالمئة","80 بالمئة","90 بالمئة"],"explanation":"يجب على المتقدمين الإجابة بشكل صحيح على ما لا يقل عن 80 بالمئة من الأسئلة في كل اختبار معرفة لتحقيق درجة النجاح، ويجب الانتظار حتى يوم العمل التالي لإعادة أي اختبار رسبوا فيه. المصدر: دليل CDL بأريزونا / دليل خدمة العملاء (ADOT MVD)، 'معلومات اختبار إضافية'."},"36":{"q":"يجب إتمام تدريب السائقين من المستوى المبتدئ (ELDT) المطلوب قبل اختبارات معينة لمهارات أو معرفة رخصة CDL بأريزونا من خلال مزوّد مدرج أين؟","options":["سجل مزوّدي التدريب (TPR) التابع لـ FMCSA","دليل المدارس الخاص بـ MVD بأريزونا فقط","أي وكالة شاحنات مرخّصة من الولاية","السجل الوطني للفاحصين الطبيين المعتمدين"],"explanation":"تتطلب لوائح ELDT الاتحادية أن يتدرب السائقون من المستوى المبتدئ مع مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA (tpr.fmcsa.dot.gov) قبل إجراء اختبارات معينة لمهارات أو معرفة رخصة CDL. المصدر: دليل CDL بأريزونا / دليل خدمة العملاء (ADOT MVD)، 'تدريب السائقين من المستوى المبتدئ (ELDT)'؛ 49 CFR Part 380."},"37":{"q":"في طلب رخصة CDL بأريزونا، يقوم السائق الذي يعمل داخل أريزونا فقط ويجب أن يستوفي المتطلبات الطبية للولاية بإقرار ذاتي تحت أي فئة؟","options":["بين الولايات غير المُعفى (NI)","داخل الولاية غير المُعفى (NA)","بين الولايات المُعفى (EI)","داخل الولاية المُعفى (EA)"],"explanation":"السائق الذي يعمل بالكامل داخل أريزونا ويجب أن يستوفي المتطلبات الطبية يقوم بإقرار ذاتي بصفته داخل الولاية غير المُعفى (NA)؛ ويضع هذا قيدًا داخل الولاية على رخصة CDL/CLP. أما بين الولايات غير المُعفى (NI) فيسمح بالعمل على مستوى البلاد بموجب البطاقة الطبية الاتحادية DOT. المصدر: دليل CDL بأريزونا / دليل خدمة العملاء (ADOT MVD)، 'الإقرار الذاتي'."},"38":{"q":"أثناء تشغيل مركبة تجارية آلية (CMV) في أريزونا، يُعتبر سائق رخصة CDL قائدًا تحت تأثير الكحول عند أي تركيز للكحول في الدم (BAC)؟","options":["0.02 أو أعلى","0.04 أو أعلى","0.08 أو أعلى","0.10 أو أعلى"],"explanation":"تحظر أريزونا، اتباعًا للمعيار الاتحادي في 49 CFR 383.51 وA.R.S. 28-1381/28-3312، تشغيل مركبة تجارية آلية (CMV) بتركيز كحول في الدم (BAC) يبلغ 0.04 أو أعلى (نصف الحد البالغ 0.08 للمركبات غير التجارية). المصدر: دليل CDL بأريزونا؛ A.R.S. 28-3312."},"39":{"q":"في أريزونا، ما هو الحد الأدنى لفترة سحب الأهلية لأول مخالفة كبرى لحامل رخصة CDL (مثل القيادة تحت التأثير في مركبة تجارية آلية) عند عدم نقل مواد خطرة؟","options":["60 يومًا","120 يومًا","سنة واحدة","3 سنوات"],"explanation":"تؤدي أول مخالفة كبرى إلى سحب الأهلية لمدة لا تقل عن سنة واحدة. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا (يعكس 49 CFR 383.51)."},"40":{"q":"إذا ارتكب حامل رخصة CDL أول مخالفة كبرى في أريزونا أثناء نقل مواد خطرة تستوجب اللصاقات التحذيرية (placarded)، يزيد الحد الأدنى لسحب الأهلية إلى:","options":["سنة واحدة","سنتان","3 سنوات","5 سنوات"],"explanation":"تؤدي أول مخالفة كبرى تُرتكب أثناء نقل مواد خطرة تستوجب اللصاقات التحذيرية (placarded) إلى سحب الأهلية لمدة ثلاث سنوات بدلًا من سنة واحدة. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا."},"41":{"q":"بموجب قانون أريزونا، ما هو سحب الأهلية لثاني مخالفة كبرى يرتكبها حامل رخصة CDL؟","options":["سنة واحدة","5 سنوات","10 سنوات","مدى الحياة"],"explanation":"تؤدي مخالفتان كبريان منفصلتان إلى سحب الأهلية مدى الحياة، وإن كانت إعادة الأهلية ممكنة بعد 10 سنوات عقب إكمال برنامج إعادة تأهيل معتمد. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا."},"42":{"q":"في أريزونا، كم عدد المخالفات المرورية الجسيمة خلال فترة 3 سنوات التي تؤدي إلى سحب أهلية رخصة CDL لمدة 60 يومًا؟","options":["1","2","3","4"],"explanation":"تؤدي مخالفتان مروريتان جسيمتان خلال ثلاث سنوات إلى سحب الأهلية لمدة 60 يومًا. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا."},"43":{"q":"يُدان سائق رخصة CDL في أريزونا بثلاث مخالفات مرورية جسيمة خلال فترة 3 سنوات. ما هي فترة سحب الأهلية؟","options":["60 يومًا","90 يومًا","120 يومًا","سنة واحدة"],"explanation":"تؤدي ثلاث مخالفات مرورية جسيمة خلال ثلاث سنوات إلى سحب الأهلية لمدة 120 يومًا. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا."},"44":{"q":"في أريزونا، يُعد تجاوز السرعة بمقدار كم فوق الحد المعلن في مخالفة واحدة 'مخالفة مرورية جسيمة' لحامل رخصة CDL؟","options":["10 mph أو أكثر فوق الحد","15 mph أو أكثر فوق الحد","20 mph أو أكثر فوق الحد","25 mph أو أكثر فوق الحد"],"explanation":"بموجب A.R.S. 28-3312(J)، يُعد تجاوز السرعة المفرط بمقدار 15 mph أو أكثر فوق الحد المعلن مخالفة مرورية جسيمة. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا."},"45":{"q":"أي مما يلي يُصنّف كمخالفة كبرى (وليس مجرد مخالفة مرورية جسيمة) لحامل رخصة CDL بأريزونا؟","options":["القيادة بمسافة قريبة جدًا (الالتصاق بالمركبة الأمامية)","تجاوز السرعة بمقدار 15 mph فوق الحد","تغيير المسار بشكل غير سليم أو متقلب","مغادرة موقع حادث يشمل مركبة تجارية آلية (CMV)"],"explanation":"تُعد مغادرة موقع حادث (الهروب من الحادث) يشمل مركبة تجارية آلية (CMV) مخالفة كبرى تحمل سحب أهلية لمدة سنة واحدة (3 سنوات في حال المواد الخطرة). أما الثلاثة الأخرى فهي مخالفات مرورية جسيمة. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا."},"46":{"q":"بموجب قانون الموافقة الضمنية في أريزونا، ماذا يحدث لحامل رخصة CDL الذي يرفض إجراء اختبار كيميائي قانوني (تنفّس/دم) أثناء إيقاف بتهمة القيادة تحت التأثير، فيما يتعلق بامتياز القيادة التجارية لديه؟","options":["تحذير فقط عند الرفض الأول","سحب أهلية رخصة CDL لمدة 30 يومًا","سحب أهلية رخصة CDL لمدة لا تقل عن سنة واحدة","لا تأثير على رخصة CDL إذا لم يكن يقود تجاريًا"],"explanation":"يُعامَل رفض إجراء اختبار كيميائي قانوني معاملة المخالفة الكبرى: سحب أهلية رخصة CDL لمدة لا تقل عن سنة واحدة (ثلاث سنوات في حال نقل مواد خطرة تستوجب اللصاقات التحذيرية placarded)، بالإضافة إلى تعليق الرخصة بموجب الموافقة الضمنية. المصدر: A.R.S. 28-1321 (الموافقة الضمنية)؛ A.R.S. 28-3312؛ دليل CDL بأريزونا."},"47":{"q":"في أريزونا، يمكن ارتكاب مخالفة القيادة تحت التأثير التي تؤدي إلى سحب أهلية حامل رخصة CDL في:","options":["مركبة تجارية آلية فقط","مركبة تحمل مواد خطرة فقط","إما مركبة تجارية أو مركبة شخصية (غير تجارية)","مركبة يزيد وزنها عن 26,001 رطل فقط"],"explanation":"تؤدي إدانة القيادة تحت التأثير في أي مركبة، تجارية كانت أم شخصية، إلى سحب أهلية رخصة CDL. يمكن للسائق أن يفقد رخصة CDL بسبب قيادة تحت التأثير ارتُكبت في سيارة خاصة. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا."},"48":{"q":"ما هي فترة سحب الأهلية لأول انتهاك لأمر إيقاف عن الخدمة (OOS) من قِبل حامل رخصة CDL في أريزونا؟","options":["60 يومًا","90 يومًا","180 يومًا","سنة واحدة"],"explanation":"يؤدي أول انتهاك لأمر الإيقاف عن الخدمة إلى سحب الأهلية لمدة لا تقل عن 180 يومًا. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا (يعكس 49 CFR 383.51)."},"49":{"q":"في أريزونا، ما هو سحب الأهلية لثاني انتهاك لأمر إيقاف عن الخدمة خلال فترة 10 سنوات (غير المواد الخطرة، غير الركاب)؟","options":["180 يومًا","سنة واحدة","سنتان","5 سنوات"],"explanation":"يؤدي ثاني انتهاك لأمر الإيقاف عن الخدمة خلال 10 سنوات إلى سحب الأهلية لمدة لا تقل عن سنتين. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا."},"50":{"q":"يرتكب سائق رخصة CDL في أريزونا ثالث انتهاك لأمر إيقاف عن الخدمة خلال 10 سنوات. الحد الأدنى لسحب الأهلية هو:","options":["سنة واحدة","سنتان","3 سنوات","مدى الحياة"],"explanation":"يؤدي ثالث انتهاك أو ما يليه لأمر الإيقاف عن الخدمة خلال 10 سنوات إلى سحب الأهلية لمدة لا تقل عن 3 سنوات. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا."},"51":{"q":"ما هو سحب الأهلية لأول مخالفة عند تقاطع السكة الحديدية (railroad grade-crossing) لحامل رخصة CDL في أريزونا؟","options":["لا تقل عن 60 يومًا","لا تقل عن 90 يومًا","لا تقل عن 120 يومًا","سنة واحدة"],"explanation":"تؤدي أول مخالفة عند تقاطع السكة الحديدية إلى سحب الأهلية لمدة لا تقل عن 60 يومًا. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا."},"52":{"q":"في أريزونا، تؤدي ثاني مخالفة لسائق رخصة CDL عند تقاطع السكة الحديدية خلال 3 سنوات إلى سحب الأهلية لمدة لا تقل عن:","options":["60 يومًا","120 يومًا","180 يومًا","سنة واحدة"],"explanation":"تؤدي ثاني مخالفة عند تقاطع السكة الحديدية خلال ثلاث سنوات إلى سحب الأهلية لمدة لا تقل عن 120 يومًا. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا."},"53":{"q":"يرتكب حامل رخصة CDL في أريزونا ثالث مخالفة عند تقاطع السكة الحديدية خلال فترة 3 سنوات. سحب الأهلية لمدة لا تقل عن:","options":["120 يومًا","180 يومًا","سنة واحدة","3 سنوات"],"explanation":"تؤدي ثالث مخالفة أو ما يليها عند تقاطع السكة الحديدية خلال ثلاث سنوات إلى سحب الأهلية لمدة لا تقل عن سنة واحدة. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا."},"54":{"q":"استخدام مركبة في ارتكاب جناية تتعلق بتصنيع أو توزيع أو صرف مادة خاضعة للرقابة يؤدي إلى أي سحب لأهلية رخصة CDL في أريزونا؟","options":["سنة واحدة","3 سنوات","10 سنوات","سحب أهلية دائم (مدى الحياة) دون إعادة أهلية"],"explanation":"يؤدي استخدام مركبة آلية في جناية تتعلق بتصنيع أو توزيع أو صرف مادة خاضعة للرقابة إلى سحب أهلية دائم (مدى الحياة) غير مؤهل لإعادة الأهلية بعد 10 سنوات. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا."},"55":{"q":"بموجب القاعدة التي تنطبق على سائقي رخص CDL في أريزونا، قد يُعرّض إرسال رسالة نصية أو قراءتها أثناء قيادة مركبة تجارية آلية (CMV) السائق لغرامة مدنية تصل إلى:","options":["$500","$1,000","$2,750","$11,000"],"explanation":"قد تؤدي المراسلة النصية أثناء قيادة مركبة تجارية آلية (CMV) إلى غرامة مدنية اتحادية تصل إلى $2,750 للسائق (ويواجه أصحاب العمل ما يصل إلى $11,000 للسماح بها أو اشتراطها). كما تُعد إدانة المراسلة النصية/استخدام الهاتف المحمول باليد مخالفة مرورية جسيمة. المصدر: 49 CFR 392.80/392.82 (قاعدة عدم المراسلة النصية من FMCSA)؛ دليل CDL بأريزونا."},"56":{"q":"بالنسبة لسائق رخصة CDL في أريزونا، يُسمح باستخدام الهاتف المحمول باليد أثناء قيادة مركبة تجارية آلية (CMV) فقط إذا كان السائق:","options":["يُبقي المكالمة أقل من دقيقة واحدة","متوقفًا عند إشارة حمراء","يستخدم إعدادًا يدعم القيادة الحرة (hands-free) ولا يضغط على أكثر من زر واحد وهو جالس ومربوط بحزام الأمان","على طريق خاص"],"explanation":"تحظر القاعدة الإمساك بالهاتف أو الوصول إليه أو الضغط على أكثر من زر واحد؛ ولا يُسمح بالاستخدام بنظام القيادة الحرة (hands-free) إلا إذا كان بإمكان السائق بدء المكالمة/الرد عليها بلمسة زر واحدة مع البقاء في وضعية القيادة جالسًا ومربوطًا بحزام الأمان. وتُحتسب المخالفات كمخالفات مرورية جسيمة. المصدر: 49 CFR 392.82؛ دليل CDL بأريزونا."},"57":{"q":"يُدان حامل رخصة CDL بمخالفة كبرى ويصل إلى سحب أهلية مدى الحياة. بموجب قواعد أريزونا/الاتحادية، قد تكون إعادة الأهلية ممكنة فقط بعد حد أدنى من:","options":["3 سنوات","5 سنوات","10 سنوات وإكمال برنامج إعادة تأهيل معتمد","لا يمكن إعادة الأهلية أبدًا"],"explanation":"قد يُخفّض سحب الأهلية مدى الحياة الناتج عن مخالفتين كبريين للسماح بإعادة الأهلية بعد 10 سنوات على الأقل إذا أكمل السائق برنامج إعادة تأهيل معتمد؛ وتظل عمليات سحب الأهلية بسبب جناية مادة خاضعة للرقابة دائمة. المصدر: A.R.S. 28-3312؛ دليل CDL بأريزونا."},"58":{"q":"عند تقاطع السكة الحديدية مع الطريق السريع حيث لا يوجد خط توقف أبيض مرسوم على سطح الطريق، أين يجب على سائق CDL في أريزونا الملزم بالتوقف أن يوقف المركبة؟","options":["على مسافة لا تقل عن 5 أقدام ولا تزيد عن 25 قدماً من أقرب قضيب","على مسافة لا تقل عن 15 قدماً ولا تزيد عن 50 قدماً من أقرب قضيب","على مسافة لا تقل عن 20 قدماً ولا تزيد عن 75 قدماً من أقرب قضيب","على مسافة لا تقل عن 10 أقدام ولا تزيد عن 100 قدم من أقرب قضيب"],"explanation":"يُلزم دليل CDL في أريزونا والمادة ARS 28-853 الحافلات والمركبات التي تنقل ركاباً مقابل أجر والمركبات الحاملة للوحات الإرشادية أو الحمولات القابلة للاشتعال بالتوقف على مسافة لا تزيد عن 50 قدماً ولا تقل عن 15 قدماً من أقرب قضيب عند عدم وجود خط توقف. المصدر: دليل CDL في أريزونا القسم 2.15؛ ARS 28-853."},"59":{"q":"بموجب قانون \"أفسح الطريق\" (Move Over) في أريزونا، عندما يقترب سائق على طريق سريع من أربعة مسارات (مساران أو أكثر في الاتجاه نفسه) من مركبة متوقفة تعرض أضواءً وامضة أو تحذيرية، فما الذي يُطلب من السائق فعله أولاً؟","options":["التوقف توقفاً تاماً حتى تغادر المركبة المتوقفة","إطلاق البوق باستمرار أثناء تجاوز المركبة المتوقفة","الانعطاف إلى الكتف والانتظار حتى يشير ضابط بالمرور","تغيير المسار بعيداً عن المركبة المتوقفة إذا كان ذلك آمناً وممكناً"],"explanation":"تُلزم المادة ARS 28-775 السائقين بإفساح الطريق عبر الانتقال إلى مسار غير مجاور عندما يكون ذلك آمناً؛ وفقط إذا كان تغيير المسار غير آمن يجب على السائق التباطؤ إلى سرعة آمنة. المصدر: ARS 28-775؛ صفحة قانون أفسح الطريق لدى AZDPS."},"60":{"q":"ما هو الحد الأقصى للسرعة في أريزونا لمركبة آلية أو مجموعة مركبات يتجاوز وزنها الإجمالي المُعلن 26,000 رطل (بخلاف حافلة الركاب)، ما لم تكن ADOT قد وضعت حداً أعلى؟","options":["55 ميلاً في الساعة","60 ميلاً في الساعة","75 ميلاً في الساعة","65 ميلاً في الساعة"],"explanation":"تحدد المادة ARS 28-709 سقفاً للمركبات التجارية الثقيلة التي يتجاوز وزنها 26,000 رطل (والمركبات التي تجر مقطورة عمود بوزن 6,000 رطل أو أكثر) عند 65 ميلاً في الساعة ما لم تضع ADOT حداً أعلى بعد دراسة هندسية. المصدر: ARS 28-709."},"61":{"q":"وفقاً لدليل CDL في أريزونا، عند التوقف على أو بجانب طريق سريع باتجاه واحد أو طريق مقسَّم، أين ينبغي وضع المثلثات التحذيرية العاكسة الثلاثة باتجاه حركة المرور القادمة؟","options":["على مسافة 10 أقدام و50 قدماً و150 قدماً باتجاه حركة المرور القادمة","على مسافة 25 قدماً و75 قدماً و125 قدماً باتجاه حركة المرور القادمة","على مسافة 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة","على مسافة 15 قدماً و100 قدم و300 قدم باتجاه حركة المرور القادمة"],"explanation":"يوجّه دليل CDL في أريزونا السائقين المتوقفين على طريق سريع باتجاه واحد أو طريق مقسَّم إلى وضع أجهزة التحذير على مسافة 10 و100 و200 قدم باتجاه حركة المرور القادمة، خلال 10 دقائق. المصدر: دليل CDL في أريزونا القسم 2.5."},"62":{"q":"على طريق ذي مسارين يحمل حركة المرور في كلا الاتجاهين (طريق سريع غير مقسَّم)، أين يقول دليل CDL في أريزونا إنه يجب وضع المثلثات التحذيرية بعد التوقف؟","options":["على مسافة 25 قدماً من المركبة و200 قدم أمامها وخلفها","على مسافة 50 قدماً من المركبة و150 قدماً أمامها وخلفها","على مسافة 10 أقدام من المركبة و250 قدماً أمامها وخلفها","على مسافة 10 أقدام من المركبة و100 قدم أمامها وخلفها"],"explanation":"على طريق غير مقسَّم باتجاهين، يُلزم دليل CDL في أريزونا بوضع مثلث على مسافة 10 أقدام من المركبة بالإضافة إلى مثلث على بعد 100 قدم أمامها وآخر على بعد 100 قدم خلفها. المصدر: دليل CDL في أريزونا القسم 2.5."},"63":{"q":"أثناء عبور خطوط السكة الحديدية بمركبة تجارية في أريزونا، ما الذي يحظره القانون ودليل CDL على السائق فعله؟","options":["استخدام أضواء الطوارئ الوامضة في الاتجاهات الأربعة","النظر يميناً ويساراً بحثاً عن القطارات","تبديل التروس أثناء عبور الخط أو الخطوط","العبور عندما تكون البوابات مرفوعة"],"explanation":"تنص المادة ARS 28-853 ودليل CDL في أريزونا على أنه يجب على السائق ألا يبدّل التروس أثناء عبور الخطوط، تجنباً لتوقف المحرك على التقاطع. المصدر: ARS 28-853؛ دليل CDL في أريزونا القسم 2.15.5."},"64":{"q":"بموجب قواعد توقف الحافلات المدرسية في أريزونا (ARS 28-857)، أي سائق قادم من الاتجاه المقابل غير مُلزَم بالتوقف لحافلة مدرسية فعّلت أضواءها الحمراء الوامضة بالتناوب؟","options":["سائق في المسار المقابل تماماً عبر مسار انعطاف مركزي بعيداً عن الحافلة","سائق يقترب من الحافلة على طريق غير مقسَّم بمسارين","سائق خلف الحافلة في اتجاه السير نفسه","سائق يسير على طريق منفصل من طريق سريع ذي طُرُق منفصلة"],"explanation":"تعفي المادة ARS 28-857 السائق الموجود على طريق منفصل من طريق سريع ذي طُرُق منفصلة (طريق سريع مقسَّم فعلياً)؛ أما الخطوط المرسومة أو مسار الانعطاف لليسار باتجاهين فلا يُنشئان طرقاً منفصلة. المصدر: ARS 28-857."},"65":{"q":"على طريق سريع في أريزونا يحتوي على مسار انعطاف لليسار باتجاهين (مسار مركزي) لكن دون فاصل مادي، ما الذي يجب على السائق القادم من الاتجاه المقابل فعله عندما تتوقف حافلة مدرسية وأضواؤها الحمراء وامضة؟","options":["المتابعة دون توقف، لأن مسار الانعطاف يقسم الطريق","التباطؤ إلى 15 ميلاً في الساعة دون الحاجة للتوقف","التوقف فقط إذا كان الأطفال يعبرون بشكل واضح","التوقف، لأن مسار الانعطاف المركزي ليس طريقاً منفصلاً"],"explanation":"تحدد المادة ARS 28-857 أن المسار أو مجموعة المسارات على أي جانب من مسار الانعطاف لليسار باتجاهين ليست طريقاً منفصلاً، لذا يجب على حركة المرور المقابلة التوقف. المصدر: ARS 28-857."},"66":{"q":"أي المركبات يُلزمها قانون أريزونا (ARS 28-853) تحديداً بالتوقف عند كل تقاطع سكة حديدية بمستوى الطريق قبل المتابعة؟","options":["فقط المركبات التي تعرض لوحات إرشادية للمواد الخطرة","جميع المركبات التجارية التي يزيد وزنها عن 10,000 رطل","الحافلات/مركبات نقل الركاب مقابل أجر، والحافلات المدرسية، والمركبات الناقلة للمتفجرات أو السوائل القابلة للاشتعال","فقط الحافلات المدرسية عندما يكون الطلاب على متنها"],"explanation":"تذكر المادة ARS 28-853 المركبات الآلية التي تنقل ركاباً مقابل أجر، والحافلات المدرسية التي تنقل أطفالاً، والمركبات التي تحمل مواد متفجرة أو سوائل قابلة للاشتعال كحمولة. المصدر: ARS 28-853."},"67":{"q":"وفقاً لقسم الحافلات المدرسية في CDL في أريزونا، متى ينبغي على سائق الحافلة المدرسية تفعيل أضواء الخطر عند الاقتراب من تقاطع سكة حديدية؟","options":["على بُعد ما لا يقل عن نحو 100 قدم قبل التقاطع","على بُعد ما لا يقل عن نحو 300 قدم قبل التقاطع","فقط بعد أن تتوقف الحافلة توقفاً تاماً","على بُعد نحو 50 قدماً قبل التقاطع"],"explanation":"يوجّه قسم الحافلات المدرسية في دليل CDL في أريزونا السائقين إلى تفعيل أضواء الخطر على بُعد نحو 100 قدم كحد أدنى قبل التقاطع للإشارة إلى نواياهم. المصدر: دليل CDL في أريزونا القسم 10.4."},"68":{"q":"ما هي الغرامة المدنية لمخالفة أولى لقانون \"أفسح الطريق\" في أريزونا (ARS 28-775)؟","options":["$150","$275","$500","$1,000"],"explanation":"تحدد المادة ARS 28-775 غرامة مدنية قدرها $275 للمخالفة الأولى، ترتفع إلى $500 للمخالفة الثانية و$1,000 للمخالفة الثالثة خلال خمس سنوات. المصدر: ARS 28-775."},"69":{"q":"على الطرق السريعة متعددة المسارات في أريزونا، ما الذي تتطلبه المادة ARS 28-721 من سائق يسير بسرعة أبطأ من السرعة الطبيعية لحركة المرور؟","options":["البقاء في المسار الأوسط في جميع الأوقات","القيادة في المسار الأيمن إلا عند التجاوز أو الاستعداد للانعطاف يساراً","استخدام المسار الأيسر فقط ليتمكن المرور الأسرع من التجاوز من اليمين","الحفاظ على سرعة 45 ميلاً في الساعة على الأقل في أي مسار"],"explanation":"تُلزم المادة ARS 28-721 المركبة التي تسير بسرعة أبطأ من حركة المرور الطبيعية بالبقاء في المسار الأيمن، إلا عند اللحاق/التجاوز أو الاستعداد للانعطاف يساراً. المصدر: ARS 28-721."},"70":{"q":"ما هو الحد الأقصى القانوني لعرض المركبة على الطرق السريعة في أريزونا قبل أن يصبح تصريح الأبعاد الزائدة من ADOT مطلوباً؟","options":["8 أقدام و6 بوصات","8 أقدام و0 بوصة","9 أقدام و0 بوصة","10 أقدام و0 بوصة"],"explanation":"الحد الأقصى القانوني للعرض في أريزونا هو 8 أقدام و6 بوصات (102 بوصة)؛ وأي شيء أعرض من ذلك يتطلب تصريح أبعاد زائدة من ADOT. المصدر: لوائح تصاريح الأبعاد الزائدة/الوزن الزائد لدى ADOT."},"71":{"q":"دون تصريح الأبعاد الزائدة/الوزن الزائد في أريزونا، ما هو الحد الأقصى المسموح به عموماً للوزن الإجمالي للمركبة؟","options":["80,000 رطل","100,000 رطل","26,000 رطل","120,000 رطل"],"explanation":"تتبع أريزونا الحد القانوني الفيدرالي البالغ 80,000 رطل للوزن الإجمالي؛ وتجاوزه يتطلب تصريح وزن زائد من ADOT. المصدر: تصاريح الأبعاد الزائدة/الوزن الزائد لدى ADOT؛ ARS الباب 28."},"72":{"q":"تشاهد شاحنة متجهة جنوباً تنزل المنحدر الحاد على I-17 بالقرب من وادي فيردي (Verde Valley) لافتة لـ\"منحدر الشاحنات الهاربة\" (Runaway Truck Ramp). ما الغرض من هذه الميزة السلامية في أريزونا؟","options":["لتوفير منعطف إلزامي لمحطة وزن لجميع الشاحنات","للسماح لمركبة فشلت مكابحها أو ارتفعت حرارتها بمغادرة الطريق السريع والتوقف بأمان","لتعمل كمنطقة مخصصة لتركيب السلاسل في الشتاء","لتعمل كمنطقة استراحة للسائقين المتعبين"],"explanation":"تتيح منحدرات الشاحنات الهاربة (منحدرات الهروب) لدى ADOT على المنحدرات مثل I-17 للشاحنات الخارجة عن السيطرة بسبب فشل المكابح الخروج والتوقف بأمان؛ وتُحدد الحاجة إليها بناءً على حدة المنحدر وطوله وتكرار الحوادث. المصدر: ADOT (منحدرات الشاحنات الهاربة)."},"73":{"q":"خلال كم دقيقة يجب على سائق CDL في أريزونا وضع أجهزة التحذير من الطوارئ بعد التوقف على طريق أو كتف؟","options":["خلال 5 دقائق","خلال 15 دقيقة","خلال 10 دقائق","خلال 30 دقيقة"],"explanation":"يُلزم دليل CDL في أريزونا بوضع أجهزة التحذير من الطوارئ خلال 10 دقائق من التوقف على طريق أو كتف. المصدر: دليل CDL في أريزونا القسم 2.5."},"74":{"q":"إذا تعذّر تغيير المسار بأمان عند تجاوز مركبة متوقفة ذات أضواء وامضة في أريزونا، فما الذي تتطلبه المادة ARS 28-775 من السائق بدلاً من ذلك؟","options":["الحفاظ على حد السرعة المحدد لكن مع إطلاق البوق","المتابعة بحذر واجب وتخفيض السرعة إلى سرعة آمنة وفقاً للظروف","التوقف توقفاً تاماً على الطريق حتى يصبح من الآمن الانتقال","المتابعة بالسرعة الطبيعية لأن الانتقال غير ممكن"],"explanation":"تنص المادة ARS 28-775 على أنه عندما يكون تغيير المسار بأمان غير ممكن، يجب على السائق التباطؤ والمتابعة بحذر بسرعة آمنة وفقاً للظروف. المصدر: ARS 28-775."},"75":{"q":"يشير دليل CDL في أريزونا إلى أن الشاحنة المقطورة تحتاج تقريباً إلى كم من الوقت لاجتياز خط سكة حديدية واحد، مؤكداً على ضرورة التأكد من قدرتك على الاجتياز الكامل قبل البدء بالعبور؟","options":["ما لا يقل عن نحو 14 ثانية","نحو 5 ثوانٍ","نحو 30 ثانية","نحو 8 ثوانٍ"],"explanation":"يذكر دليل CDL في أريزونا أن الشاحنة المقطورة النموذجية تحتاج إلى 14 ثانية على الأقل لاجتياز خط واحد وأكثر من 15 ثانية لخط مزدوج، لذا لا تبدأ العبور أبداً ما لم تستطع الاجتياز الكامل. المصدر: دليل CDL في أريزونا القسم 2.15.5."},"76":{"q":"على طريق سريع مقسَّم بفاصل مادي، كيف يجب على سائق في أريزونا أن يتصرف تجاه حافلة مدرسية متوقفة وأضواؤها الحمراء وامضة على الطريق المقابل، وتجاه أخرى متوقفة على الطريق نفسه؟","options":["لا يلزم التوقف للطريق المقابل، لكن التوقف مطلوب على الطريق نفسه","التوقف مطلوب في كلا الاتجاهين بغض النظر عن الفاصل","لا يلزم التوقف في أي من الاتجاهين لأن الطريق السريع مقسَّم","التوقف مطلوب فقط على الطريق المقابل"],"explanation":"بموجب المادة ARS 28-857، لا يلزم حركة المرور على طريق منفصل فعلياً (مقابل) التوقف، لكن المركبات التي تواجه الحافلة أو تسير خلفها على الطريق نفسه يجب أن تتوقف حتى تنطفئ الأضواء. المصدر: ARS 28-857."},"77":{"q":"بالنسبة للمخالفين، ما هي الغرامة المدنية الدنيا في أريزونا لمخالفة أولى تتمثل في التجاوز غير القانوني لحافلة مدرسية متوقفة تعرض أضواءها الحمراء الوامضة (ARS 28-857)؟","options":["$100","$500","$250","$1,000"],"explanation":"تحدد المادة ARS 28-857 غرامة مدنية دنيا قدرها $250 للمخالفة الأولى؛ والمخالفة الثانية خلال 36 شهراً لا تقل عن $750 والثالثة لا تقل عن $1,000، وكلاهما مع احتمال تعليق الرخصة. المصدر: ARS 28-857."},"78":{"q":"أي جهة في أريزونا تصدر رخص القيادة التجارية (CDLs)؟","options":["شعبة المركبات الآلية التابعة لإدارة النقل في أريزونا (ADOT)","إدارة السلامة العامة في أريزونا","إدارة الأوزان والمقاييس في أريزونا","الإدارة الفيدرالية لسلامة الناقلين الآليين (FMCSA)"],"explanation":"في أريزونا، تصدر رخص CDL من قبل شعبة المركبات الآلية (MVD) التابعة لإدارة النقل في أريزونا (ADOT). أما FMCSA فتضع المعايير الفيدرالية لكنها لا تصدر الرخصة الفعلية. المصدر: ADOT MVD، صفحة الحصول على رخصة القيادة التجارية."},"79":{"q":"ما الحد الأدنى للدرجة التي يجب أن تحققها في كل اختبار معرفي (كتابي) لـ CDL في أريزونا لتنجح؟","options":["80 بالمئة","70 بالمئة","75 بالمئة","85 بالمئة"],"explanation":"تتطلب اختبارات المعرفة لدى Arizona MVD حداً أدنى للدرجة قدره 80 بالمئة للنجاح في كل اختبار. المصدر: ADOT MVD، صفحات الحصول على رخصة القيادة التجارية / الاختبارات والأدلة."},"80":{"q":"قبل أن يُسمح لك بإجراء اختبار المهارات لـ CDL في أريزونا، كم من الوقت يجب أن تكون قد احتفظت بتصريح المتعلم التجاري (CLP)؟","options":["14 يوماً على الأقل","30 يوماً على الأقل","10 أيام على الأقل","60 يوماً على الأقل"],"explanation":"تتبع أريزونا القاعدة الفيدرالية: يجب على حامل CLP الانتظار 14 يوماً على الأقل بعد إصدار CLP قبل إجراء اختبار المهارات لـ CDL. المصدر: ADOT MVD، صفحة الحصول على رخصة القيادة التجارية (49 CFR 383.25)."},"81":{"q":"ما هي المدة القصوى التي يكون فيها تصريح المتعلم التجاري (CLP) في أريزونا صالحاً؟","options":["12 شهراً","6 أشهر","180 يوماً","24 شهراً"],"explanation":"يكون CLP في أريزونا صالحاً لمدة أقصاها 12 شهراً. المصدر: ADOT MVD، صفحة الحصول على رخصة القيادة التجارية."},"82":{"q":"كم مرة يجب عموماً تجديد شهادة الفاحص الطبي DOT لحامل CDL؟","options":["كل 24 شهراً أو أقل","كل 12 شهراً أو أقل","كل 36 شهراً أو أقل","كل 48 شهراً أو أقل"],"explanation":"يجب تجديد شهادة الفاحص الطبي كل 24 شهراً أو أقل، حسبما يحدده الفاحص الطبي أو اللوائح. المصدر: ADOT MVD، صفحة الشهادة الطبية (CDL)."},"83":{"q":"ينقسم اختبار المهارات لـ CDL في أريزونا إلى أي ثلاثة أجزاء؟","options":["فحص ما قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","المعرفة الكتابية، وفحص النظر، والقيادة على الطريق","فحص ما قبل الرحلة، والتعامل مع المواد الخطرة، والقيادة الليلية","الرجوع للخلف، والركن الموازي، والاندماج في الطريق السريع فقط"],"explanation":"يتألف اختبار المهارات لـ CDL في أريزونا من ثلاثة مكونات: فحص ما قبل الرحلة، والتحكم الأساسي بالمركبة، واختبار القيادة على الطريق. المصدر: ADOT MVD، صفحة الاختبارات والأدلة؛ دليل CDL في أريزونا الأقسام 11-13."},"84":{"q":"أين يجب أن يكون الفاحص الطبي مُدرجاً ليُقبل الفحص الطبي لـ CDL في أريزونا؟","options":["في السجل الوطني للفاحصين الطبيين المعتمدين لدى FMCSA","في قائمة الأطباء المعتمدين لدى ADOT","في قائمة الأخصائيين لدى المجلس الطبي في أريزونا","في قائمة الأطباء المعتمدين لدى أي إدارة مركبات في أي ولاية"],"explanation":"يجب أن يُجري الفحص الطبي لـ CDL فاحصٌ طبي مُدرج في السجل الوطني للفاحصين الطبيين المعتمدين لدى FMCSA (وفقاً لـ 49 CFR 391.41/391.43). المصدر: ADOT MVD، صفحة الشهادة الطبية (CDL)."},"85":{"q":"بالنسبة لحامل CDL القياسي (غير المقيد بالعمل داخل الولاية)، كيف تُرسَل شهادة الفاحص الطبي عادةً إلى Arizona MVD؟","options":["يقدمها الفاحص الطبي المعتمد إلى MVD إلكترونياً","يرسل السائق الشهادة الورقية بالبريد إلى مقر MVD","يرسلها صاحب العمل بالفاكس إلى MVD نيابةً عن السائق","تحيلها FMCSA تلقائياً دون أي إجراء من الفاحص"],"explanation":"يقدم الفاحص الطبي المعتمد شهادة الفاحص الطبي (MEC) إلى MVD إلكترونياً؛ وينبغي على السائقين الانتظار 24 ساعة قبل زيارة مكتب MVD. المصدر: ADOT MVD، صفحة الشهادة الطبية (CDL)."},"86":{"q":"ما هي فئات التصديق الذاتي الأربع التي يجب على مقدم طلب CDL في أريزونا الاختيار من بينها؟","options":["بين الولايات غير المستثنى، وبين الولايات المستثنى، وداخل الولاية غير المستثنى، وداخل الولاية المستثنى","بين الولايات، وداخل الولاية، وفيدرالي، وولائي","تجاري، وغير تجاري، ومواد خطرة، وصهريج","الفئة A، والفئة B، والفئة C، والفئة D"],"explanation":"يتطلب التصديق الذاتي لـ CDL اختيار إحدى أربع فئات: بين الولايات غير المستثنى، أو بين الولايات المستثنى، أو داخل الولاية غير المستثنى، أو داخل الولاية المستثنى. المصدر: التصديق الذاتي لـ CDL لدى ADOT MVD / النموذج 96-0526 (49 CFR 383.71)."},"87":{"q":"أي فئة من فئات التصديق الذاتي تتطلب من السائق استيفاء متطلبات البطاقة الطبية الفيدرالية DOT؟","options":["بين الولايات غير المستثنى","بين الولايات المستثنى","داخل الولاية المستثنى","داخل الولاية غير المستثنى"],"explanation":"السائق الذي يصدّق ذاتياً على أنه ضمن فئة بين الولايات غير المستثنى يعمل في التجارة بين الولايات ويجب أن يستوفي متطلبات الشهادة الطبية الفيدرالية DOT. أما الفئات المستثناة فلا تتطلب البطاقة الطبية الفيدرالية. المصدر: التصديق الذاتي لدى ADOT MVD / FMCSA (49 CFR 383.71)."},"88":{"q":"على رخصة CDL في أريزونا، ماذا يشير القيد 'K' بشأن السائق؟","options":["السائق مقيد بالعمل داخل الولاية (أريزونا فقط)","لا يجوز للسائق تشغيل مركبات ذات مكابح هوائية","لا يجوز للسائق نقل المواد الخطرة","يجب على السائق ارتداء عدسات تصحيحية"],"explanation":"يعني القيد 'K' أن السائق مقيد بالتجارة داخل الولاية فقط (القيادة ضمن أريزونا). ويستمر هؤلاء السائقون في تقديم MEC الورقي والنموذج الطويل إلى MVD. المصدر: ADOT MVD، صفحات الشهادة الطبية (CDL) / قيود CDL."},"89":{"q":"بالنسبة لحامل CDL ذي القيد 'K' الخاص بالعمل داخل الولاية فقط في أريزونا، كيف تُقدَّم الشهادة الطبية؟","options":["بالاستمرار في تقديم MEC الورقي والنموذج الطويل إلى MVD للمراجعة","إلكترونياً عبر السجل الوطني فقط","غير مطلوبة لسائقي الولاية الداخلية","بتحميلها عبر بوابة السائق لدى FMCSA"],"explanation":"يستمر سائقو الولاية الداخلية (المقيدون بـ K) في تقديم شهادة الفاحص الطبي الورقية والنموذج الطويل إلى MVD للمراجعة، بدلاً من الاعتماد على التقديم الإلكتروني عبر السجل الوطني. المصدر: ADOT MVD، صفحة الشهادة الطبية (CDL)."},"90":{"q":"ماذا يحدث لرخصة CDL إذا أخفق حاملها في الاحتفاظ بشهادة فاحص طبي سارية في ملفه لدى MVD؟","options":["تخضع رخصة CDL للتعليق والإلغاء","لا شيء، طالما بقي السائق داخل الولاية","يحصل السائق على تمديد تلقائي لمدة عام","تُزال فقط مصادقة المواد الخطرة"],"explanation":"يؤدي الإخفاق في الاحتفاظ بشهادة فاحص طبي سارية في الملف لدى MVD إلى تعليق وإلغاء امتيازات CDL. المصدر: ADOT MVD، صفحة الشهادة الطبية (CDL)."},"91":{"q":"بموجب قواعد تدريب السائقين المبتدئين (ELDT)، متى يجب على مقدم الطلب لأول مرة في أريزونا إكمال ELDT؟","options":["قبل إجراء اختبار المهارات لـ CDL أولي من الفئة A أو B","بعد اجتياز اختبار المهارات لكن قبل طباعة الرخصة","فقط بعد عام من الاحتفاظ بـ CDL","فقط إذا كان عمر مقدم الطلب أقل من 21 عاماً"],"explanation":"يجب إكمال ELDT (عبر مدرسة مُدرجة في سجل مقدمي التدريب لدى FMCSA) قبل إجراء اختبار المهارات لـ CDL من الفئة A أو B لأول مرة، أو الترقية من B إلى A، أو الحصول على مصادقة S أو P أو H لأول مرة. المصدر: ADOT MVD؛ 49 CFR Part 380."},"92":{"q":"أي مما يلي يُعد متطلباً من متطلبات الوثائق عند التقدم بطلب للحصول على CDL في مكتب Arizona MVD؟","options":["إثبات الوجود المصرَّح به في الولايات المتحدة، وإثباتان للإقامة في أريزونا، ورقم الضمان الاجتماعي","خطاب موثّق من صاحب عمل حالي فقط","جواز سفر من بلد الولادة ولا شيء غير ذلك","إثبات إكمال دورة قيادة دفاعية"],"explanation":"يجب على مقدمي الطلبات تقديم إثبات أن وجودهم في الولايات المتحدة مصرَّح به بموجب القانون الفيدرالي، وإثباتين لعنوان الإقامة، ورقم الضمان الاجتماعي، بالإضافة إلى شهادة فاحص طبي سارية. المصدر: ADOT MVD، صفحة الحصول على رخصة القيادة التجارية."},"93":{"q":"إلى جانب مكاتب CDL التابعة لـ MVD، من غيرهم مخوَّل بإجراء اختبار القيادة/المهارات لـ CDL في أريزونا؟","options":["الفاحصون من الطرف الثالث المعتمدون من MVD في المؤسسات العامة والخاصة","أي سائق تجاري مرخَّص لديه خمس سنوات خبرة","فاحصو إدارات المركبات من خارج الولاية الزائرون لأريزونا","المفتشون الفيدراليون لدى FMCSA فقط"],"explanation":"بالإضافة إلى مكاتب CDL التابعة لـ MVD، لدى العديد من المؤسسات العامة والخاصة في أريزونا فاحصون معتمدون من MVD مخوَّلون بإجراء اختبار القيادة/المهارات. المصدر: ADOT MVD، صفحات برنامج فحص CDL / مواقع الاختبار."},"94":{"q":"تكون رخصة CDL في أريزونا صالحة لمدة قصوى تبلغ كم عاماً؟","options":["حتى 8 سنوات","حتى 4 سنوات","حتى 5 سنوات","حتى 10 سنوات"],"explanation":"تكون رخص CDL في أريزونا صالحة لمدة تصل إلى 8 سنوات، ويتحمل السائق مسؤولية التجديد قبل انتهاء الصلاحية. لاحظ أن دورة شهادة طبية أقصر يمكن أن تؤدي مع ذلك إلى تخفيض الرخصة. المصدر: ADOT MVD، صفحة إدارة رخصة القيادة التجارية."},"95":{"q":"ما هو الحد الأدنى للعمر للحصول على CDL صالحة للتجارة بين الولايات (خارج الولاية) في أريزونا؟","options":["21 عاماً","18 عاماً","19 عاماً","25 عاماً"],"explanation":"يجب أن يكون عمر السائق 21 عاماً على الأقل للحصول على CDL للتجارة بين الولايات. أما مقدمو الطلبات الذين تتراوح أعمارهم بين 18 و20 عاماً فيمكنهم الحصول على CDL مقيدة بالعمل داخل الولاية (أريزونا فقط). المصدر: ADOT MVD، صفحة الحصول على رخصة القيادة التجارية (49 CFR 383.3)."},"96":{"q":"إذا صدّق سائق ذاتياً على أنه ضمن فئة داخل الولاية غير المستثنى أو داخل الولاية المستثنى في أريزونا، فما النتيجة المترتبة؟","options":["لا يجوز للسائق تشغيل مركبة آلية تجارية في التجارة بين الولايات","السائق معفى من جميع اختبارات المهارات","لا يجوز للسائق قيادة سوى الحافلات المدرسية","لا تحتاج رخصة CDL الخاصة بالسائق إلى التجديد أبداً"],"explanation":"يقيّد التصديق ضمن فئة داخل الولاية غير المستثنى أو داخل الولاية المستثنى السائقَ بالتجارة داخل الولاية؛ ولا يجوز له تشغيل مركبة آلية تجارية في التجارة بين الولايات. المصدر: ADOT MVD، صفحة إدارة رخصة القيادة التجارية (49 CFR 383.71)."},"97":{"q":"أي عبارة تصف على أفضل وجه عملية ولاية أريزونا وهيكل الرسوم لاختبار CDL؟","options":["تُجرى اختبارات المعرفة والمهارات عبر MVD أو الفاحصين المعتمدين، وتُحدد الرسوم الدقيقة من قبل ADOT ويمكن أن تتغير بمرور الوقت","جميع اختبارات CDL مجانية في أريزونا في كل الأوقات","تُحدَّد الرسوم بشكل دائم بموجب قانون فيدرالي ولا تتغير أبداً","تجمع الحكومة الفيدرالية فقط جميع الرسوم المتعلقة بـ CDL"],"explanation":"تُجرى اختبارات المعرفة والمهارات لـ CDL في أريزونا عبر مكاتب MVD والفاحصين من الطرف الثالث المعتمدين من MVD؛ وتُحدَّد الرسوم المطبقة من قبل ADOT وهي عرضة للتغيير، لذا ينبغي على مقدمي الطلبات التحقق من المبالغ الحالية مع MVD. المصدر: ADOT MVD، صفحات برنامج فحص CDL / جدول الرسوم."}}};
